def agent_cache_warmup_state() -> dict[str, Any]:
    with _AGENT_CACHE_WARMUP_LOCK:
        return copy.deepcopy(_AGENT_CACHE_WARMUP_STATE)


def warm_agent_runtime_caches(employee_id: str | None = None, *, force: bool = False) -> dict[str, Any]:
    """Warm common read-only indexes used by the first BoI Agent request."""
    warmup_employee_id = str(employee_id or DEMO_EMPLOYEE_ID)
    with _AGENT_CACHE_WARMUP_LOCK:
        if _AGENT_CACHE_WARMUP_STATE.get("status") == "running" and not force:
            return copy.deepcopy(_AGENT_CACHE_WARMUP_STATE)
        if _AGENT_CACHE_WARMUP_STATE.get("status") == "completed" and not force:
            return copy.deepcopy(_AGENT_CACHE_WARMUP_STATE)
        _AGENT_CACHE_WARMUP_STATE.update(
            {
                "enabled": BOI_AGENT_CACHE_WARMUP_ON_STARTUP,
                "status": "running",
                "employee_id": warmup_employee_id,
                "started_at": now_iso(),
                "completed_at": "",
                "elapsed_ms": 0,
                "checks": {},
                "error": "",
            }
        )
    started = time.perf_counter()
    checks: dict[str, Any] = {}
    try:
        event_types = load_event_types()
        checks["event_types"] = len(event_types)
        actions = load_action_catalog()
        checks["actions"] = len(actions)
        docs = accessible_docs(warmup_employee_id)
        checks["accessible_docs"] = len(docs)
        index = search_index_for_employee(warmup_employee_id)
        checks["search_docs"] = len(index.get("doc_records") or [])
        ontology = ontology_search_payload("SOP", warmup_employee_id, scope="all", limit=3, view="compact")
        checks["ontology_best_matches"] = len(ontology.get("best_matches") or [])
        page_context = resolve_agent_page_context(
            f"/docs/boi:public:sop:equipment-abnormal-response?employee_id={quote(warmup_employee_id)}",
            warmup_employee_id,
        )
        checks["sample_page_context_resolved"] = bool(page_context.get("resolved"))
        elapsed_ms = int((time.perf_counter() - started) * 1000)
        with _AGENT_CACHE_WARMUP_LOCK:
            _AGENT_CACHE_WARMUP_STATE.update(
                {
                    "status": "completed",
                    "completed_at": now_iso(),
                    "elapsed_ms": elapsed_ms,
                    "checks": checks,
                    "error": "",
                }
            )
            return copy.deepcopy(_AGENT_CACHE_WARMUP_STATE)
    except Exception as exc:  # pragma: no cover - defensive startup path
        elapsed_ms = int((time.perf_counter() - started) * 1000)
        with _AGENT_CACHE_WARMUP_LOCK:
            _AGENT_CACHE_WARMUP_STATE.update(
                {
                    "status": "failed",
                    "completed_at": now_iso(),
                    "elapsed_ms": elapsed_ms,
                    "checks": checks,
                    "error": f"{type(exc).__name__}: {exc}",
                }
            )
            return copy.deepcopy(_AGENT_CACHE_WARMUP_STATE)


def start_agent_cache_warmup() -> None:
    with _AGENT_CACHE_WARMUP_LOCK:
        _AGENT_CACHE_WARMUP_STATE["enabled"] = BOI_AGENT_CACHE_WARMUP_ON_STARTUP
        if not BOI_AGENT_CACHE_WARMUP_ON_STARTUP:
            if _AGENT_CACHE_WARMUP_STATE.get("status") == "not_started":
                _AGENT_CACHE_WARMUP_STATE["status"] = "disabled"
            return
        if _AGENT_CACHE_WARMUP_STATE.get("status") in {"running", "completed"}:
            return
    threading.Thread(
        target=lambda: warm_agent_runtime_caches(DEMO_EMPLOYEE_ID),
        name="boi-agent-cache-warmup",
        daemon=True,
    ).start()


@app.on_event("startup")
async def startup() -> None:
    ensure_dirs()
    start_agent_cache_warmup()


@app.get("/health")
async def health() -> dict[str, str]:
    return {"status": "ok"}


@app.get("/okf-media/{media_path:path}")
async def okf_media(media_path: str) -> FileResponse:
    target_path = (DATA_ROOT / media_path).resolve()
    try:
        target_path.relative_to(DATA_ROOT.resolve())
    except ValueError:
        raise HTTPException(status_code=404, detail="media not found")
    if "_media" not in target_path.parts or target_path.suffix.lower() not in ALLOWED_MEDIA_EXTENSIONS:
        raise HTTPException(status_code=404, detail="media not found")
    if not target_path.exists() or not target_path.is_file():
        raise HTTPException(status_code=404, detail="media not found")
    return FileResponse(target_path)


def git_content_status() -> dict[str, Any]:
    try:
        root = subprocess.run(
            ["git", "-C", str(DATA_ROOT), "rev-parse", "--show-toplevel"],
            text=True,
            capture_output=True,
            check=True,
        ).stdout.strip()
        branch = subprocess.run(
            ["git", "-C", root, "rev-parse", "--abbrev-ref", "HEAD"],
            text=True,
            capture_output=True,
            check=True,
        ).stdout.strip()
        revision = subprocess.run(
            ["git", "-C", root, "rev-parse", "--short", "HEAD"],
            text=True,
            capture_output=True,
            check=True,
        ).stdout.strip()
        porcelain = subprocess.run(
            ["git", "-C", root, "status", "--porcelain"],
            text=True,
            capture_output=True,
            check=True,
        ).stdout.splitlines()
        return {
            "available": True,
            "root": root,
            "branch": branch,
            "revision": revision,
            "dirty": bool(porcelain),
            "dirty_count": len(porcelain),
            "auto_commit": BOI_AUTO_COMMIT,
            "auto_push": BOI_AUTO_PUSH,
            "remote": BOI_CONTENT_GIT_REMOTE,
            "target_branch": BOI_CONTENT_GIT_BRANCH or branch,
        }
    except Exception as exc:
        return {
            "available": False,
            "root": str(DATA_ROOT),
            "auto_commit": BOI_AUTO_COMMIT,
            "auto_push": BOI_AUTO_PUSH,
            "remote": BOI_CONTENT_GIT_REMOTE,
            "target_branch": BOI_CONTENT_GIT_BRANCH,
            "error": type(exc).__name__,
        }


def langflow_simulator_health_status() -> dict[str, Any]:
    status: dict[str, Any] = {
        "mode": LANGFLOW_SIMULATOR_MODE,
        "health": "unknown",
        "flow_audit": {"ok": False, "errors": ["smoke has not run"]},
        "last_smoke_at": "",
        "last_smoke_error": "smoke has not run",
        "health_file": str(LANGFLOW_SIMULATOR_HEALTH_FILE),
    }
    if not LANGFLOW_SIMULATOR_HEALTH_FILE.exists():
        return status
    try:
        payload = json.loads(LANGFLOW_SIMULATOR_HEALTH_FILE.read_text(encoding="utf-8"))
    except Exception as exc:
        status["health"] = "failed"
        status["last_smoke_error"] = f"invalid health file: {type(exc).__name__}"
        return status
    if not isinstance(payload, dict):
        status["health"] = "failed"
        status["last_smoke_error"] = "invalid health file payload"
        return status
    ok = bool(payload.get("ok"))
    errors = payload.get("errors") if isinstance(payload.get("errors"), list) else []
    status.update(
        {
            "health": "ok" if ok else "failed",
            "flow_audit": payload.get("flow_audit") if isinstance(payload.get("flow_audit"), dict) else {"ok": ok, "errors": errors},
            "last_smoke_at": str(payload.get("checked_at") or payload.get("last_smoke_at") or ""),
            "last_smoke_error": "" if ok else "; ".join(str(error) for error in errors[:3]),
            "coverage_score": payload.get("coverage_score"),
            "business_context_quality": payload.get("business_context_quality") or {},
        }
    )
    return status


def runtime_readiness_status(git_status: dict[str, Any], boi_agent: dict[str, Any]) -> dict[str, Any]:
    failures: list[str] = []
    warnings: list[str] = []
    if DEPLOY_PROFILE in {"local-full", "local-full-datalake", "pilot-external"}:
        if not BOI_BUILD_REVISION or BOI_BUILD_REVISION == "unknown":
            failures.append("build.revision is unknown")
        if BOI_AUTO_COMMIT and not git_status.get("available"):
            failures.append("git.available is false while BOI_AUTO_COMMIT=true")
        if BOI_AGENT_BACKEND != "native":
            failures.append("boi_agent.backend is not native")
        required_llm_components = {
            "router": boi_agent.get("router") or {},
            "status_writer": boi_agent.get("status_writer") or {},
            "composer": boi_agent.get("composer") or {},
            "suggestions": boi_agent.get("suggestions") or {},
            "work_context_narrative": boi_agent.get("work_context_narrative") or {},
        }
        for name, component in required_llm_components.items():
            if component.get("required") and not component.get("llm_enabled"):
                failures.append(f"boi_agent.{name}.llm_enabled is false")
        langgraph = boi_agent.get("langgraph") or {}
        if langgraph.get("required") and not langgraph.get("available"):
            failures.append("boi_agent.langgraph.available is false")
    if KAFKA_MODE == "disabled":
        warnings.append("KAFKA_MODE=disabled: event broker publish is disabled")
    if LANGFLOW_MODE == "disabled":
        warnings.append("LANGFLOW_MODE=disabled: Langflow action workflows are disabled")
    return {
        "ok": not failures,
        "failures": failures,
        "warnings": warnings,
        "profile": DEPLOY_PROFILE,
        "checked_at": now_iso(),
    }


def runtime_log_files_health(*, include_line_counts: bool = True) -> list[dict[str, Any]]:
    files: list[dict[str, Any]] = []
    for kind, root, prefix in (
        ("action", ACTION_LOG_ROOT, "actions"),
        ("event", EVENTS_ROOT, "events"),
    ):
        for path in sorted(root.glob(f"{prefix}-*.jsonl")):
            if not path.is_file():
                continue
            index_path = runtime_log_index_path(path)
            size = path.stat().st_size
            files.append(
                {
                    "kind": kind,
                    "file": path.name,
                    "path": str(path),
                    "bytes": size,
                    "line_count": runtime_log_line_count(path) if include_line_counts else None,
                    "index_path": str(index_path),
                    "index_exists": index_path.exists(),
                    "index_bytes": index_path.stat().st_size if index_path.exists() else 0,
                    "over_limit": size > BOI_RUNTIME_LOG_MAX_BYTES,
                    "modified_at": datetime.fromtimestamp(path.stat().st_mtime, tz=KST).replace(microsecond=0).isoformat(),
                }
            )
    files.sort(key=lambda item: (item["bytes"], item["file"]), reverse=True)
    return files


def runtime_log_health_payload(*, include_line_counts: bool = True) -> dict[str, Any]:
    files = runtime_log_files_health(include_line_counts=include_line_counts)
    total_bytes = sum(int(item.get("bytes") or 0) for item in files)
    largest = files[0] if files else {}
    warnings: list[dict[str, Any]] = []
    for item in files:
        if item.get("over_limit"):
            warnings.append(
                {
                    "kind": item.get("kind"),
                    "file": item.get("file"),
                    "warning": "file_exceeds_rotation_limit",
                    "bytes": item.get("bytes"),
                    "max_bytes": BOI_RUNTIME_LOG_MAX_BYTES,
                }
            )
        if BOI_RUNTIME_INDEX_ENABLED and not item.get("index_exists"):
            warnings.append(
                {
                    "kind": item.get("kind"),
                    "file": item.get("file"),
                    "warning": "missing_sidecar_index",
                }
            )
    return {
        "ok": True,
        "checked_at": now_iso(),
        "config": {
            "max_bytes": BOI_RUNTIME_LOG_MAX_BYTES,
            "retention_days": BOI_RUNTIME_LOG_RETENTION_DAYS,
            "archive_enabled": BOI_RUNTIME_LOG_ARCHIVE_ENABLED,
            "index_enabled": BOI_RUNTIME_INDEX_ENABLED,
        },
        "summary": {
            "segment_count": len(files),
            "total_bytes": total_bytes,
            "largest_file": largest.get("file", ""),
            "largest_file_bytes": int(largest.get("bytes") or 0),
            "warning_count": len(warnings),
            "last_rotation": "",
        },
        "warnings": warnings,
        "files": files,
    }


def rebuild_runtime_log_index(path: Path, ref_prefix: str) -> int:
    index_path = runtime_log_index_path(path)
    tmp_path = index_path.with_suffix(index_path.suffix + ".tmp")
    count = 0
    with path.open("r", encoding="utf-8") as source, tmp_path.open("w", encoding="utf-8") as target:
        for line_number, line in enumerate(source, start=1):
            try:
                row = json.loads(line)
            except Exception:
                continue
            if not isinstance(row, dict):
                continue
            log_ref = f"{ref_prefix}:{path.name}:{line_number}"
            target.write(json.dumps(runtime_log_index_row(row, log_ref=log_ref, log_path=path, line_number=line_number), ensure_ascii=False, default=str) + "\n")
            count += 1
    tmp_path.replace(index_path)
    return count


