def dedupe_suggestions(values: list[str], limit: int = 4) -> list[str]:
    seen: set[str] = set()
    suggestions: list[str] = []
    for value in values:
        text = re.sub(r"\s+", " ", str(value or "")).strip()
        if not text or text in seen:
            continue
        seen.add(text)
        suggestions.append(text)
        if len(suggestions) >= limit:
            break
    return suggestions


def page_context_suggestions(current_url: str, page_context: dict[str, Any] | None = None) -> list[str]:
    context = page_context or {}
    url = str(current_url or "")
    page_kind = str(context.get("page_kind") or "")
    title = str(context.get("title") or context.get("page_title") or "").strip()
    access = context.get("access") if isinstance(context.get("access"), dict) else {}
    if access and access.get("can_use_in_agent_context") is False:
        return [
            "현재 문서의 접근 정책과 보안 등급을 설명해줘.",
            "내 권한으로 사용할 수 있는 관련 공개 문서를 찾아줘.",
            "이 문서를 Agent context로 쓸 수 없는 이유를 알려줘.",
        ]

    suggestions: list[str] = []
    if page_kind == "workflow_status" or "/workflows/" in url or "trace_id=" in url:
        event_count = int(context.get("event_count") or 0)
        action_count = int(context.get("action_count") or 0)
        handoff_count = int(context.get("manual_handoff_count") or 0)
        workflow_key = str(context.get("workflow_key") or "workflow")
        if event_count or action_count:
            suggestions.append(f"이 {workflow_key} trace의 이벤트 {event_count}개와 Action {action_count}개를 SOP 단계 기준으로 요약해줘.")
        if handoff_count:
            suggestions.append(f"남은 수동 조치 {handoff_count}건을 일반 업무 관점으로 정리해줘.")
        suggestions.extend([
            "승인 대기 또는 조치 필요 Action을 먼저 알려줘.",
            "생성된 BoI와 원본 실행 기록 링크를 묶어서 보여줘.",
        ])
    elif page_kind == "action_raw" or "/actions/raw/" in url:
        action_key = str(context.get("action_key") or "이 Action")
        status = str(context.get("status") or "")
        suggestions.extend([
            f"{action_key} 실행 결과를 업무 관점으로 요약해줘.",
            f"{action_key}이 어떤 SOP/이벤트와 연결되는지 찾아줘.",
            "이 Action 결과가 다음 업무 흐름 단계에 어떤 영향을 주는지 알려줘.",
        ])
        if status:
            suggestions.append(f"현재 상태 `{status}`에서 내가 할 일을 알려줘.")
    elif page_kind == "event_type" or "/event-types/" in url:
        event_type = str(context.get("event_type") or "이 이벤트 유형")
        stage = str(context.get("workflow_stage") or "")
        recommended_actions = context.get("recommended_actions") if isinstance(context.get("recommended_actions"), list) else []
        suggestions.extend([
            f"{event_type}가 발생하면 어떤 SOP 단계와 Action이 이어지는지 알려줘.",
            f"{event_type} 최근 실행 trace를 찾아줘.",
        ])
        if stage:
            suggestions.append(f"`{stage}` 단계에서 사람이 확인해야 할 항목을 정리해줘.")
        if recommended_actions:
            suggestions.append(f"{event_type}의 권장 Action {len(recommended_actions)}개가 충분한지 점검해줘.")
    elif page_kind == "events" or url.startswith("/events"):
        event_type = str(context.get("event_type") or "")
        trace_id = str(context.get("trace_id") or "")
        event_count = int(context.get("event_count") or 0)
        if trace_id:
            suggestions.append("이 trace의 실행 흐름과 다음 조치를 요약해줘.")
        if event_type:
            suggestions.append(f"{event_type} 이벤트 {event_count}건에서 반복 패턴을 찾아줘.")
            suggestions.append(f"{event_type}가 연결된 SOP와 Action을 보여줘.")
        suggestions.extend([
            "최근 이벤트 중 내가 처리해야 할 Action을 Inbox 기준으로 보여줘.",
            "Event Stream을 시간/trace 기준으로 좁혀볼 추천 필터를 알려줘.",
        ])
    elif page_kind == "doc" or title:
        doc_type = str(context.get("type") or "")
        boi_id = str(context.get("boi_id") or "")
        stage_count = int(context.get("stage_count") or 0)
        action_count = int(context.get("workflow_action_count") or 0)
        manual_count = int(context.get("workflow_manual_action_count") or 0)
        is_sop = doc_type == "boi/sop" or ":sop:" in boi_id or "/sop/" in url or bool(stage_count)
        subject = title or "현재 문서"
        if is_sop:
            suggestions.extend([
                f"{subject}를 Mermaid 프로세스 플로우로 보여줘.",
                f"{subject}의 이벤트, Action, 수동 조치 관계를 요약해줘.",
            ])
            if action_count or manual_count:
                suggestions.append(f"{subject}의 Action {action_count}개와 수동 조치 {manual_count}개 중 부족한 명세를 찾아줘.")
            else:
                suggestions.append(f"{subject}를 실행하려면 부족한 Action 명세가 있는지 찾아줘.")
        else:
            suggestions.extend([
                f"{subject}와 연결된 SOP/이벤트/Action을 찾아줘.",
                f"{subject}의 핵심과 관련 BoI를 요약해줘.",
                "이 내용을 팀 공유용 draft로 만들려면 무엇을 확인해야 해?",
            ])
    else:
        suggestions = [
            "SOP/Event/Action을 함께 검색해줘.",
            "내가 처리해야 할 Action이 있는지 확인해줘.",
            "BoI Wiki에서 업무 용어를 ontology search로 찾아줘.",
        ]
    return dedupe_suggestions(suggestions)


def suggestion_context_for_llm(page_context: dict[str, Any]) -> dict[str, Any]:
    access = page_context.get("access") if isinstance(page_context.get("access"), dict) else {}
    can_use_context = access.get("can_use_in_agent_context") is not False
    keys = (
        "page_kind",
        "title",
        "boi_id",
        "type",
        "visibility",
        "classification",
        "event_type",
        "workflow_key",
        "workflow_stage",
        "workflow_stage_names",
        "workflow_event_types",
        "workflow_actions",
        "workflow_manual_actions",
        "stage_count",
        "workflow_action_count",
        "workflow_manual_action_count",
        "event_count",
        "action_count",
        "manual_handoff_count",
        "status",
        "trace_id",
        "action_key",
    )
    context = {key: page_context.get(key) for key in keys if page_context.get(key) not in (None, "", [])}
    context["access"] = {
        "can_use_in_agent_context": access.get("can_use_in_agent_context", True),
        "can_cite": access.get("can_cite", True),
        "classification": access.get("classification") or page_context.get("classification") or "",
        "redactions": access.get("redactions") or [],
        "reasons": access.get("reasons") or [],
    }
    if can_use_context:
        for key in ("citations", "okf_refs", "links"):
            value = page_context.get(key)
            if value:
                context[key] = value[:8] if isinstance(value, list) else value
        excerpt = text_excerpt(str(page_context.get("body_excerpt") or page_context.get("summary") or ""), 800)
        if excerpt:
            context["safe_excerpt"] = excerpt
    return redact_sensitive(context)


def suggestion_specific_terms(page_context: dict[str, Any]) -> list[str]:
    terms: list[str] = []
    for key in (
        "title",
        "event_type",
        "workflow_key",
        "workflow_stage",
        "action_key",
        "trace_id",
    ):
        value = str(page_context.get(key) or "").strip()
        if value:
            terms.append(value)
    for key in (
        "workflow_stage_names",
        "workflow_event_types",
        "workflow_actions",
        "workflow_manual_actions",
        "recommended_actions",
    ):
        value = page_context.get(key)
        if isinstance(value, list):
            terms.extend(str(item).strip() for item in value[:8] if str(item).strip())
    return dedupe_suggestions(terms, limit=12)


def suggestions_prompt_for_request(req: BoiAgentSuggestionsRequest, employee_id: str, page_context: dict[str, Any]) -> str:
    specific_terms = suggestion_specific_terms(page_context)
    answer_context = req.answer_context if isinstance(req.answer_context, dict) else {}
    if answer_context:
        safe_followup_examples = [
            "이 답변의 근거 문서를 더 자세히 보여줘",
            "이 내용을 업무 체크리스트로 정리해줘",
            "부족한 근거나 업무 명세가 있는지 점검해줘",
        ]
        if answer_context.get("execution_cards"):
            safe_followup_examples = [
                "이 Action을 실행하기 전에 필요한 입력값을 점검해줘",
                "승인 기준과 영향 범위를 일반 업무 관점으로 정리해줘",
                "관련 SOP 단계와 근거 문서를 보여줘",
            ]
        elif answer_context.get("artifacts"):
            safe_followup_examples.append("이 산출물을 다음 조치 기준으로 다시 정리해줘")
        return json.dumps(
            {
                "task": "boi_agent_answer_followups",
                "language": "ko",
                "employee_id": employee_id,
                "current_url": req.current_url,
                "resolved_page_context": suggestion_context_for_llm(page_context),
                "specific_page_terms": specific_terms,
                "answer_context": redact_sensitive(answer_context),
                "safe_followup_examples": safe_followup_examples,
                "supported_tasks": [
                    "답변 근거를 더 자세히 설명",
                    "BoI/SOP/Event/Action ontology search",
                    "SOP Mermaid diagram",
                    "Event to Action workflow explanation",
                    "Action Spec gap check",
                    "Trace reasoning",
                    "Inbox 업무 확인",
                    "신규 이벤트 유형 초안 제안",
                    "승인/조치가 필요한 업무를 확인 카드로 준비",
                ],
                "rules": [
                    "Return JSON only.",
                    "Produce 3 to 5 short Korean follow-up questions.",
                    "Every suggestion must be Korean and must contain Hangul.",
                    "Every suggestion must be based on answer_context, not only the current page.",
                    "Prefer concrete artifacts, evidence, links, action affordances, or missing context from answer_context.",
                    "Use answer_context.memory_preferences to match the user's preferred format or recurring work style when it is relevant.",
                    "If private and team memory preferences differ, follow private memory first and use team memory only as a secondary style hint.",
                    "Do not repeat the user's original question.",
                    "Do not return generic starter questions that could appear before the answer.",
                    "Write each suggestion as a natural user-facing sentence that can be clicked as-is.",
                    "Use conversational request endings such as '보여줘', '알려줘', '정리해줘', '찾아줘', '점검해줘', or '초안 만들어줘'.",
                    "For mutating work, phrase it as draft/preview/approval/먼저 확인, not immediate execution.",
                    "When execution_cards exist, prefer questions about required inputs, approval criteria, impact, evidence, or related SOP before execution.",
                    "Never suggest immediate execution phrases such as '바로 실행', '즉시 실행', '지금 바로 실행', '바로 발행', or '즉시 반영'.",
                    "If answer_context.followup_policy.mutation_affordances_available is false, do not suggest draft, execute, publish, apply, complete, invoke, or approval follow-ups.",
                    "Do not use Markdown formatting, code fences, backticks, bullets, or numbering in suggestion text.",
                    "Do not expose internal affordance keys or labels such as ask_more, open_reference, make_artifact, check_gap, create_draft, request_execution, complete_handoff, or approval.",
                    "Do not mention links or actions that are not present in answer_context.",
                    "If access.can_use_in_agent_context is false, ask about access policy or allowed related documents instead of hidden content.",
                ],
                "output_shape": {"suggestions": ["답변을 바탕으로 한 후속 질문 한 문장"]},
            },
            ensure_ascii=False,
        )
    return json.dumps(
        {
            "task": "boi_agent_page_suggestions_only",
            "language": "ko",
            "employee_id": employee_id,
            "current_url": req.current_url,
            "client_page_title": req.page_context.get("title") if isinstance(req.page_context, dict) else "",
            "resolved_page_context": suggestion_context_for_llm(page_context),
            "specific_page_terms": specific_terms,
            "contextual_candidate_tasks": page_context_suggestions(req.current_url, page_context),
            "supported_tasks": [
                "현재 페이지 질의응답",
                "BoI/SOP/Event/Action ontology search",
                "SOP Mermaid diagram",
                "Event to Action workflow explanation",
                "Action Spec gap check",
                "Trace reasoning",
                "Inbox 업무 확인",
                "신규 이벤트 유형 초안 제안",
            ],
            "rules": [
                "Return JSON only.",
                "Produce 3 to 5 short Korean suggestions.",
                "Write each suggestion as a natural user-facing sentence that can be clicked as-is.",
                "Use conversational request endings such as '보여줘', '알려줘', '정리해줘', '찾아줘', or '점검해줘'.",
                "Do not return noun phrases, menu labels, titles, or keyword strings such as 'Mermaid 플로우 생성'.",
                "Every suggestion must be useful for the current page context.",
                "Use concrete terms from specific_page_terms where natural; avoid suggestions that could fit any unrelated page.",
                "Prefer visible business nouns such as the current SOP title, Event Type, workflow stage, Action key, or Manual Handoff name.",
                "Do not use Markdown formatting, code fences, backticks, bullets, or numbering in suggestion text.",
                "Do not expose internal affordance keys or labels such as ask_more, open_reference, make_artifact, check_gap, create_draft, request_execution, complete_handoff, or approval.",
                "Avoid internal technical words unless they are visible business terms on the page.",
                "If access.can_use_in_agent_context is false, ask about access policy or allowed related documents instead of document content.",
                "For mutating work, phrase it as draft/preview/approval, not immediate execution.",
            ],
            "output_shape": {"suggestions": ["질문 또는 요청 한 문장"]},
        },
        ensure_ascii=False,
    )


def parse_suggestions_payload(text: str) -> dict[str, Any] | None:
    def normalize_payload(payload: Any) -> dict[str, Any] | None:
        if isinstance(payload, list):
            return {"suggestions": payload}
        if not isinstance(payload, dict):
            return None
        for key in ("suggestions", "suggested_questions", "followups", "follow_up_questions", "next_questions"):
            if isinstance(payload.get(key), list):
                return {"suggestions": payload[key]}
        for key in ("answer_plan", "response", "result"):
            nested = normalize_payload(payload.get(key))
            if nested:
                return nested
        return None

    parsed = parse_langflow_json_text(text)
    normalized = normalize_payload(parsed)
    if normalized:
        return normalized
    decoder = json.JSONDecoder()
    stripped = text.strip()
    if stripped.startswith("```") and stripped.endswith("```"):
        fenced = re.sub(r"^```[A-Za-z0-9_-]*\s*", "", stripped, count=1).strip()
        fenced = re.sub(r"\s*```$", "", fenced, count=1).strip()
        if fenced and fenced != stripped:
            payload = parse_suggestions_payload(fenced)
            if payload:
                return payload
    try:
        normalized = normalize_payload(json.loads(stripped))
    except json.JSONDecodeError:
        normalized = None
    if normalized:
        return normalized
    for index, char in enumerate(stripped):
        if char not in "{[":
            continue
        try:
            payload, _end = decoder.raw_decode(stripped[index:])
        except json.JSONDecodeError:
            continue
        normalized = normalize_payload(payload)
        if normalized:
            return normalized
    plain_lines = extract_plain_suggestion_lines(stripped)
    if plain_lines:
        return {"suggestions": plain_lines}
    return None


def extract_plain_suggestion_lines(text: str) -> list[str]:
    suggestions: list[str] = []
    for raw_line in str(text or "").splitlines():
        line = normalize_suggestion_text(raw_line)
        if not line:
            continue
        if line.startswith("{") or line.startswith("[") or line.startswith("```"):
            continue
        if not is_actionable_suggestion_text(line):
            continue
        suggestions.append(line)
    return dedupe_suggestions(suggestions, limit=5)


def is_actionable_suggestion_text(text: str) -> bool:
    value = str(text or "").strip()
    if not re.search(r"[가-힣]", value):
        return False
    if re.search(r"\b(?:ask_more|open_reference|make_artifact|check_gap|create_draft|request_execution|complete_handoff|approval)\b", value, re.I):
        return False
    return bool(
        re.search(
            r"(줘|주세요|알려줘|알려 주세요|보여줘|보여 주세요|정리해줘|정리해 주세요|찾아줘|찾아 주세요|점검해줘|점검해 주세요|만들어줘|만들어 주세요|확인해줘|확인해 주세요|해주세요|해 주세요|해줘|까요|습니까|나요|가요|\?)[.!?]?$",
            value,
        )
    )


def normalize_suggestion_text(item: Any) -> str:
    text = re.sub(r"\s+", " ", str(item or "")).strip()
    text = re.sub(r"^\s*(?:[-*•]\s*|\d+[.)]\s+)", "", text).strip()
    text = text.strip("\"'` ")
    quote_match = re.search(r"[\"“](.+)$", text)
    if quote_match:
        quoted = quote_match.group(1).strip().strip("\"'`” ")
        prefix = text[: quote_match.start()]
        if re.search(r"[가-힣]", quoted) and not re.search(r"[가-힣]", prefix):
            text = quoted
    if "->" in text:
        after_arrow = text.rsplit("->", 1)[-1].strip()
        if re.search(r"[가-힣]", after_arrow):
            text = after_arrow
    text = re.sub(
        r"^\s*(?:idea|suggestion|follow[- ]?up|question|focus)\s*\d*(?:\s*\([^)]*\))?\s*[:：]\s*",
        "",
        text,
        flags=re.I,
    ).strip()
    text = text.replace("`", "")
    # LLMs sometimes echo internal affordance keys such as
    # `check_gap: "..."`. Keep only the user-facing Korean sentence.
    text = re.sub(
        r"^\s*[A-Za-z_][A-Za-z0-9_-]{1,48}(?:\s*\([^)]*\))?\s*:\s*",
        "",
        text,
    ).strip()
    text = text.strip("\"'` ")
    text = re.sub(r"^\s*[:：]\s*", "", text).strip()
    return text


def suggestion_similarity_key(value: Any) -> str:
    text = normalize_suggestion_text(value).lower()
    text = re.sub(r"[^\w가-힣]+", "", text, flags=re.UNICODE)
    return text


def is_repeated_original_question_suggestion(suggestion: str, original_question: str) -> bool:
    suggestion_key = suggestion_similarity_key(suggestion)
    original_key = suggestion_similarity_key(original_question)
    if not suggestion_key or not original_key:
        return False
    if suggestion_key == original_key:
        return True
    if min(len(suggestion_key), len(original_key)) < 14:
        return False
    return SequenceMatcher(None, suggestion_key, original_key).ratio() >= 0.94


def remove_repeated_original_suggestions(suggestions: list[str], original_question: str) -> list[str]:
    if not str(original_question or "").strip():
        return suggestions
    return [
        suggestion
        for suggestion in suggestions
        if not is_repeated_original_question_suggestion(suggestion, original_question)
    ]


def normalize_llm_suggestions(payload: dict[str, Any]) -> list[str]:
    suggestions: list[str] = []
    for item in payload.get("suggestions") or []:
        text = normalize_suggestion_text(item)
        if not text:
            continue
        if text in {".", "..", "...", "…"} or len(text) < 8:
            continue
        if not is_actionable_suggestion_text(text):
            continue
        if len(text) > 120:
            text = text[:119].rstrip() + "…"
        suggestions.append(text)
    normalized = dedupe_suggestions(suggestions, limit=5)
    if not normalized:
        raise BoiAgentSuggestionsUnavailable("LLM suggestion writer returned no usable suggestions")
    return normalized


@contextmanager
def boi_agent_llm_slot(component: str):
    start = time.perf_counter()
    acquired = _BOI_AGENT_LLM_SEMAPHORE.acquire(timeout=BOI_AGENT_LLM_QUEUE_TIMEOUT_SECONDS)
    if not acquired:
        raise TimeoutError(f"BoI Agent LLM queue timed out for {component}")
    try:
        yield {"component": component, "queue_wait_ms": int((time.perf_counter() - start) * 1000)}
    finally:
        _BOI_AGENT_LLM_SEMAPHORE.release()


def call_boi_agent_suggestions_llm(req: BoiAgentSuggestionsRequest, employee_id: str, page_context: dict[str, Any]) -> list[str]:
    if not BOI_AGENT_SUGGESTIONS_LLM_ENABLED:
        raise BoiAgentSuggestionsUnavailable("LLM suggestion writer is not configured")
    if not BOI_AGENT_SUGGESTIONS_BASE_URL or not BOI_AGENT_SUGGESTIONS_MODEL:
        raise BoiAgentSuggestionsUnavailable("LLM suggestion writer base URL/model is missing")
    url = BOI_AGENT_SUGGESTIONS_BASE_URL.rstrip("/") + "/chat/completions"
    headers = {"Content-Type": "application/json"}
    if BOI_AGENT_SUGGESTIONS_API_KEY:
        headers["Authorization"] = f"Bearer {BOI_AGENT_SUGGESTIONS_API_KEY}"
    base_prompt = suggestions_prompt_for_request(req, employee_id, page_context)
    repair_candidates = page_context_suggestions(req.current_url, page_context)
    if isinstance(req.answer_context, dict):
        for item in req.answer_context.get("affordances") or []:
            if isinstance(item, dict) and item.get("question_hint"):
                repair_candidates.append(str(item.get("question_hint") or ""))
    if repair_candidates:
        try:
            repair_candidates = normalize_llm_suggestions({"suggestions": repair_candidates})[:5]
        except BoiAgentSuggestionsUnavailable:
            repair_candidates = []
    last_error = ""
    last_excerpt = ""
    for attempt in range(BOI_AGENT_SUGGESTIONS_MAX_ATTEMPTS):
        messages = [
            {
                "role": "system",
                "content": (
                    "You write concise, page-aware suggestion buttons for BoI Agent. "
                    "Return only one JSON object shaped exactly like "
                    '{"suggestions":["...","...","..."]}. Never answer the user task. '
                    "The suggestions array must not be empty."
                ),
            },
            {"role": "user", "content": base_prompt},
        ]
        if attempt > 0:
            messages.append(
                {
                    "role": "user",
                    "content": json.dumps(
                        {
                            "repair_required": True,
                            "previous_error": last_error,
                            "previous_response_excerpt": last_excerpt,
                            "allowed_candidate_questions": repair_candidates,
                            "must_return": {"suggestions": repair_candidates[:3] or ["짧은 한국어 후속 질문", "짧은 한국어 후속 질문", "짧은 한국어 후속 질문"]},
                            "rules": [
                                "Return JSON only.",
                                "No Markdown fences.",
                                "No prose outside JSON.",
                                "The suggestions array must contain 1 to 5 useful strings.",
                                "Do not return an empty array.",
                                "If allowed_candidate_questions is not empty, copy or lightly rephrase those questions instead of inventing unrelated questions.",
                                "Do not return placeholder strings such as '.', '...', or menu labels.",
                                "Do not expose internal affordance keys or labels.",
                            ],
                        },
                        ensure_ascii=False,
                    ),
                }
            )
        body = {
            "model": BOI_AGENT_SUGGESTIONS_MODEL,
            "temperature": 0.25 if attempt > 0 else 0.35,
            "max_tokens": BOI_AGENT_SUGGESTIONS_MAX_TOKENS,
            "response_format": {"type": "text"},
            "messages": messages,
        }
        try:
            with boi_agent_llm_slot("suggestions"):
                with httpx.Client(timeout=BOI_AGENT_SUGGESTIONS_TIMEOUT_SECONDS) as client:
                    response = client.post(url, headers=headers, json=body)
                    response.raise_for_status()
                    payload = response.json()
        except Exception as exc:
            last_error = f"call_failed:{type(exc).__name__}"
            last_excerpt = str(exc)[:500]
            if attempt + 1 >= BOI_AGENT_SUGGESTIONS_MAX_ATTEMPTS:
                raise BoiAgentSuggestionsUnavailable(f"LLM suggestion writer call failed: {exc}") from exc
            continue
        parsed = None
        raw_candidates: list[str] = []
        for text in iter_langflow_text_candidates(payload):
            raw_candidates.append(text_excerpt(text, 700))
            candidate = parse_suggestions_payload(text)
            if candidate:
                parsed = candidate
                break
        if not parsed:
            last_error = "invalid_json"
            last_excerpt = raw_candidates[0] if raw_candidates else text_excerpt(json.dumps(payload, ensure_ascii=False), 700)
            continue
        try:
            normalized = normalize_llm_suggestions(parsed)
            if isinstance(req.answer_context, dict):
                normalized = remove_repeated_original_suggestions(normalized, str(req.answer_context.get("question") or ""))
            if not normalized:
                raise BoiAgentSuggestionsUnavailable("LLM suggestion writer repeated the original question")
            return normalized
        except BoiAgentSuggestionsUnavailable as exc:
            last_error = str(exc)
            last_excerpt = text_excerpt(json.dumps(parsed, ensure_ascii=False), 700)
            if attempt + 1 >= BOI_AGENT_SUGGESTIONS_MAX_ATTEMPTS:
                raise
    raise BoiAgentSuggestionsUnavailable(last_error or "LLM suggestion writer returned invalid JSON")


def agent_link_for_item(item: dict[str, Any]) -> dict[str, str]:
    label = str(item.get("title") or item.get("term") or item.get("event_type") or item.get("action_key") or item.get("boi_id") or "")
    return {
        "label": label,
        "url": str(item.get("url") or ""),
        "kind": str(item.get("kind") or ""),
    }


class LangflowBoiAgentUnavailable(RuntimeError):
    """Raised when the trusted Langflow BoI Agent backend cannot answer."""


class BoiAgentRouterUnavailable(RuntimeError):
    """Raised when the required LLM router cannot produce a usable route."""


class BoiAgentStatusUnavailable(RuntimeError):
    """Raised when the required LLM status writer cannot produce progress text."""


class BoiAgentSuggestionsUnavailable(RuntimeError):
    """Raised when the required LLM suggestion writer cannot produce page-aware suggestions."""


def agent_component_error(
    component: str,
    status: str,
    message: str,
    *,
    recoverable: bool = True,
    user_visible: bool = False,
) -> dict[str, Any]:
    return {
        "component": str(component or "agent_component"),
        "status": str(status or "component_error"),
        "message": text_excerpt(str(message or ""), 700),
        "recoverable": bool(recoverable),
        "user_visible": bool(user_visible),
    }


ALLOWED_AGENT_ROUTES = {"fast", "deep", "inbox", "manual_handoff", "approval_required"}
ALLOWED_AGENT_INTENTS = {
    "search",
    "page_qa",
    "summarize",
    "diagram",
    "workflow_explain",
    "gap_check",
    "trace_reasoning",
    "inbox",
    "manual_complete",
    "approval",
    "event_publish",
    "action_invoke",
    "workflow_start",
    "event_type_draft",
}
DEEP_AGENT_INTENTS = {"diagram", "workflow_explain", "gap_check", "trace_reasoning"}
MUTATION_AGENT_INTENTS = {"manual_complete", "approval", "event_publish", "action_invoke", "workflow_start", "event_type_draft"}


def normalize_agent_route(value: str) -> str:
    route = str(value or "").strip().lower().replace("-", "_")
    return route if route in ALLOWED_AGENT_ROUTES else "fast"


def require_llm_agent_route(value: Any) -> str:
    route = str(value or "").strip().lower().replace("-", "_")
    if route not in ALLOWED_AGENT_ROUTES:
        raise BoiAgentRouterUnavailable("LLM router returned invalid route")
    return route


def normalize_agent_intent(value: str, *, fallback: str = "search") -> str:
    intent = str(value or "").strip().lower().replace("-", "_")
    aliases = {
        "lookup": "search",
        "page_summary": "summarize",
        "summary": "summarize",
        "workflow_reasoning": "trace_reasoning",
        "reasoning": "trace_reasoning",
        "manual_handoff": "manual_complete",
        "approval_required": "approval",
        "publish_event": "event_publish",
        "event": "event_publish",
        "invoke_action": "action_invoke",
        "action": "action_invoke",
        "start_workflow": "workflow_start",
        "forced_fast": fallback,
        "forced_deep": fallback if fallback in DEEP_AGENT_INTENTS else "trace_reasoning",
    }
    intent = aliases.get(intent, intent)
    return intent if intent in ALLOWED_AGENT_INTENTS else fallback


def require_llm_agent_intent(value: Any) -> str:
    intent = normalize_agent_intent(str(value or ""), fallback="")
    if intent not in ALLOWED_AGENT_INTENTS:
        raise BoiAgentRouterUnavailable("LLM router returned invalid intent")
    return intent


def safety_route_override(question: str) -> str | None:
    q = str(question or "").lower()
    manual_action_terms = ("handoff 완료", "핸드오프 완료", "조치 완료", "완료 처리", "조치내용", "조치 내용", "완료 기록", "완료로 기록")
    approval_terms = ("승인", "approve", "실행해", "실행해줘", "invoke", "publish", "게시", "배포", "반영", "적용", "source_apply", "doc_body_apply")
    if any(term in q for term in manual_action_terms):
        return "manual_handoff"
    if any(term in q for term in approval_terms):
        return "approval_required"
    return None


def deterministic_agent_intent(question: str, current_url: str = "") -> str:
    q = str(question or "").lower()
    if (
        any(term in q for term in ("event type", "event-type", "이벤트 타입", "이벤트 유형", "이벤트 정의", "신규 이벤트"))
        and any(term in q for term in ("초안", "만들", "생성", "정의", "추가", "draft", "create"))
    ):
        return "event_type_draft"
    if re.search(r"\b[a-z][a-z0-9_]*(?:\.[a-z][a-z0-9_]*)+\.v\d+\b", question) and any(term in q for term in ("이벤트 발행", "event 발행", "publish event", "이벤트를 발행", "이벤트 발생", "발행해", "발행해줘")):
        return "event_publish"
    if any(term in q for term in ("workflow 시작", "workflow 실행", "워크플로우 시작", "워크플로우 실행", "workflow start", "start workflow")):
        return "workflow_start"
    if re.search(r"\b[a-z][a-z0-9_]*(?:\.[a-z][a-z0-9_]*){2,}\b", question) and any(term in q for term in ("action 실행", "액션 실행", "action 요청", "액션 요청", "invoke", "호출", "실행해", "실행해줘")):
        return "action_invoke"
    if safety := safety_route_override(q):
        return "manual_complete" if safety == "manual_handoff" else "approval"
    profile = select_agent_goal_profile_for_text(question, current_url)
    if profile:
        return normalize_agent_intent(str(profile.get("intent") or profile.get("goal_type") or ""), fallback="page_qa")
    if any(term in q for term in ("mermaid", "머메이드", "flowchart", "다이어그램", "도식", "프로세스 플로우", "프로세스플로우", "그려", "그려줘")):
        return "diagram"
    if any(term in q for term in ("부족", "누락", "없는지", "없나", "gap", "갭", "action spec", "액션 spec", "명세", "완성도")):
        return "gap_check"
    if any(term in q for term in ("trace", "트레이스", "workflow status", "로그", "왜", "원인", "리스크", "시뮬레이션", "추론", "판단")):
        return "trace_reasoning"
    if any(term in q for term in ("찾", "검색", "링크", "목록", "어디", "보여줘")):
        return "search"
    if any(term in q for term in ("요약", "정리", "summary", "summarize")):
        return "summarize"
    return "page_qa" if current_url else "search"


def route_for_agent_intent(intent: str) -> str:
    if intent in DEEP_AGENT_INTENTS:
        return "deep"
    if intent == "inbox":
        return "inbox"
    if intent == "manual_complete":
        return "manual_handoff"
    if intent == "approval":
        return "approval_required"
    if intent in {"event_publish", "action_invoke", "workflow_start"}:
        return "approval_required"
    if intent == "event_type_draft":
        return "approval_required"
    return "fast"


def router_prompt_for_request(req: BoiAgentChatRequest, employee_id: str) -> str:
    return json.dumps(
        {
            "task": "Route this BoI Agent request. Return JSON only.",
            "allowed_routes": sorted(ALLOWED_AGENT_ROUTES),
            "allowed_intents": sorted(ALLOWED_AGENT_INTENTS),
            "route_policy": {
                "fast": "search, page_qa, summarize only. Use current page context and ontology search.",
                "deep": "diagram, workflow_explain, gap_check, trace_reasoning, multi-hop reasoning, artifact generation",
                "inbox": "ask what actions/manual handoffs are pending for the employee",
                "manual_handoff": "request to complete or record a manual handoff",
                "approval_required": "request to approve, execute, publish, edit, or mutate shared/runtime state",
            },
            "intent_policy": {
                "search": "find documents, SOPs, actions, events, dictionary terms",
                "page_qa": "answer a question about the current page",
                "summarize": "summarize current page or search results",
                "diagram": "produce Mermaid or visual workflow artifacts",
                "workflow_explain": "explain Event -> SOP -> Action -> Manual Handoff -> BoI flow",
                "gap_check": "find missing Action Specs, Event Types, evidence, or workflow gaps",
                "trace_reasoning": "reason over trace/workflow/action evidence",
                "inbox": "show assigned work",
                "manual_complete": "complete a manual handoff",
                "approval": "approve, publish, invoke, edit, deploy, or mutate state",
                "event_publish": "publish a specific Event Type through Event Broker after confirmation",
                "action_invoke": "invoke a specific allow-listed Action Gateway action after confirmation",
                "workflow_start": "start a specific SOP workflow after confirmation",
                "event_type_draft": "create a draft proposal for a new Event Type, never directly apply it",
            },
            "employee_id": employee_id,
            "question": req.question,
            "current_url": req.current_url,
            "page_title": req.page_context.get("title") if isinstance(req.page_context, dict) else "",
            "selected_text": req.selected_text[:1000],
            "conversation_tail": req.conversation[-4:],
            "required_json_schema": {
                "route": "fast|deep|inbox|manual_handoff|approval_required",
                "confidence": "0.0-1.0",
                "intent": "search|page_qa|summarize|diagram|workflow_explain|gap_check|trace_reasoning|inbox|manual_complete|approval|event_publish|action_invoke|workflow_start|event_type_draft",
                "reason": "short Korean or English reason",
                "requires_mutation": "boolean",
                "requires_deep_reasoning": "boolean",
            },
        },
        ensure_ascii=False,
    )


def parse_router_payload(text: str) -> dict[str, Any] | None:
    parsed = parse_langflow_json_text(text)
    if parsed is not None and parsed.get("route"):
        return parsed
    decoder = json.JSONDecoder()
    stripped = text.strip()
    if stripped.startswith("```") and stripped.endswith("```"):
        fenced = re.sub(r"^```[A-Za-z0-9_-]*\s*", "", stripped, count=1).strip()
        fenced = re.sub(r"\s*```$", "", fenced, count=1).strip()
        if fenced and fenced != stripped:
            payload = parse_router_payload(fenced)
            if payload and payload.get("route"):
                return payload
    for index, char in enumerate(stripped):
        if char != "{":
            continue
        try:
            payload, _end = decoder.raw_decode(stripped[index:])
        except json.JSONDecodeError:
            continue
        if isinstance(payload, dict) and payload.get("route"):
            return payload
    return None


def parse_agent_compose_payload(text: str) -> dict[str, Any] | None:
    parsed = parse_langflow_json_text(text)
    if isinstance(parsed, dict):
        answer = str(parsed.get("answer_markdown") or parsed.get("answer") or parsed.get("message") or parsed.get("final_answer") or "").strip()
        if answer:
            parsed["answer_markdown"] = answer
            return parsed
        plan = normalize_agent_answer_plan(parsed)
        if plan:
            parsed["answer_plan"] = plan
            return parsed
    decoder = json.JSONDecoder()
    stripped = text.strip()
    if stripped.startswith("```") and stripped.endswith("```"):
        fenced = re.sub(r"^```[A-Za-z0-9_-]*\s*", "", stripped, count=1).strip()
        fenced = re.sub(r"\s*```$", "", fenced, count=1).strip()
        if fenced and fenced != stripped:
            payload = parse_agent_compose_payload(fenced)
            if payload:
                return payload
    for index, char in enumerate(stripped):
        if char != "{":
            continue
        try:
            payload, _end = decoder.raw_decode(stripped[index:])
        except json.JSONDecodeError:
            continue
        if isinstance(payload, dict):
            answer = str(payload.get("answer_markdown") or payload.get("answer") or payload.get("message") or payload.get("final_answer") or "").strip()
            if answer:
                payload["answer_markdown"] = answer
                return payload
            plan = normalize_agent_answer_plan(payload)
            if plan:
                payload["answer_plan"] = plan
                return payload
    return None


def sanitize_agent_plan_text(value: Any, limit: int = 360) -> str:
    text = re.sub(r"\s+", " ", str(value or "").strip())
    text = re.sub(r"^#{1,6}\s*", "", text).strip()
    text = text.replace("|", "\\|")
    if len(text) > limit:
        text = text[:limit].rstrip() + "..."
    return text


def normalize_agent_answer_plan(payload: dict[str, Any]) -> dict[str, Any] | None:
    if not isinstance(payload, dict):
        return None
    source = payload.get("answer_plan") if isinstance(payload.get("answer_plan"), dict) else payload
    title = sanitize_agent_plan_text(source.get("title") or "답변", 80)
    title = re.sub(r"\s*-\d+\s*$", "", title).strip() or "답변"
    summary = sanitize_agent_plan_text(source.get("summary") or source.get("short_answer") or "", 700)
    suggestions = [
        sanitize_agent_plan_text(item, 120)
        for item in (source.get("suggested_questions") or source.get("followups") or [])[:4]
        if sanitize_agent_plan_text(item, 120)
    ]
    for index in range(1, 5):
        item = sanitize_agent_plan_text(source.get(f"suggested_question_{index}") or "", 120)
        if item:
            suggestions.append(item)
    suggestions = suggestions[:4]
    if not summary:
        return None
    return {
        "title": title or "답변",
        "summary": summary,
        "bullets": [],
        "links": [],
        "suggested_questions": suggestions,
    }


def render_agent_answer_plan(plan: dict[str, Any]) -> str:
    title = sanitize_agent_plan_text(plan.get("title") or "답변", 80)
    parts = [f"## {title}"]
    summary = sanitize_agent_plan_text(plan.get("summary") or "", 700)
    if summary:
        parts.append(summary)
    bullets = plan.get("bullets") if isinstance(plan.get("bullets"), list) else []
    bullet_lines = []
    for item in bullets[:7]:
        text = sanitize_agent_plan_text((item or {}).get("text") if isinstance(item, dict) else item, 420)
        if text:
            bullet_lines.append(f"- {text}")
    if bullet_lines:
        parts.append("\n".join(bullet_lines))
    links = plan.get("links") if isinstance(plan.get("links"), list) else []
    link_lines = []
    for item in links[:6]:
        if not isinstance(item, dict):
            continue
        label = sanitize_agent_plan_text(item.get("label") or item.get("url") or "", 90)
        url = str(item.get("url") or "").strip()
        reason = sanitize_agent_plan_text(item.get("reason") or "", 180)
        if not label or not url:
            continue
        suffix = f" - {reason}" if reason else ""
        link_lines.append(f"- [{label}]({url}){suffix}")
    if link_lines:
        parts.append("**관련 링크**\n" + "\n".join(link_lines))
    return "\n\n".join(part for part in parts if str(part).strip()).strip()


def agent_composer_evidence_excerpt(value: Any, limit: int = 650) -> str:
    text = str(value or "")
    text = re.sub(r"```.*?```", " ", text, flags=re.DOTALL)
    text = re.sub(r"\[([^\]]+)\]\([^)]+\)", r"\1", text)
    text = re.sub(r"^\s{0,3}#{1,6}\s*", "", text, flags=re.MULTILINE)
    text = re.sub(r"^\s*\|.*\|\s*$", " ", text, flags=re.MULTILINE)
    text = re.sub(r"[#|*_>`]+", " ", text)
    text = re.sub(r"\s+", " ", text).strip()
    return text_excerpt(text, limit)


def compact_agent_composer_page_context(value: Any) -> dict[str, Any]:
    raw = value if isinstance(value, dict) else {}
    compact: dict[str, Any] = {}
    for key in ("page_kind", "resolved", "title", "boi_id", "type", "event_type", "workflow_key", "trace_id"):
        if raw.get(key) not in (None, "", []):
            compact[key] = raw.get(key)
    for key in ("workflow_action_count", "workflow_manual_action_count"):
        if raw.get(key) not in (None, "", []):
            compact[key] = raw.get(key)
    if isinstance(raw.get("workflow_event_types"), list):
        compact["workflow_event_types"] = [str(item) for item in raw["workflow_event_types"][:6]]
    return compact


def looks_like_repetitive_generation(text: str) -> bool:
    normalized = re.sub(r"\s+", " ", str(text or "")).strip().lower()
    if not normalized:
        return False
    if re.search(r"\b(de la vie|de facto)\b", normalized):
        return True
    if re.search(r"(.{6,80})(?:[.。,:;!?]*\s+\1){2,}", normalized):
        return True
    if re.search(r"(.{3,40})(?:\\s*[-·,/]?\\s*\\1){4,}", normalized):
        return True
    tokens = re.findall(r"[a-z0-9가-힣一-龥]+", normalized)
    if len(tokens) < 30:
        return False
    for size in (1, 2, 3):
        grams = [" ".join(tokens[index : index + size]) for index in range(0, len(tokens) - size + 1)]
        if not grams:
            continue
        most_common = max(grams.count(item) for item in set(grams))
        if most_common >= max(6, int(len(grams) * 0.14)):
            return True
    return False


DISALLOWED_AGENT_SCRIPT_RE = re.compile(
    r"[\u0370-\u03ff\u0400-\u052f\u0590-\u05ff\u0600-\u06ff\u0750-\u077f\u4e00-\u9fff]"
)
ALLOWED_AGENT_LATIN_WORDS = {
    "acl",
    "action",
    "agent",
    "ai",
    "api",
    "boi",
    "codex",
    "event",
    "github",
    "hbm",
    "inbox",
    "json",
    "kafka",
    "langflow",
    "manual",
    "mcp",
    "mermaid",
    "nas",
    "native",
    "okf",
    "rbac",
    "sop",
    "sso",
    "trace",
    "url",
    "wiki",
    "workflow",
}


def agent_quality_text_without_code_and_urls(text: str) -> str:
    stripped = re.sub(r"```.*?```", " ", str(text or ""), flags=re.DOTALL)
    stripped = re.sub(r"`[^`]*`", " ", stripped)
    stripped = re.sub(r"\]\([^)]+\)", "]", stripped)
    stripped = re.sub(r"https?://\S+", " ", stripped)
    return stripped


def contains_disallowed_agent_script(text: str) -> bool:
    return bool(DISALLOWED_AGENT_SCRIPT_RE.search(agent_quality_text_without_code_and_urls(text)))


def looks_like_english_dominant_agent_line(text: str) -> bool:
    for raw_line in str(text or "").splitlines():
        line = re.sub(r"^[#>*\-\s0-9.]+", "", raw_line).strip()
        if not line:
            continue
        line = agent_quality_text_without_code_and_urls(line)
        if re.search(r"[가-힣]", line):
            continue
        latin_words = re.findall(r"\b[A-Za-z][A-Za-z-]{2,}\b", line)
        if len(latin_words) < 3:
            continue
        unexpected = [
            word
            for word in latin_words
            if word.lower().strip("-") not in ALLOWED_AGENT_LATIN_WORDS
        ]
        if unexpected:
            return True
    return False


def invalid_agent_composer_answer_reason(answer: str) -> str:
    text = str(answer or "").strip()
    if not text:
        return "empty_answer"
    if re.search(r"(?:ization){2,}|\\text\s*\{|\$|\\\(|\\\)|<\|channel\>|\bde/v\d+\b|(?:thought|hought)[_-]?process", text, flags=re.IGNORECASE):
        return "corrupt_model_artifact"
    if re.search(r"[가-힣A-Za-z]{2,}\s*-\s*(?:\n|$)", text):
        return "dangling_hyphen_fragment"
    if looks_like_repetitive_generation(text):
        return "degenerate_repetition"
    if re.search(r"[가-힣]{2,}(?:-[가-힣]{2,}){2,}", text):
        return "korean_hyphen_noise"
    if text.count("```") % 2:
        return "broken_markdown_fence"
    if re.search(r"```[^\S\r\n]*json\b", text, flags=re.IGNORECASE):
        return "json_fence_fragment"
    lowered = text.lower()
    prompt_echo_markers = (
        "user wants",
        "target audience",
        "constraint:",
        "format: github-flavored markdown",
        "structured_draft",
        "body_excerpt",
        "required_json_schema",
        "supplied evidence",
        "do not invent private data",
        "return only one json object",
    )
    if any(marker in lowered for marker in prompt_echo_markers):
        return "prompt_echo"
    if re.match(r"^\s*[-*]\s+user\s+wants\b", text, flags=re.IGNORECASE):
        return "prompt_echo"
    if contains_disallowed_agent_script(text):
        return "non_korean_script"
    if looks_like_english_dominant_agent_line(text):
        return "english_dominant_line"
    if text.startswith("{") or text.startswith("[") or text.startswith("```json"):
        return "unparsed_json"
    if text.startswith("chatcmpl-"):
        return "openai_response_metadata"
    return ""


def boi_agent_composer_request_body(payload: dict[str, Any], employee_id: str, *, repair: dict[str, Any] | None = None) -> dict[str, Any]:
    source_payload = payload if isinstance(payload, dict) else {}
    user_payload = {
        "employee_id": employee_id,
        "question": source_payload.get("question") or "",
        "route": source_payload.get("route") or "",
        "intent": source_payload.get("intent") or "",
        "page_context": compact_agent_composer_page_context(source_payload.get("page_context")),
        "evidence_summary": agent_composer_evidence_excerpt(source_payload.get("structured_draft") or "", 180),
    }
    if repair:
        user_payload["quality_repair"] = repair
    system_content = (
        "JSON만 출력하세요. 키는 title, summary 두 개만 사용하세요. "
        "title은 24자 이하, summary는 70자 이하의 짧은 한국어 문장입니다. "
        "배열, 중첩 객체, 마크다운, 코드블록, 표, 링크, 영어 설명, 반복 문구, 추가 텍스트는 금지입니다. "
        "제공된 근거만 사용하고 없는 내용은 만들지 마세요."
    )
    if repair:
        system_content += (
            " 이전 출력은 품질 검증에 실패했습니다. 같은 표현을 반복하지 말고 더 짧은 title, summary JSON만 반환하세요."
        )
    return {
        "model": BOI_AGENT_COMPOSER_MODEL,
        "temperature": 0,
        "frequency_penalty": 0.6,
        "max_tokens": min(BOI_AGENT_COMPOSER_MAX_TOKENS, 60),
        "response_format": {
            "type": "json_schema",
            "json_schema": {
                "name": "boi_agent_answer_plan",
                "schema": {
                    "type": "object",
                    "properties": {
                        "title": {"type": "string"},
                        "summary": {"type": "string"},
                    },
                    "required": ["title", "summary"],
                },
            },
        },
        "messages": [
            {"role": "system", "content": system_content},
            {
                "role": "user",
                "content": json.dumps(user_payload, ensure_ascii=False),
            },
        ],
    }


def parse_boi_agent_composer_response(raw: Any) -> tuple[dict[str, Any] | None, list[str]]:
    invalid_reasons: list[str] = []
    for text in iter_langflow_text_candidates(raw):
        candidate = parse_agent_compose_payload(text)
        if candidate:
            if isinstance(candidate.get("answer_plan"), dict):
                answer = render_agent_answer_plan(candidate["answer_plan"])
                suggestions = candidate["answer_plan"].get("suggested_questions")
                composer_contract = "answer_plan"
            else:
                answer = str(candidate.get("answer_markdown") or "").strip()
                suggestions = candidate.get("suggested_questions")
                composer_contract = "legacy_answer_markdown"
            invalid_reason = invalid_agent_composer_answer_reason(answer)
            if invalid_reason:
                invalid_reasons.append(invalid_reason)
                continue
            return {
                "answer_markdown": answer,
                "composer_contract": composer_contract,
                **({"suggested_questions": suggestions} if isinstance(suggestions, list) and suggestions else {}),
            }, invalid_reasons
    return None, invalid_reasons or ["no_valid_json_answer"]


def call_boi_agent_composer_llm(payload: dict[str, Any], employee_id: str) -> dict[str, Any]:
    if not BOI_AGENT_COMPOSER_LLM_ENABLED:
        raise NativeAgentRuntimeUnavailable("LLM answer composer is not configured")
    if not BOI_AGENT_COMPOSER_BASE_URL or not BOI_AGENT_COMPOSER_MODEL:
        raise NativeAgentRuntimeUnavailable("LLM answer composer base URL/model is missing")
    url = BOI_AGENT_COMPOSER_BASE_URL.rstrip("/") + "/chat/completions"
    headers = {"Content-Type": "application/json"}
    if BOI_AGENT_COMPOSER_API_KEY:
        headers["Authorization"] = f"Bearer {BOI_AGENT_COMPOSER_API_KEY}"
    invalid_reasons: list[str] = []
    repair_payload: dict[str, Any] | None = None
    for attempt in range(BOI_AGENT_COMPOSER_MAX_ATTEMPTS):
        body = boi_agent_composer_request_body(payload, employee_id, repair=repair_payload)
        try:
            with boi_agent_llm_slot("composer"):
                with httpx.Client(timeout=BOI_AGENT_COMPOSER_TIMEOUT_SECONDS) as client:
                    response = client.post(url, headers=headers, json=body)
                    response.raise_for_status()
                    raw = response.json()
        except Exception as exc:
            raise NativeAgentRuntimeUnavailable(f"LLM answer composer call failed: {exc}") from exc
        parsed, reasons = parse_boi_agent_composer_response(raw)
        invalid_reasons.extend(reasons)
        if parsed:
            if attempt > 0:
                parsed["quality_repair_used"] = True
            return parsed
        repair_payload = {
            "previous_rejection_reasons": sorted(set(invalid_reasons)),
            "required_fix": "Return a Korean-only structured answer plan. Do not include Markdown code fences, prompt text, or mixed-language filler. Keep official BoI/SOP/Event/Action/API/MCP identifiers only when needed.",
        }
    reason_summary = ", ".join(sorted(set(invalid_reasons))) or "unknown"
    raise NativeAgentRuntimeUnavailable(f"LLM answer composer returned invalid final answer: {reason_summary}")


REQUIRED_AGENT_STATUS_STAGES = ("page_context", "intent", "retrieval", "tool_loop", "compose", "answer_stream", "waiting")


def status_prompt_for_request(req: BoiAgentChatRequest, employee_id: str) -> str:
    return json.dumps(
        {
            "task": "Write BoI Agent progress status lines. Return JSON only.",
            "language": "ko",
            "style": {
                "tone": "일반 구성원이 이해하기 쉬운 업무 문장",
                "length": "각 message는 18~70자 한 문장",
                "avoid": ["dry-run", "invoke", "router", "fallback", "stub", "LLM", "LangGraph", "stack trace"],
                "must_be_specific_to_request": True,
            },
            "required_stages": list(REQUIRED_AGENT_STATUS_STAGES),
            "stage_meaning": {
                "page_context": "현재 페이지, 사번, 접근 권한을 확인하는 단계",
                "intent": "질문 의도와 필요한 산출물을 판단하는 단계",
                "retrieval": "BoI Wiki, SOP, Event, Action, Dictionary, runtime evidence를 찾는 단계",
                "tool_loop": "필요한 근거를 여러 번 조회하고 빈틈을 점검하는 단계",
                "compose": "답변, 표, Mermaid, 링크, citation을 정리하는 단계",
                "answer_stream": "완성된 답변을 사용자에게 보여주는 단계",
                "waiting": "작업이 길어질 때 계속 처리 중임을 알리는 단계",
            },
            "employee_id": employee_id,
            "question": req.question,
            "current_url": req.current_url,
            "page_title": req.page_context.get("title") if isinstance(req.page_context, dict) else "",
            "selected_text_excerpt": text_excerpt(req.selected_text, 500),
            "conversation_tail": req.conversation[-3:],
            "required_json_schema": {
                "statuses": [
                    {
                        "stage": "one of required_stages",
                        "message": "Korean one-line progress text",
                    }
                ]
            },
        },
        ensure_ascii=False,
    )


def parse_status_payload(text: str) -> dict[str, Any] | None:
    parsed = parse_langflow_json_text(text)
    if isinstance(parsed, dict) and isinstance(parsed.get("statuses"), list):
        return parsed
    decoder = json.JSONDecoder()
    stripped = text.strip()
    for index, char in enumerate(stripped):
        if char != "{":
            continue
        try:
            payload, _end = decoder.raw_decode(stripped[index:])
        except json.JSONDecodeError:
            continue
        if isinstance(payload, dict) and isinstance(payload.get("statuses"), list):
            return payload
    return None


def parse_stream_plan_payload(text: str) -> dict[str, Any] | None:
    parsed = parse_langflow_json_text(text)
    if isinstance(parsed, dict) and parsed.get("route") and isinstance(parsed.get("statuses"), list):
        return parsed
    decoder = json.JSONDecoder()
    stripped = text.strip()
    for index, char in enumerate(stripped):
        if char != "{":
            continue
        try:
            payload, _end = decoder.raw_decode(stripped[index:])
        except json.JSONDecodeError:
            continue
        if isinstance(payload, dict) and payload.get("route") and isinstance(payload.get("statuses"), list):
            return payload
    return None


def is_usable_llm_status_message(message: str) -> bool:
    text = str(message or "").strip()
    if not text:
        return False
    if len(text) > 90:
        return False
    if contains_disallowed_agent_script(text):
        return False
    # Drop common local-LLM degeneration patterns instead of showing broken
    # progress text as if it were healthy. This is validation, not a canned
    # replacement: if every generated line is rejected, the Agent returns a
    # status_generation_failed error.
    if re.search(r"[A-Za-z]{8,}", text):
        return False
    if re.search(r"[가-힣]-[가-힣]", text):
        return False
    if re.search(r"([A-Za-z]{3,})(?:[-_\s]+\1){1,}", text, flags=re.IGNORECASE):
        return False
    if re.search(r"([가-힣]{2,})(?:을|를|은|는|이|가|의)?[-_\s·/]+\1", text):
        return False
    if re.search(r"([가-힣]{2,})(?:[-_\s·/]*\1){1,}", text):
        return False
    if re.search(r"([가-힣])\1{2,}", text):
        return False
    return True


def normalize_llm_status_steps(payload: dict[str, Any]) -> list[dict[str, str]]:
    seen: dict[str, str] = {}
    seen_messages: set[str] = set()
    for item in payload.get("statuses") or []:
        if not isinstance(item, dict):
            continue
        stage = str(item.get("stage") or "").strip()
        message = re.sub(r"\s+", " ", str(item.get("message") or "")).strip()
        if stage not in REQUIRED_AGENT_STATUS_STAGES or not message:
            continue
        if not is_usable_llm_status_message(message):
            continue
        if len(message) > 90:
            message = message[:89].rstrip() + "…"
        if message in seen_messages:
            continue
        seen_messages.add(message)
        seen.setdefault(stage, message)
    if not seen:
        raise BoiAgentStatusUnavailable("LLM status writer returned no usable status message")
    ordered_stages = [stage for stage in REQUIRED_AGENT_STATUS_STAGES if stage in seen]
    return [{"stage": stage, "message": seen[stage], "source": "llm_status"} for stage in ordered_stages]


def normalize_llm_route_payload(payload: dict[str, Any], req: BoiAgentChatRequest) -> dict[str, Any]:
    route = require_llm_agent_route(payload.get("route"))
    try:
        confidence = float(payload.get("confidence") or 0)
    except (TypeError, ValueError):
        confidence = 0.0
    if confidence < BOI_AGENT_ROUTER_CONFIDENCE_THRESHOLD:
        raise BoiAgentRouterUnavailable("LLM router confidence is below threshold")
    intent = require_llm_agent_intent(payload.get("intent"))
    if intent in DEEP_AGENT_INTENTS and route != "deep":
        route = "deep"
    elif intent == "inbox":
        route = "inbox"
    elif intent == "manual_complete":
        route = "manual_handoff"
    elif intent == "approval":
        route = "approval_required"
    elif intent == "event_type_draft":
        route = "approval_required"
    return {
        "route": route,
        "confidence": confidence,
        "intent": intent,
        "reason": str(payload.get("reason") or "llm_router"),
        "requires_mutation": bool(payload.get("requires_mutation") or route in {"manual_handoff", "approval_required"}),
        "requires_deep_reasoning": bool(payload.get("requires_deep_reasoning") or payload.get("requires_langflow") or route == "deep"),
        # Compatibility field for older clients. Deep answers are handled by native agent unless backend=langflow.
        "requires_langflow": False,
        "router_backend": "llm",
    }


def call_boi_agent_status_llm(req: BoiAgentChatRequest, employee_id: str) -> list[dict[str, str]]:
    if not BOI_AGENT_STATUS_REQUIRED:
        raise BoiAgentStatusUnavailable("LLM status writer is disabled by configuration")
    if not BOI_AGENT_STATUS_LLM_ENABLED:
        raise BoiAgentStatusUnavailable("LLM status writer is not configured")
    if not BOI_AGENT_STATUS_BASE_URL or not BOI_AGENT_STATUS_MODEL:
        raise BoiAgentStatusUnavailable("LLM status writer base URL/model is missing")
    url = BOI_AGENT_STATUS_BASE_URL.rstrip("/") + "/chat/completions"
    headers = {"Content-Type": "application/json"}
    if BOI_AGENT_STATUS_API_KEY:
        headers["Authorization"] = f"Bearer {BOI_AGENT_STATUS_API_KEY}"
    body = {
        "model": BOI_AGENT_STATUS_MODEL,
        "temperature": 0.2,
        "max_tokens": BOI_AGENT_STATUS_MAX_TOKENS,
        "response_format": {"type": "text"},
        "messages": [
            {
                "role": "system",
                "content": (
                    "You write concise progress status lines for BoI Agent. "
                    "Return only JSON. Do not answer the user's question."
                ),
            },
            {"role": "user", "content": status_prompt_for_request(req, employee_id)},
        ],
    }
    try:
        with boi_agent_llm_slot("status"):
            with httpx.Client(timeout=BOI_AGENT_STATUS_TIMEOUT_SECONDS) as client:
                response = client.post(url, headers=headers, json=body)
                response.raise_for_status()
                payload = response.json()
    except Exception as exc:
        raise BoiAgentStatusUnavailable(f"LLM status writer call failed: {exc}") from exc
    parsed = None
    for text in iter_langflow_text_candidates(payload):
        candidate = parse_status_payload(text)
        if candidate:
            parsed = candidate
            break
    if not parsed:
        raise BoiAgentStatusUnavailable("LLM status writer returned invalid JSON")
    return normalize_llm_status_steps(parsed)


def stream_plan_prompt_for_request(req: BoiAgentChatRequest, employee_id: str) -> str:
    payload: dict[str, Any] = {
        "task": "route_and_status_plan_only",
        "lang": "ko",
        "employee_id": employee_id,
        "question": req.question,
        "url": req.current_url,
        "title": req.page_context.get("title") if isinstance(req.page_context, dict) else "",
        "routes": "fast|deep|inbox|manual_handoff|approval_required",
        "intents": "|".join(sorted(ALLOWED_AGENT_INTENTS)),
        "stages": "|".join(REQUIRED_AGENT_STATUS_STAGES),
        "must": [
            "JSON only",
            "No markdown",
            "Do not answer the user",
            "statuses has exactly 3 distinct Korean nontechnical messages",
            "Use three different stages: early context check, evidence/tool work, answer composition",
            "Do not include a reason field",
            "Do not repeat the same sentence or phrase",
            "Avoid broken hyphenated Korean such as 의-목",
        ],
        "output_shape": {
            "route": "route",
            "confidence": 0.0,
            "intent": "intent",
            "requires_mutation": False,
            "requires_deep_reasoning": False,
            "statuses": [{"stage": "stage", "message": "18-70 chars"}],
        },
    }
    selected = text_excerpt(req.selected_text, 220)
    if selected:
        payload["selected"] = selected
    return json.dumps(payload, ensure_ascii=False, separators=(",", ":"))


def call_boi_agent_stream_plan_llm(req: BoiAgentChatRequest, employee_id: str) -> dict[str, Any]:
    if not BOI_AGENT_STATUS_REQUIRED:
        raise BoiAgentStatusUnavailable("LLM status writer is disabled by configuration")
    if not BOI_AGENT_STATUS_LLM_ENABLED:
        raise BoiAgentStatusUnavailable("LLM status writer is not configured")
    if not BOI_AGENT_STATUS_BASE_URL or not BOI_AGENT_STATUS_MODEL:
        raise BoiAgentStatusUnavailable("LLM status writer base URL/model is missing")
    if BOI_AGENT_ROUTER_REQUIRED and (not BOI_AGENT_ROUTER_LLM_ENABLED or BOI_AGENT_ROUTER_MODE != "llm_first"):
        raise BoiAgentRouterUnavailable("LLM router is not configured")
    url = BOI_AGENT_STATUS_BASE_URL.rstrip("/") + "/chat/completions"
    headers = {"Content-Type": "application/json"}
    if BOI_AGENT_STATUS_API_KEY:
        headers["Authorization"] = f"Bearer {BOI_AGENT_STATUS_API_KEY}"

    def post_stream_plan(messages: list[dict[str, str]]) -> dict[str, Any]:
        body = {
            "model": BOI_AGENT_STATUS_MODEL,
            "temperature": 0,
            "frequency_penalty": 0.6,
            "max_tokens": max(BOI_AGENT_STATUS_MAX_TOKENS, BOI_AGENT_ROUTER_MAX_TOKENS),
            # Keep this aligned with the router LLM path. The local
            # OpenAI-compatible Gemma runtime used in NAS is more reliable with
            # text mode plus strict JSON extraction than json_schema mode.
            "response_format": {"type": "text"},
            "messages": messages,
        }
        try:
            with boi_agent_llm_slot("stream_plan"):
                with httpx.Client(timeout=max(BOI_AGENT_STATUS_TIMEOUT_SECONDS, BOI_AGENT_ROUTER_TIMEOUT_SECONDS)) as client:
                    response = client.post(url, headers=headers, json=body)
                    response.raise_for_status()
                    return response.json()
        except Exception as exc:
            raise BoiAgentStatusUnavailable(f"LLM stream plan call failed: {exc}") from exc

    def parse_stream_plan_response(payload: dict[str, Any]) -> dict[str, Any]:
        for text in iter_langflow_text_candidates(payload):
            candidate = parse_stream_plan_payload(text)
            if candidate:
                return candidate
        raise BoiAgentStatusUnavailable("LLM stream plan returned invalid JSON")

    initial_messages = [
            {
                "role": "system",
                "content": (
                    "You plan BoI Agent streaming work. Return one compact JSON object with "
                    "both routing fields and a complete progress status sequence. "
                    "Do not answer the user."
                ),
            },
            {"role": "user", "content": stream_plan_prompt_for_request(req, employee_id)},
    ]
    parsed = parse_stream_plan_response(post_stream_plan(initial_messages))
    status_steps = normalize_llm_status_steps(parsed)
    route = normalize_llm_route_payload(parsed, req)
    return {"status_steps": status_steps, "route": apply_agent_route_overrides(req, route)}


def router_llm_backoff_remaining() -> float:
    return max(0.0, _BOI_AGENT_ROUTER_BACKOFF_UNTIL - time.monotonic())


def call_boi_agent_router_llm(req: BoiAgentChatRequest, employee_id: str) -> dict[str, Any]:
    global _BOI_AGENT_ROUTER_BACKOFF_UNTIL, _BOI_AGENT_ROUTER_BACKOFF_REASON
    if not BOI_AGENT_ROUTER_LLM_ENABLED or BOI_AGENT_ROUTER_MODE != "llm_first":
        raise BoiAgentRouterUnavailable("LLM router is not configured")
    if not BOI_AGENT_ROUTER_BASE_URL or not BOI_AGENT_ROUTER_MODEL:
        raise BoiAgentRouterUnavailable("LLM router base URL/model is missing")
    backoff_remaining = router_llm_backoff_remaining()
    if backoff_remaining > 0:
        raise BoiAgentRouterUnavailable(
            f"LLM router backoff active for {backoff_remaining:.1f}s after {_BOI_AGENT_ROUTER_BACKOFF_REASON or 'previous failure'}"
        )
    url = BOI_AGENT_ROUTER_BASE_URL.rstrip("/") + "/chat/completions"
    headers = {"Content-Type": "application/json"}
    if BOI_AGENT_ROUTER_API_KEY:
        headers["Authorization"] = f"Bearer {BOI_AGENT_ROUTER_API_KEY}"
    body = {
        "model": BOI_AGENT_ROUTER_MODEL,
        "temperature": 0,
        "max_tokens": BOI_AGENT_ROUTER_MAX_TOKENS,
        # Some OpenAI-compatible runtimes used for local Gemma serving reject
        # OpenAI's older json_object mode and only accept text/json_schema.
        # We request text and keep strict JSON extraction in parse_router_payload.
        "response_format": {"type": "text"},
        "messages": [
            {
                "role": "system",
                "content": (
                    "You are a routing classifier for BoI Wiki Agent. "
                    "Return only one compact JSON object. Do not answer the user."
                ),
            },
            {"role": "user", "content": router_prompt_for_request(req, employee_id)},
        ],
    }
    try:
        with boi_agent_llm_slot("router"):
            with httpx.Client(timeout=BOI_AGENT_ROUTER_TIMEOUT_SECONDS) as client:
                response = client.post(url, headers=headers, json=body)
                response.raise_for_status()
                payload = response.json()
    except Exception as exc:
        if BOI_AGENT_ROUTER_FAILURE_BACKOFF_SECONDS > 0:
            _BOI_AGENT_ROUTER_BACKOFF_UNTIL = time.monotonic() + BOI_AGENT_ROUTER_FAILURE_BACKOFF_SECONDS
            _BOI_AGENT_ROUTER_BACKOFF_REASON = type(exc).__name__
        raise BoiAgentRouterUnavailable(f"LLM router call failed: {exc}") from exc
    _BOI_AGENT_ROUTER_BACKOFF_UNTIL = 0.0
    _BOI_AGENT_ROUTER_BACKOFF_REASON = ""
    parsed = None
    for text in iter_langflow_text_candidates(payload):
        candidate = parse_router_payload(text)
        if candidate and candidate.get("route"):
            parsed = candidate
            break
    if not parsed:
        raise BoiAgentRouterUnavailable("LLM router returned invalid JSON")
    return normalize_llm_route_payload(parsed, req)


def apply_agent_route_overrides(req: BoiAgentChatRequest, route: dict[str, Any]) -> dict[str, Any]:
    deterministic_intent = deterministic_agent_intent(req.question, req.current_url)
    profile = None if deterministic_intent in MUTATION_AGENT_INTENTS else select_agent_goal_profile_for_request(req)
    if profile and int(profile.get("_match_score") or 0) < 20 and route.get("router_backend") in {"llm", "request_hint"}:
        profile = None
    route["intent"] = normalize_agent_intent(str(route.get("intent") or ""), fallback=deterministic_intent)
    if profile:
        profile_intent = normalize_agent_intent(str(profile.get("intent") or ""), fallback=deterministic_intent)
        profile_route = normalize_agent_route(str(profile.get("route") or route_for_agent_intent(profile_intent)))
        route.update(
            {
                "route": profile_route,
                "intent": profile_intent,
                "reason": f"profile override after {route.get('router_backend')}: {profile.get('goal_type')}",
                "requires_deep_reasoning": profile_route == "deep",
                "requires_langflow": False,
                "response_profile": str(profile.get("response_profile") or profile_intent),
                "goal_model": {
                    "goal_type": str(profile.get("goal_type") or profile_intent),
                    "intent": profile_intent,
                    "response_profile": str(profile.get("response_profile") or profile_intent),
                    "route": profile_route,
                    "source": "agent_goal_registry",
                    "description": str(profile.get("description") or ""),
                    "match_score": int(profile.get("_match_score") or 0),
                },
            }
        )
    # Rules are the safety net for obvious artifact/reasoning requests even when the LLM router says fast.
    if not profile and deterministic_intent in DEEP_AGENT_INTENTS and (route.get("route") != "deep" or route.get("intent") != deterministic_intent):
        route.update(
            {
                "route": "deep",
                "intent": deterministic_intent,
                "reason": f"intent override after {route.get('router_backend')}: {deterministic_intent}",
                "requires_deep_reasoning": True,
                "requires_langflow": False,
            }
        )
    if deterministic_intent in {"event_publish", "action_invoke", "workflow_start", "event_type_draft"}:
        route.update(
            {
                "route": "approval_required",
                "intent": deterministic_intent,
                "reason": f"mutation intent override after {route.get('router_backend')}: {deterministic_intent}",
                "requires_mutation": True,
                "requires_langflow": False,
            }
        )
    override = safety_route_override(req.question)
    if override and route.get("route") not in {"manual_handoff", "approval_required"}:
        route.update(
            {
                "route": override,
                "intent": "manual_complete" if override == "manual_handoff" else "approval",
                "reason": f"safety override after {route.get('router_backend')}",
                "requires_mutation": True,
                "requires_langflow": False,
            }
        )
    elif route.get("requires_mutation") and route.get("route") not in {"manual_handoff", "approval_required"}:
        route.update(
            {
                "route": "approval_required",
                "intent": "approval",
                "reason": f"mutation safety override after {route.get('router_backend')}",
                "requires_mutation": True,
                "requires_langflow": False,
            }
        )
    route["route"] = normalize_agent_route(str(route.get("route") or "fast"))
    route["intent"] = normalize_agent_intent(str(route.get("intent") or ""), fallback=deterministic_intent)
    return route


def deterministic_agent_route_for_request(
    req: BoiAgentChatRequest,
    *,
    reason: str = "native goal router",
    component_error: dict[str, Any] | None = None,
) -> dict[str, Any]:
    deterministic_intent = deterministic_agent_intent(req.question, req.current_url)
    profile = None if deterministic_intent in MUTATION_AGENT_INTENTS else select_agent_goal_profile_for_request(req)
    intent = normalize_agent_intent(str((profile or {}).get("intent") or ""), fallback=deterministic_intent)
    route_name = normalize_agent_route(str((profile or {}).get("route") or route_for_agent_intent(intent)))
    route = {
        "route": route_name,
        "confidence": 0.72,
        "intent": intent,
        "reason": reason,
        "requires_mutation": route_name in {"manual_handoff", "approval_required"},
        "requires_deep_reasoning": route_name == "deep",
        "requires_langflow": False,
        "router_backend": "agent_goal_registry" if profile else "native_goal_router",
    }
    if profile:
        route["response_profile"] = str(profile.get("response_profile") or intent)
        route["goal_model"] = {
            "goal_type": str(profile.get("goal_type") or intent),
            "intent": intent,
            "response_profile": route["response_profile"],
            "route": route_name,
            "source": "agent_goal_registry",
            "description": str(profile.get("description") or ""),
            "match_score": int(profile.get("_match_score") or 0),
        }
    if component_error:
        route["component_errors"] = [component_error]
    return apply_agent_route_overrides(req, route)


def route_boi_agent_request(req: BoiAgentChatRequest, employee_id: str) -> dict[str, Any]:
    if req.mode in {"fast", "deep"} or str(req.intent or "").strip():
        requested_intent = normalize_agent_intent(
            req.intent,
            fallback=deterministic_agent_intent(req.question, req.current_url),
        )
        requested_route = route_for_agent_intent(requested_intent)
        if req.mode == "fast" and requested_route not in {"manual_handoff", "approval_required"}:
            requested_route = "fast"
        elif req.mode == "deep":
            requested_route = "deep"
        route = {
            "route": requested_route,
            "confidence": 1.0,
            "intent": requested_intent,
            "reason": "client supplied explicit mode/intent",
            "requires_mutation": requested_route in {"manual_handoff", "approval_required"},
            "requires_deep_reasoning": requested_route == "deep",
            "requires_langflow": False,
            "router_backend": "request_hint",
        }
        route = apply_agent_route_overrides(req, route)
        if req.mode == "deep" and route.get("route") not in {"manual_handoff", "approval_required"}:
            route.update(
                {
                    "route": "deep",
                    "reason": f"{route.get('reason') or 'request hint'}; client requested deep mode",
                    "requires_deep_reasoning": True,
                    "requires_langflow": False,
                }
            )
        elif req.mode == "fast":
            route["reason"] = f"{route.get('reason') or 'request hint'}; client requested fast mode"
        return route
    try:
        route = call_boi_agent_router_llm(req, employee_id)
    except BoiAgentRouterUnavailable as exc:
        return deterministic_agent_route_for_request(
            req,
            reason="llm router unavailable; native goal router",
            component_error=agent_component_error(
                "router",
                "boi_agent_router_unavailable",
                str(exc),
                recoverable=True,
                user_visible=False,
            ),
        )
    route = apply_agent_route_overrides(req, route)
    if req.mode == "deep" and route.get("route") not in {"manual_handoff", "approval_required"}:
        route.update(
            {
                "route": "deep",
                "reason": f"{route.get('reason') or 'llm route'}; client requested deep mode",
                "requires_deep_reasoning": True,
                "requires_langflow": False,
            }
        )
    elif req.mode == "fast":
        route["reason"] = f"{route.get('reason') or 'llm route'}; client requested fast mode"
    return route


def text_excerpt(value: str, limit: int = 900) -> str:
    text = re.sub(r"\s+", " ", str(value or "")).strip()
    return text[: limit - 1] + "…" if len(text) > limit else text


def resolve_agent_page_context(current_url: str, employee_id: str) -> dict[str, Any]:
    parsed = urlsplit(str(current_url or ""))
    path = parsed.path or "/"
    query = parse_qs(parsed.query)
    context: dict[str, Any] = {"page_kind": "unknown", "resolved": False, "current_url": current_url}
    if path in {"", "/"}:
        return {
            **context,
            "page_kind": "library",
            "resolved": True,
            "title": "BoI Wiki",
            "description": "OKF folder hierarchy 기반으로 업무 단위 BoI, SOP, Event, Action 연결 후보를 함께 탐색합니다.",
            "body_excerpt": "BoI Wiki는 public, team, private 아래 자유 업무 단위 폴더를 만들고 업무 지식과 실행 연결을 함께 찾는 첫 화면입니다.",
            "url": app_url("/", employee_id),
        }
    if path == "/sops":
        return {
            **context,
            "page_kind": "sops",
            "resolved": True,
            "title": "SOP",
            "description": "SOP와 관련 실행 가이드를 검색하고 확인하는 화면입니다.",
            "body_excerpt": "SOP 화면은 업무 절차, 연결 Event, Action, Manual Handoff를 확인하는 탐색 화면입니다.",
            "url": app_url("/sops", employee_id),
        }
    if path == "/event-types":
        return {
            **context,
            "page_kind": "event_types",
            "resolved": True,
            "title": "Event Broker",
            "description": "Event Broker가 발행하고 SOP/Action과 연결되는 업무 이벤트 정의를 확인하는 화면입니다.",
            "body_excerpt": "Event Types 화면은 이벤트 정의, 연결 SOP, 권장 Action, 최근 Stream을 기준으로 업무 흐름을 찾는 탐색 화면입니다.",
            "url": app_url("/event-types", employee_id),
        }
    if path == "/actions":
        if (query.get("view") or [""])[0] == "history":
            payload = filter_action_logs_payload(
                employee_id=employee_id,
                q=(query.get("q") or [""])[0],
                status=(query.get("status") or [""])[0],
                connector_kind=(query.get("connector_kind") or [""])[0],
                event_type=(query.get("event_type") or [""])[0],
                action_key=(query.get("action_key") or [""])[0],
                trace_id=(query.get("trace_id") or [""])[0],
                request_id=(query.get("request_id") or [""])[0],
                from_time=(query.get("from_time") or query.get("from") or [""])[0],
                to_time=(query.get("to_time") or query.get("to") or [""])[0],
                time_preset=(query.get("time_preset") or [""])[0],
                limit=10,
                offset=0,
            )
            return {
                **context,
                "page_kind": "action_history",
                "resolved": True,
                "title": "Action 실행 이력",
                "description": "필터된 Action 실행 요청, 실패, 승인 필요, 수동 조치, 결과 로그를 확인하는 화면입니다.",
                "filters": payload.get("filters") or {},
                "summary": payload.get("summary") or {},
                "action_log_count": payload.get("total") or 0,
                "action_logs": [
                    {
                        "action_key": item.get("action_key"),
                        "status": item.get("status"),
                        "status_label": item.get("status_label"),
                        "connector_kind": item.get("connector_kind"),
                        "request_id": item.get("request_id"),
                        "event_type": item.get("event_type"),
                        "trace_id": item.get("trace_id"),
                        "result_summary": item.get("result_summary"),
                        "workflow_run_url": item.get("workflow_run_url"),
                        "raw_url": item.get("raw_url"),
                    }
                    for item in payload.get("items") or []
                ],
                "url": app_url("/actions", employee_id, view="history"),
            }
        return {
            **context,
            "page_kind": "actions",
            "resolved": True,
            "title": "Action",
            "description": "업무 흐름에서 재사용할 API, MCP, Webhook, Manual Action 명세를 확인하는 화면입니다.",
            "body_excerpt": "Action 화면은 Action 명세, connector, 실행 조건, 승인 필요 여부를 확인하는 카탈로그입니다.",
            "url": app_url("/actions", employee_id),
        }
    if path.startswith("/docs/"):
        boi_id = unquote(path.removeprefix("/docs/"))
        doc = find_doc_by_id(boi_id, employee_id)
        if not doc:
            return {**context, "page_kind": "doc", "boi_id": boi_id, "context_resolution": "ontology_search_only"}
        metadata = doc.get("metadata") or {}
        access = access_policy_for_doc(doc, employee_id)
        source_event = metadata.get("source_event") if isinstance(metadata.get("source_event"), dict) else {}
        can_use_context = access.can_use_in_agent_context
        workflow = metadata.get("workflow") if isinstance(metadata.get("workflow"), dict) else {}
        workflow_stages = workflow.get("stages") if isinstance(workflow.get("stages"), list) and can_use_context else []
        workflow_event_types: list[str] = []
        workflow_actions: list[str] = []
        workflow_manual_actions: list[str] = []
        workflow_stage_names: list[str] = []
        for stage in workflow_stages:
            if not isinstance(stage, dict):
                continue
            stage_name = str(stage.get("name") or stage.get("stage") or stage.get("id") or "").strip()
            if stage_name and stage_name not in workflow_stage_names:
                workflow_stage_names.append(stage_name)
            for event_type in stage.get("event_types") or ([stage.get("entry_event")] if stage.get("entry_event") else []):
                if event_type and str(event_type) not in workflow_event_types:
                    workflow_event_types.append(str(event_type))
            for action_key in stage.get("automated_actions") or []:
                if action_key and str(action_key) not in workflow_actions:
                    workflow_actions.append(str(action_key))
            for manual_key in stage.get("manual_actions") or []:
                if manual_key and str(manual_key) not in workflow_manual_actions:
                    workflow_manual_actions.append(str(manual_key))
        return {
            **context,
            "page_kind": "doc",
            "resolved": True,
            "title": metadata.get("title") or "",
            "description": metadata.get("description") or "" if can_use_context else "",
            "boi_id": metadata.get("boi_id") or boi_id,
            "type": metadata.get("type") or "",
            "visibility": metadata.get("visibility") or "",
            "status": metadata.get("status") or "",
            "event_type": metadata.get("event_type") or source_event.get("event_type") or "",
            "action_key": metadata.get("action_key") or "",
            "trace_id": source_event.get("trace") or "",
            "workflow_key": workflow.get("workflow_key") or "",
            "stage_count": len(workflow_stages),
            "workflow_stage_names": workflow_stage_names[:12],
            "workflow_event_types": workflow_event_types[:12],
            "workflow_actions": workflow_actions[:12],
            "workflow_manual_actions": workflow_manual_actions[:12],
            "workflow_action_count": len(workflow_actions),
            "workflow_manual_action_count": len(workflow_manual_actions),
            "body_excerpt": text_excerpt(str(doc.get("body") or "")) if can_use_context else "",
            "linked_items": lightweight_doc_link_items(doc, employee_id, limit=8) if can_use_context else [],
            "url": doc_url_for_ref(str(metadata.get("boi_id") or boi_id), employee_id) if access.can_cite else "",
            "access": access.to_dict(),
        }
    if path.startswith("/workflows/") and path.endswith("/status"):
        workflow_key = unquote(path.removeprefix("/workflows/").removesuffix("/status")).strip("/")
        trace_id = (query.get("trace_id") or [""])[0]
        if not workflow_key or not trace_id:
            return {**context, "page_kind": "workflow_status", "context_resolution": "ontology_search_only"}
        payload = workflow_status_payload(workflow_key, trace_id, employee_id, compact=True)
        manual_details = {
            str(item.get("action_key")): {
                **item,
                "title": item.get("title") or item.get("name_ko") or item.get("action_key"),
            }
            for item in payload.get("manual_action_details") or []
            if isinstance(item, dict) and item.get("action_key")
        }
        return {
            **context,
            "page_kind": "workflow_status",
            "resolved": True,
            "title": "Workflow Run Status",
            "workflow_key": workflow_key,
            "trace_id": trace_id,
            "sop_ref": payload.get("sop_ref") or "",
            "sop_url": payload.get("sop_url") or "",
            "event_count": len(payload.get("events") or []),
            "action_count": len(payload.get("actions") or []),
            "manual_handoff_count": len(payload.get("manual_handoffs") or []),
            "manual_handoffs": payload.get("manual_handoffs") or [],
            "expected_manual_actions": payload.get("expected_manual_actions") or [],
            "manual_action_details": manual_details,
            "approval_required_actions": payload.get("approval_required_actions") or [],
            "events": payload.get("events") or [],
            "actions": payload.get("actions") or [],
            "generated_docs": payload.get("generated_docs") or [],
            "generated_boi_count": len(payload.get("generated_docs") or []),
            "url": workflow_status_page_url_for_key(workflow_key, trace_id, employee_id),
        }
    if path == "/events" or path.startswith("/events"):
        event_type = (query.get("event_type") or [""])[0]
        trace_id = (query.get("trace_id") or [""])[0]
        event_id = (query.get("event_id") or [""])[0]
        rows = read_event_logs(limit=5, event_type=event_type or None, trace_id=trace_id or None, event_id=event_id or None)
        return {
            **context,
            "page_kind": "events",
            "resolved": True,
            "event_type": event_type,
            "trace_id": trace_id,
            "event_id": event_id,
            "event_count": len(rows),
            "events": [
                {
                    "event_id": row.get("event_id"),
                    "event_type": row.get("event_type"),
                    "trace_id": row.get("trace_id"),
                    "status": row.get("status"),
                }
                for row in rows
            ],
        }
    if path.startswith("/actions/raw/"):
        log_ref = unquote(path.removeprefix("/actions/raw/"))
        row = find_action_log_row_by_ref(log_ref, employee_id)
        if not row:
            return {**context, "page_kind": "action_raw", "log_ref": log_ref, "context_resolution": "ontology_search_only"}
        readable = action_raw_readable_markdown(row)
        result_value = row.get("result") if isinstance(row.get("result"), dict) else {}
        return {
            **context,
            "page_kind": "action_raw",
            "resolved": True,
            "log_ref": log_ref,
            "action_key": row.get("action_key") or "",
            "status": row.get("status") or result_value.get("status") or "",
            "request_id": row.get("request_id") or "",
            "trace_id": row.get("trace_id") or "",
            "event_id": row.get("event_id") or "",
            "doc_ref": row.get("doc_ref") or "",
            "readable_excerpt": text_excerpt(str(readable.get("markdown") or ""), 700) if readable.get("available") else "",
            "url": action_raw_page_url(log_ref, employee_id),
        }
    if path.startswith("/event-types/"):
        event_type = unquote(path.removeprefix("/event-types/"))
        event_def = event_type_map().get(event_type)
        if not event_def:
            return {**context, "page_kind": "event_type", "event_type": event_type, "context_resolution": "ontology_search_only"}
        return {
            **context,
            "page_kind": "event_type",
            "resolved": True,
            "event_type": event_type,
            "title": event_def.get("name_ko") or event_type,
            "description": event_def.get("description") or "",
            "workflow_stage": event_def.get("workflow_stage") or "",
            "sop_ref": event_def.get("sop_ref") or "",
            "recommended_actions": event_def.get("recommended_actions") or [],
            "url": event_type_url(event_type, employee_id),
        }
    return {**context, "context_resolution": "ontology_search_only"}


def link_items_from_agent_context(page_context: dict[str, Any], employee_id: str) -> list[dict[str, str]]:
    links: list[dict[str, str]] = []
    if page_context.get("url"):
        links.append({"label": str(page_context.get("title") or page_context.get("page_kind") or "현재 화면"), "url": str(page_context["url"]), "kind": "current_page"})
    if page_context.get("boi_id"):
        links.append({"label": str(page_context["boi_id"]), "url": doc_url_for_ref(str(page_context["boi_id"]), employee_id), "kind": "boi"})
    if page_context.get("sop_ref"):
        links.append({"label": str(page_context["sop_ref"]), "url": doc_url_for_ref(str(page_context["sop_ref"]), employee_id), "kind": "sop"})
    return [item for item in links if item.get("url")]


def page_context_ontology_seed(page_context: dict[str, Any], employee_id: str, query: str) -> dict[str, Any]:
    """Return a compact ontology seed for page-first Agent requests.

    Diagram, workflow explanation, gap check, page QA, and summarization are
    anchored to the current page. Running a broad ontology search before the
    page tool loop adds latency and can dilute the evidence. Search requests
    still use the full ontology retriever; page-first requests get a typed seed
    that keeps the Agent contract consistent for Web, API, and MCP clients.
    """
    title = str(page_context.get("title") or page_context.get("page_kind") or "현재 화면")
    boi_id = str(page_context.get("boi_id") or page_context.get("sop_ref") or "")
    current_item: dict[str, Any] = {
        "kind": "boi",
        "score": 100,
        "match_reason": "current_page",
        "boi_id": boi_id,
        "title": title,
        "description": str(page_context.get("description") or ""),
        "type": str(page_context.get("type") or ""),
        "url": str(page_context.get("url") or (doc_url_for_ref(boi_id, employee_id) if boi_id else "")),
        "access": page_context.get("access") or {"can_cite": True, "can_use_in_agent_context": True},
    }
    current_items = [current_item] if boi_id or current_item.get("url") else []
    return {
        "ok": True,
        "query": query,
        "scope": "page_context",
        "employee_id": employee_id,
        "current_url": str(page_context.get("url") or ""),
        "view": "compact",
        "query_expansion": [query] if query else [],
        "used_dictionary_terms": [],
        "knowledge_panel": {"interpreted_as": [title] if title else [], "top_sop": current_items[:1]},
        "groups": {"current_page": current_items},
        "best_matches": current_items,
        "graph_paths": [],
        "citations": [
            {"label": title, "ref": boi_id, "url": str(current_item.get("url") or ""), "kind": "current_page"}
        ] if current_item.get("url") else [],
        "document_rank_refs": [boi_id] if boi_id else [],
    }


def agent_page_context_has_business_anchor(page_context: dict[str, Any]) -> bool:
    if not page_context.get("resolved"):
        return False
    for key in ("boi_id", "sop_ref", "trace_id", "event_type", "action_key", "log_ref"):
        if page_context.get(key):
            return True
    return str(page_context.get("page_kind") or "") in {"doc", "workflow_status", "action_raw", "event_type"}


AGENT_EVENT_TYPE_RE = re.compile(r"\b([a-z][a-z0-9_]*(?:\.[a-z][a-z0-9_]*)+\.v\d+)\b")


def event_type_from_agent_context(req: BoiAgentChatRequest, page_context: dict[str, Any]) -> str:
    if isinstance(page_context, dict) and page_context.get("event_type"):
        return str(page_context["event_type"])
    haystack_parts = [req.question, req.current_url, req.selected_text]
    if isinstance(req.page_context, dict):
        haystack_parts.append(json.dumps(req.page_context, ensure_ascii=False))
    haystack = "\n".join(str(part or "") for part in haystack_parts)
    match = AGENT_EVENT_TYPE_RE.search(haystack)
    if match:
        return match.group(1)
    known_events = set(event_type_map().keys())
    for definition in load_workflow_definition_catalog():
        known_events.update(workflow_definition_event_types(definition))
    for event_type in sorted(known_events, key=len, reverse=True):
        if event_type and event_type in haystack:
            return event_type
    return ""


def workflow_definition_for_event_type(event_type: str) -> dict[str, Any] | None:
    if not event_type:
        return None
    for definition in load_workflow_definition_catalog():
        if event_type in workflow_definition_event_types(definition):
            return definition
    return None


def workflow_definition_event_contract(definition: dict[str, Any], event_type: str) -> dict[str, Any]:
    for contract in definition.get("event_contracts") or []:
        if isinstance(contract, dict) and str(contract.get("event_type") or "") == event_type:
            return dict(contract)
    return {}


def agent_event_context(req: BoiAgentChatRequest, page_context: dict[str, Any]) -> dict[str, Any]:
    event_type = event_type_from_agent_context(req, page_context)
    if not event_type:
        return {}
    event = get_event_type(event_type) or {"event_type": event_type}
    definition = workflow_definition_for_event_type(event_type) or {}
    contract = workflow_definition_event_contract(definition, event_type)
    return {
        "event_type": event_type,
        "name_ko": event.get("name_ko") or event_type,
        "description": event.get("description") or "",
        "topic": event.get("topic") or "",
        "workflow_key": event.get("workflow_key") or definition.get("workflow_key") or "",
        "sop_ref": event.get("sop_ref") or (normalize_registry_list(definition.get("sop_refs")) or [""])[0],
        "sop_stage_id": event.get("sop_stage_id") or contract.get("sop_stage_id") or "",
        "recommended_actions": normalize_registry_list(event.get("recommended_actions") or definition.get("action_refs")),
        "recommended_manual_actions": normalize_registry_list(event.get("recommended_manual_actions")),
        "payload_schema": contract.get("payload_schema") or event.get("payload_schema") or {},
        "required_payload_fields": normalize_registry_list(contract.get("required_payload_fields") or event.get("required_payload_fields")),
        "trace_policy": contract.get("trace_policy") or event.get("trace_policy") or "",
        "idempotency_key_fields": normalize_registry_list(contract.get("idempotency_key_fields") or event.get("idempotency_key_fields")),
        "actor_policy": contract.get("actor_policy") or event.get("actor_policy") or "",
        "visibility_policy": contract.get("visibility_policy") or event.get("visibility_policy") or "",
    }


def agent_workflow_definition_context(event_context: dict[str, Any]) -> dict[str, Any]:
    event_type = str((event_context or {}).get("event_type") or "")
    definition = workflow_definition_for_event_type(event_type)
    if not definition:
        return {}
    summary = workflow_definition_summary(definition)
    return {
        **summary,
        "workflow_key": definition.get("workflow_key") or event_context.get("workflow_key") or "",
        "event_contracts": [
            {
                "event_type": contract.get("event_type"),
                "payload_schema": contract.get("payload_schema") or {},
                "required_payload_fields": normalize_registry_list(contract.get("required_payload_fields")),
                "trace_policy": contract.get("trace_policy") or "",
                "idempotency_key_fields": normalize_registry_list(contract.get("idempotency_key_fields")),
                "actor_policy": contract.get("actor_policy") or "",
                "visibility_policy": contract.get("visibility_policy") or "",
                "sop_stage_id": contract.get("sop_stage_id") or "",
            }
            for contract in definition.get("event_contracts") or []
            if isinstance(contract, dict)
        ],
        "required_evidence": definition.get("required_evidence") or [],
        "supported_artifacts": normalize_registry_list(definition.get("supported_artifacts")),
        "routing_policy": definition.get("routing_policy") or {},
        "rbac_policy": definition.get("rbac_policy") or {},
        "risk_policy": definition.get("risk_policy") or {},
    }


def agent_context_pack(req: BoiAgentChatRequest, employee_id: str, *, search_limit: int = 5) -> dict[str, Any]:
    page_context = resolve_agent_page_context(req.current_url, employee_id)
    event_context = agent_event_context(req, page_context)
    workflow_definition_context = agent_workflow_definition_context(event_context)
    ontology_seed: dict[str, Any] = {}
    intent = normalize_agent_intent(str(req.intent or ""), fallback=deterministic_agent_intent(req.question, req.current_url))
    page_first_intents = {"diagram", "workflow_explain", "gap_check", "page_qa", "summarize"}
    has_page_anchor = agent_page_context_has_business_anchor(page_context)
    should_seed_search = bool(req.question.strip()) and not (has_page_anchor and intent in page_first_intents)
    if should_seed_search:
        ontology_seed = ontology_search_payload(req.question, employee_id, scope="all", limit=search_limit, current_url=req.current_url, view="compact")
    elif has_page_anchor and intent in page_first_intents:
        ontology_seed = page_context_ontology_seed(page_context, employee_id, req.question)
    return {
        "question": req.question,
        "selected_text_excerpt": text_excerpt(req.selected_text, 700) if req.selected_text else "",
        "current_url": req.current_url,
        "page_context": page_context,
        "event_context": event_context,
        "workflow_definition_context": workflow_definition_context,
        "ontology_search_seed": ontology_seed,
        "agent_goal_profiles": load_agent_goal_profiles(),
        "agent_response_profiles": load_agent_response_profiles(),
        "access_summary": page_context.get("access") or {"can_read": True, "can_use_in_agent_context": True},
    }


def native_agent_doc_tool(ref: str, employee_id: str) -> dict[str, Any] | None:
    doc = find_doc_by_id(ref, employee_id)
    if not doc:
        return None
    metadata = doc.get("metadata") or {}
    access = access_policy_for_doc(doc, employee_id)
    stable_ref = stable_doc_ref(doc)
    visible_metadata = metadata
    if not access.can_use_in_agent_context:
        visible_metadata = {
            "boi_id": metadata.get("boi_id"),
            "type": metadata.get("type"),
            "title": metadata.get("title"),
            "visibility": metadata.get("visibility"),
            "classification": access.classification,
            "status": metadata.get("status"),
        }
    return {
        "ok": True,
        "boi_id": metadata.get("boi_id") or stable_ref,
        "uri": doc.get("uri") or "",
        "title": metadata.get("title") or stable_ref,
        "description": metadata.get("description") or "",
        "metadata": visible_metadata,
        "body_excerpt": text_excerpt(str(doc.get("body") or ""), 1800) if access.can_use_in_agent_context else "",
        "url": doc_url_for_ref(stable_ref, employee_id) if access.can_cite else "",
        "access": access.to_dict(),
        "redacted_count": len(access.redactions),
    }


def native_agent_action_spec_tool(action_key: str, employee_id: str) -> dict[str, Any] | None:
    for action in load_action_catalog():
        if str(action.get("action_key") or "") != action_key:
            continue
        doc_ref = str(action.get("doc_ref") or "")
        return {
            "ok": True,
            "action_key": action_key,
            "item": action,
            "doc_ref": doc_ref,
            "doc": native_agent_doc_tool(doc_ref, employee_id) if doc_ref else None,
            "url": action_doc_url(action, employee_id),
        }
    return None


def native_agent_trace_context_tool(trace_id: str, employee_id: str) -> dict[str, Any]:
    event_rows = read_event_logs(limit=100, trace_id=trace_id) if trace_id else []
    action_rows = [
        row
        for row in cached_action_log_rows()
        if str(row.get("trace_id") or "") == trace_id
        if action_log_visible_to_employee(row, employee_id)
    ] if trace_id else []
    return {
        "ok": True,
        "trace_id": trace_id,
        "events": [
            {
                "event_id": row.get("event_id"),
                "event_type": row.get("event_type"),
                "status": row.get("status"),
                "url": events_url(employee_id, trace_id=trace_id, event_id=str(row.get("event_id") or "")),
            }
            for row in event_rows[:20]
        ],
        "actions": [
            {
                "request_id": row.get("request_id"),
                "action_key": row.get("action_key"),
                "status": row.get("status") or ((row.get("result") or {}).get("status") if isinstance(row.get("result"), dict) else ""),
                "raw_url": action_raw_page_url(str(row.get("_log_ref") or ""), employee_id) if row.get("_log_ref") else "",
            }
            for row in action_rows[:30]
        ],
    }


def native_agent_workflow_status_tool(workflow_key: str, trace_id: str, employee_id: str) -> dict[str, Any] | None:
    if not workflow_key or not trace_id:
        return None
    return workflow_status_payload(workflow_key, trace_id, employee_id, compact=True)


def native_agent_llm_json(employee_id: str, task: str, payload: dict[str, Any]) -> dict[str, Any] | None:
    """LLM helper used inside the native graph.

    The native agent owns routing. This adapter reuses the configured
    OpenAI-compatible router endpoint without making the API entrypoint call a
    separate pre-router first.
    """
    if task == "compose":
        return call_boi_agent_composer_llm(payload, employee_id)
    if task != "route":
        return None
    request_payload = payload.get("request") if isinstance(payload, dict) else {}
    if not isinstance(request_payload, dict):
        return None
    try:
        req = BoiAgentChatRequest(
            question=str(request_payload.get("question") or ""),
            mode=str(request_payload.get("mode") or "auto"),
            intent=str(request_payload.get("intent") or ""),
            current_url=str(request_payload.get("current_url") or ""),
            selected_text=str(request_payload.get("selected_text") or ""),
            page_context=request_payload.get("page_context") if isinstance(request_payload.get("page_context"), dict) else {},
            conversation=request_payload.get("conversation") if isinstance(request_payload.get("conversation"), list) else [],
            save_memory=bool(request_payload.get("save_memory", True)),
        )
        return call_boi_agent_router_llm(req, employee_id)
    except (BoiAgentRouterUnavailable, ValueError, TypeError):
        return None


def native_agent_memory_tool(query: str, employee_id: str, limit: int = 5) -> dict[str, Any]:
    items = agent_memory_items(employee_id, q=query, limit=limit)
    return {"ok": True, "count": len(items), "items": items}


def native_agent_tools(employee_id: str, current_url: str = "") -> NativeAgentTools:
    return NativeAgentTools(
        ontology_search=lambda query, scope="all", limit=8: ontology_search_payload(query, employee_id, scope=scope, limit=limit, current_url=current_url, view="compact"),
        boi_get=lambda ref: native_agent_doc_tool(ref, employee_id),
        event_type_lookup=lambda event_type: event_type_map().get(event_type),
        action_spec_lookup=lambda action_key: native_agent_action_spec_tool(action_key, employee_id),
        workflow_status=lambda workflow_key, trace_id: native_agent_workflow_status_tool(workflow_key, trace_id, employee_id),
        trace_context_lookup=lambda trace_id: native_agent_trace_context_tool(trace_id, employee_id),
        dictionary_resolve=lambda query: {"ok": True, "view": "compact", **resolve_dictionary_query(query, employee_id, scope="all", limit=DICTIONARY_RESOLVE_DEFAULT_LIMIT, view="compact")},
        memory_recall=lambda query, limit=5: native_agent_memory_tool(query, employee_id, limit=limit),
        agent_inbox=lambda limit=10: agent_inbox_payload(employee_id, status="open", limit=limit, include_context="compact"),
        llm_json=lambda task, payload: native_agent_llm_json(employee_id, task, payload),
    )


def call_native_boi_agent(
    req: BoiAgentChatRequest,
    employee_id: str,
    route: dict[str, Any],
    started_at: float,
    progress_callback: Callable[[dict[str, Any]], None] | None = None,
) -> dict[str, Any]:
    context_pack = agent_context_pack(req, employee_id, search_limit=8)
    runtime = NativeBoiAgent(
        native_agent_tools(employee_id, req.current_url),
        NativeAgentConfig(
            max_tool_loops=BOI_AGENT_NATIVE_MAX_TOOL_LOOPS,
            tool_timeout_seconds=BOI_AGENT_NATIVE_TOOL_TIMEOUT_SECONDS,
            build_revision=BOI_BUILD_REVISION,
            llm_enabled=BOI_AGENT_ROUTER_LLM_ENABLED and BOI_AGENT_ROUTER_MODE == "llm_first",
            require_langgraph=BOI_AGENT_LANGGRAPH_REQUIRED,
            composer_enabled=BOI_AGENT_COMPOSER_LLM_ENABLED,
            composer_required=BOI_AGENT_COMPOSER_REQUIRED,
            progress_callback=progress_callback,
        ),
    )
    response = runtime.run(
        {
            "question": req.question,
            "mode": req.mode,
            "intent": req.intent,
            "current_url": req.current_url,
            "selected_text": req.selected_text,
            "page_context": req.page_context,
            "conversation": req.conversation[-12:],
            "save_memory": req.save_memory,
        },
        route,
        context_pack,
    )
    latency_ms = int((time.perf_counter() - started_at) * 1000)
    router_confidence = response.get("router_confidence")
    final_reference_redactions = sanitize_agent_final_references(response, employee_id)
    response.update(
        {
            "employee_id": employee_id,
            "latency_ms": latency_ms,
            "router_backend": response.get("router_backend") or route.get("router_backend"),
            "router_confidence": router_confidence if router_confidence is not None else route.get("confidence"),
            "access_summary": context_pack.get("access_summary") or {},
            "guardrails_applied": sorted(set([*(response.get("guardrails_applied") or []), "acl_policy", "classification", "mutation_confirmation", "agent_final_reference_acl"])),
            "redacted_count": max(int(response.get("redacted_count") or 0), count_agent_redactions(response), len((context_pack.get("access_summary") or {}).get("redactions") or [])) + final_reference_redactions,
        }
    )
    response.setdefault("context_summary", {})["latency_ms"] = latency_ms
    return response


AGENT_ALLOWED_APP_LINK_PREFIXES = (
    "docs",
    "events",
    "workflows",
    "actions",
    "event-types",
    "api",
    "permissions",
    "sops",
    "source",
)
AGENT_MARKDOWN_LINK_RE = re.compile(r"(?<!!)\[(?P<label>[^\]]+)\]\((?P<href>[^)\s]+)(?:\s+\"[^\"]*\")?\)")
AGENT_HOSTLESS_APP_URL_RE = re.compile(
    r"\bhttps?:/{3,}(?P<rest>(?:docs|events|workflows|actions|event-types|api|permissions|sops|source)(?:[^\s<)]*)?)",
    flags=re.IGNORECASE,
)
AGENT_CONTROL_CHARS_RE = re.compile(r"[\x00-\x08\x0b\x0c\x0e-\x1f\x7f]")


def strip_agent_control_chars(value: str) -> str:
    return AGENT_CONTROL_CHARS_RE.sub("", str(value or ""))


def normalize_agent_href(value: Any) -> str:
    text = strip_agent_control_chars(str(value or "")).strip()
    if not text:
        return ""
    match = re.match(r"^https?:/{3,}(?P<rest>.*)$", text, flags=re.IGNORECASE)
    if not match:
        return text
    rest = str(match.group("rest") or "").lstrip("/")
    if rest.startswith(AGENT_ALLOWED_APP_LINK_PREFIXES):
        return "/" + rest
    return text


def normalize_agent_text_references(value: str) -> str:
    text = strip_agent_control_chars(str(value or ""))

    def replace_markdown_link(match: re.Match[str]) -> str:
        return f"[{match.group('label')}]({normalize_agent_href(match.group('href'))})"

    text = AGENT_MARKDOWN_LINK_RE.sub(replace_markdown_link, text)
    return AGENT_HOSTLESS_APP_URL_RE.sub(lambda match: "/" + str(match.group("rest") or "").lstrip("/"), text)


def agent_doc_ref_from_reference(value: Any) -> str:
    text = normalize_agent_href(value)
    if not text:
        return ""
    try:
        parsed = urlsplit(text)
    except Exception:
        parsed = None
    path = unquote(parsed.path if parsed else text)
    if path.startswith("/docs/"):
        return path.removeprefix("/docs/").strip()
    if text.startswith("boi:"):
        return text.split("#", 1)[0].split("?", 1)[0].strip()
    normalized_path = path.split("#", 1)[0].split("?", 1)[0].lstrip("/")
    if normalized_path.startswith(("public/", "team/", "private/")) and (
        normalized_path.endswith(".md") or find_doc_path_by_ref(normalized_path)
    ):
        return normalized_path
    return ""


def agent_reference_allowed(value: Any, employee_id: str) -> bool:
    ref = agent_doc_ref_from_reference(value)
    if not ref:
        return True
    doc = find_doc_by_id(ref, employee_id, include_inaccessible=True)
    if doc:
        access = access_policy_for_doc(doc, employee_id)
        return bool(access.can_read and access.can_cite)
    if ref.startswith("boi:private:"):
        parts = ref.split(":")
        return len(parts) >= 3 and parts[2] == employee_id
    return True


def redact_inaccessible_agent_text(value: str, employee_id: str) -> tuple[str, int]:
    redacted_count = 0

    def replace_markdown_link(match: re.Match[str]) -> str:
        nonlocal redacted_count
        label = match.group("label")
        href = match.group("href")
        if agent_reference_allowed(href, employee_id):
            return match.group(0)
        redacted_count += 1
        return f"{label} (권한 제한으로 숨김)"

    text = re.sub(
        r"\[(?P<label>[^\]]+)\]\((?P<href>[^)]+)\)",
        replace_markdown_link,
        str(value or ""),
    )

    def replace_private_ref(match: re.Match[str]) -> str:
        nonlocal redacted_count
        ref = match.group(0)
        if agent_reference_allowed(ref, employee_id):
            return ref
        redacted_count += 1
        return "[권한 제한]"

    text = re.sub(r"boi:private:[0-9]{6,8}:[A-Za-z0-9:_-]+", replace_private_ref, text)
    return text, redacted_count


def sanitize_agent_reference_value(value: Any, employee_id: str) -> tuple[Any, int]:
    if isinstance(value, dict):
        redacted_count = 0
        normalized_value = dict(value)
        for key in ("url", "href"):
            if key in normalized_value:
                normalized_value[key] = normalize_agent_href(normalized_value.get(key))
        for key in ("url", "href", "ref", "boi_id", "doc_ref"):
            if key in normalized_value and not agent_reference_allowed(normalized_value.get(key), employee_id):
                return None, 1
        sanitized: dict[str, Any] = {}
        for key, item in normalized_value.items():
            sanitized_item, item_redactions = sanitize_agent_reference_value(item, employee_id)
            redacted_count += item_redactions
            if sanitized_item is not None:
                sanitized[key] = sanitized_item
        return sanitized, redacted_count
    if isinstance(value, list):
        sanitized_items = []
        redacted_count = 0
        for item in value:
            sanitized_item, item_redactions = sanitize_agent_reference_value(item, employee_id)
            redacted_count += item_redactions
            if sanitized_item is not None:
                sanitized_items.append(sanitized_item)
        return sanitized_items, redacted_count
    if isinstance(value, str):
        return redact_inaccessible_agent_text(normalize_agent_text_references(value), employee_id)
    return value, 0


def sanitize_agent_final_references(response: dict[str, Any], employee_id: str) -> int:
    redacted_count = 0
    for key in (
        "answer_markdown",
        "display_markdown",
        "links",
        "citations",
        "suggested_questions",
        "artifacts",
        "execution_cards",
        "tool_trace",
        "status_updates",
        "status_events",
        "context_summary",
        "goal_model",
        "response_profile",
        "component_errors",
    ):
        sanitized, count = sanitize_agent_reference_value(response.get(key), employee_id)
        redacted_count += count
        if sanitized is not None:
            response[key] = sanitized
        elif key in {"links", "citations", "artifacts", "execution_cards", "suggested_questions", "tool_trace", "status_updates", "status_events"}:
            response[key] = []
        else:
            response[key] = ""
    return redacted_count


def count_agent_redactions(response: dict[str, Any]) -> int:
    count = 0
    for item in response.get("tool_trace") or []:
        result = item.get("result") if isinstance(item, dict) else {}
        if isinstance(result, dict):
            count += int(result.get("redacted_count") or 0)
    access = response.get("access_summary") if isinstance(response.get("access_summary"), dict) else {}
    count += len(access.get("redactions") or []) if isinstance(access, dict) else 0
    return count


def mermaid_artifact_from_markdown(answer_markdown: str) -> dict[str, Any] | None:
    match = re.search(r"```mermaid\s*\n(?P<body>.*?)```", str(answer_markdown or ""), flags=re.IGNORECASE | re.DOTALL)
    if not match:
        return None
    source = match.group("body").strip()
    return (
        normalize_agent_artifact_presentation({"type": "mermaid", "title": "Mermaid diagram", "source": source})
        if source
        else None
    )


def default_agent_artifact_presentation(artifact_type: str) -> tuple[str, str, int, str, bool]:
    if artifact_type in {"mermaid", "gap_table", "workflow_summary", "manual_handoff_summary", "action_requirements", "task_cards", "confirmation_required", "image"}:
        return ("primary", "inline", 10, "요청에 맞춰 바로 확인할 산출물", True)
    return ("supporting", "collapsed", 60, "답변을 보강하는 참고 자료", False)


def normalize_agent_artifact_presentation(artifact: dict[str, Any]) -> dict[str, Any]:
    artifact_type = str(artifact.get("type") or "")
    role_default, mode_default, priority_default, reason_default, requested_default = default_agent_artifact_presentation(artifact_type)
    role = str(artifact.get("role") or role_default)
    if role not in BOI_AGENT_ARTIFACT_ROLES:
        role = role_default
    display_mode = str(artifact.get("display_mode") or mode_default)
    if display_mode not in BOI_AGENT_ARTIFACT_DISPLAY_MODES:
        display_mode = mode_default
    normalized = dict(artifact)
    normalized["role"] = role
    normalized["display_mode"] = display_mode
    try:
        normalized["priority"] = int(normalized.get("priority", priority_default))
    except (TypeError, ValueError):
        normalized["priority"] = priority_default
    normalized["reason"] = str(normalized.get("reason") or reason_default)
    normalized["user_requested"] = bool(normalized.get("user_requested", requested_default))
    normalized["default_collapsed"] = bool(
        normalized.get("default_collapsed", role in {"evidence", "diagnostic"} or display_mode in {"collapsed", "viewer_only", "hidden_diagnostic"})
    )
    return normalized


def normalize_agent_artifacts(value: Any, answer_markdown: str = "") -> list[dict[str, Any]]:
    artifacts: list[dict[str, Any]] = []
    if isinstance(value, dict):
        for artifact_type, artifact_value in value.items():
            if artifact_type == "mermaid" and isinstance(artifact_value, str):
                artifacts.append({"type": "mermaid", "title": "Mermaid diagram", "source": artifact_value.strip()})
            elif artifact_type in {"gap_table", "workflow_summary", "manual_handoff_summary", "action_requirements", "task_cards"}:
                artifacts.append({"type": artifact_type, "data": artifact_value})
    elif isinstance(value, list):
        for item in value:
            if isinstance(item, dict) and item.get("type"):
                artifacts.append(item)
    mermaid = mermaid_artifact_from_markdown(answer_markdown)
    if mermaid and not any(item.get("type") == "mermaid" and item.get("source") == mermaid["source"] for item in artifacts):
        artifacts.append(mermaid)
    return [normalize_agent_artifact_presentation(artifact) for artifact in artifacts if artifact.get("type")]


def execution_cards_from_artifacts(artifacts: list[dict[str, Any]]) -> list[dict[str, Any]]:
    cards: list[dict[str, Any]] = []
    for artifact in artifacts:
        if not isinstance(artifact, dict) or artifact.get("type") != "confirmation_required":
            continue
        data = artifact.get("data") if isinstance(artifact.get("data"), dict) else {}
        operation = str(data.get("operation") or data.get("type") or "confirmation_required")
        title = str(data.get("title") or artifact.get("title") or "확인 필요")
        message = str(data.get("message") or "")
        primary_label = str(data.get("primary_label") or "확인 후 실행")
        cards.append(
            {
                "contract_version": BOI_AGENT_RESPONSE_CONTRACT_VERSION,
                "type": operation,
                "operation": operation,
                "title": title,
                "message": message,
                "primary_label": primary_label,
                "payload": data.get("payload") or {},
                "requires_confirmation": True,
                "user_confirmed_required": True,
                "approve_url": "/api/agents/boi-wiki/approve",
                "display": {
                    "title": title,
                    "status_label": "확인 필요",
                    "why_it_matters": message or "이 요청은 BoI Wiki 상태를 변경할 수 있어 실행 전 확인이 필요합니다.",
                    "next_action": primary_label,
                    "risk_label": "명시 확인 후 실행",
                },
                "technical_details": {
                    "route": data.get("route"),
                    "intent": data.get("intent"),
                    "operation": operation,
                },
                "route": data.get("route"),
                "intent": data.get("intent"),
            }
        )
    return cards


def agent_operation_required_role(operation: str) -> str:
    normalized = str(operation or "").strip()
    if normalized in {"event_publish", "publish_event", "workflow_start", "start_workflow", "manual_handoff_complete", "manual_complete"}:
        return "boi.workflow_runner"
    if normalized in {"action_invoke", "invoke_action"}:
        return "boi.action_invoker"
    if normalized in {"event_type_draft", "create_event_type_draft"}:
        return "boi.editor"
    if normalized in {"source_apply", "doc_body_apply"}:
        return "boi.editor"
    if normalized in {"event_type_draft_apply", "apply_event_type_draft", "promotion_submit", "submit_promotion"}:
        return "boi.promoter"
    return ""


def agent_operation_permission_decision(employee_id: str, operation: str) -> dict[str, Any]:
    required_role = agent_operation_required_role(operation)
    if not required_role:
        return {"allowed": True, "reason": "no_role_required", "role": "", "scope": "agent_approve", "resource": operation}
    return role_binding_decision(employee_id, required_role, scope="agent_approve", resource=operation)


def require_agent_operation_permission(employee_id: str, operation: str) -> dict[str, Any]:
    permission = agent_operation_permission_decision(employee_id, operation)
    if permission.get("allowed"):
        return permission
    raise HTTPException(
        status_code=403,
        detail={
            "message": "Agent approval requires an allowed RBAC decision",
            "operation": operation,
            "required_role": agent_operation_required_role(operation),
            "permission": permission,
        },
    )


def normalize_agent_execution_cards(value: Any, employee_id: str) -> list[dict[str, Any]]:
    if not isinstance(value, list):
        return []
    cards: list[dict[str, Any]] = []
    for item in value:
        if not isinstance(item, dict):
            continue
        operation = str(item.get("operation") or item.get("type") or "confirmation_required").strip() or "confirmation_required"
        title = str(item.get("title") or operation)
        message = str(item.get("message") or "")
        primary_label = str(item.get("primary_label") or "확인 후 실행")
        display = item.get("display") if isinstance(item.get("display"), dict) else {}
        technical_details = item.get("technical_details") if isinstance(item.get("technical_details"), dict) else {}
        required_role = str(item.get("required_role") or agent_operation_required_role(operation))
        permission = item.get("permission") if isinstance(item.get("permission"), dict) else agent_operation_permission_decision(employee_id, operation)
        allowed = bool(permission.get("allowed", True))
        status_label = "권한 필요" if not allowed else str(display.get("status_label") or "확인 필요")
        risk_label = (
            f"권한 필요: {required_role or 'unknown'}"
            if not allowed
            else str(display.get("risk_label") or "명시 확인 후 실행")
        )
        normalized = {
            **item,
            "contract_version": BOI_AGENT_RESPONSE_CONTRACT_VERSION,
            "type": str(item.get("type") or operation),
            "operation": operation,
            "title": title,
            "message": message,
            "primary_label": primary_label,
            "payload": item.get("payload") if isinstance(item.get("payload"), dict) else {},
            "required_role": required_role,
            "permission": permission,
            "requires_confirmation": bool(item.get("requires_confirmation", True)),
            "user_confirmed_required": bool(item.get("user_confirmed_required", True)),
            "approve_url": str(item.get("approve_url") or "/api/agents/boi-wiki/approve"),
            "display": {
                "title": str(display.get("title") or title),
                "status_label": status_label,
                "why_it_matters": str(
                    display.get("why_it_matters")
                    or message
                    or "이 요청은 BoI Wiki 상태를 변경할 수 있어 실행 전 확인이 필요합니다."
                ),
                "next_action": str(display.get("next_action") or primary_label),
                "risk_label": risk_label,
                **{k: v for k, v in display.items() if k not in {"title", "status_label", "why_it_matters", "next_action", "risk_label"}},
            },
            "technical_details": {
                "operation": operation,
                "required_role": required_role,
                **technical_details,
            },
        }
        cards.append(normalized)
    return cards


def normalize_agent_mermaid_source(value: str) -> str:
    return re.sub(r"\s+", " ", str(value or "").strip())


def markdown_without_duplicate_mermaid_artifacts(answer_markdown: str, artifacts: list[dict[str, Any]]) -> str:
    """Return display Markdown with Mermaid fences removed when artifacts render them.

    Agent answers can include Mermaid both in answer_markdown and in structured
    artifacts. The Pet UI renders artifacts separately, so server-rendered
    answer_html should omit Mermaid fences whenever Mermaid artifacts exist.
    The original answer_markdown API field still preserves source transparency.
    """
    mermaid_sources = {
        normalize_agent_mermaid_source(str(artifact.get("source") or ""))
        for artifact in artifacts
        if isinstance(artifact, dict) and artifact.get("type") == "mermaid" and artifact.get("source")
    }
    if not mermaid_sources:
        return str(answer_markdown or "")

    def replace(match: re.Match[str]) -> str:
        return ""

    return re.sub(
        r"```[^\S\r\n]*mermaid[^\S\r\n]*(?:\r?\n)(?P<body>.*?)(?:\r?\n)?```",
        replace,
        str(answer_markdown or ""),
        flags=re.IGNORECASE | re.DOTALL,
    ).strip()


def enrich_agent_answer_html(response: dict[str, Any], employee_id: str) -> dict[str, Any]:
    response.setdefault("agent_contract_version", BOI_AGENT_RESPONSE_CONTRACT_VERSION)
    response.setdefault("answer_markdown", "")
    response.setdefault("links", [])
    response.setdefault("citations", [])
    response.setdefault("suggested_questions", [])
    response.setdefault("suggested_questions_source", "suggestions_endpoint_required")
    response.setdefault("evidence_ledger", [])
    response.setdefault("affordances", [])
    response.setdefault("answer_quality", {})
    response.setdefault("goal_model", {})
    response.setdefault("response_profile", str(response.get("intent") or (response.get("context_summary") or {}).get("intent") or "qa"))
    response.setdefault("component_errors", [])
    response.setdefault("diagnostics", list(response.get("component_errors") or []))
    response.setdefault("goal_hypothesis", response.get("goal_model") or {})
    response.setdefault("tool_trace", [])
    if not isinstance(response.get("status_updates"), list) and isinstance(response.get("status_events"), list):
        response["status_updates"] = response["status_events"]
    response.setdefault("status_updates", [])
    response["status_events"] = list(response["status_updates"])
    response.setdefault("coverage_report", {})
    response.setdefault("context_summary", {})
    response.setdefault("access_summary", {})
    response.setdefault("guardrails_applied", [])
    response.setdefault("redacted_count", 0)
    answer_markdown = str(response.get("answer_markdown") or "")
    artifacts = normalize_agent_artifacts(response.get("artifacts"), answer_markdown)
    response["artifacts"] = artifacts
    if not isinstance(response.get("execution_cards"), list) or not response.get("execution_cards"):
        cards = execution_cards_from_artifacts(artifacts)
        if cards:
            response["execution_cards"] = cards
    response.setdefault("execution_cards", [])
    response["execution_cards"] = normalize_agent_execution_cards(response.get("execution_cards"), employee_id)
    final_redactions = sanitize_agent_final_references(response, employee_id)
    response["redacted_count"] = int(response.get("redacted_count") or 0) + final_redactions
    answer_markdown = str(response.get("answer_markdown") or "")
    artifacts = normalize_agent_artifacts(response.get("artifacts"), answer_markdown)
    response["artifacts"] = artifacts
    response["execution_cards"] = normalize_agent_execution_cards(response.get("execution_cards"), employee_id)
    display_markdown = markdown_without_duplicate_mermaid_artifacts(answer_markdown, artifacts)
    response["display_markdown"] = display_markdown
    response["answer_html"] = (
        str(render_markdown(display_markdown, employee_id=employee_id))
        if display_markdown.strip()
        else ""
    )
    return response


def _agent_evidence_item(
    *,
    kind: str,
    label: str,
    url: str = "",
    source: str = "",
    confidence: float = 1.0,
    used_for: list[str] | None = None,
    access_summary: dict[str, Any] | None = None,
) -> dict[str, Any]:
    access = access_summary or {}
    return {
        "kind": kind,
        "label": label,
        "url": normalize_agent_href(url) if url else "",
        "source": source,
        "confidence": confidence,
        "acl_decision": {
            "can_read": access.get("can_read", True),
            "can_cite": access.get("can_cite", True),
            "classification": access.get("classification") or "",
        },
        "used_for": used_for or ["answer"],
    }


def build_agent_evidence_ledger(response: dict[str, Any], req: BoiAgentChatRequest, employee_id: str) -> list[dict[str, Any]]:
    access = response.get("access_summary") if isinstance(response.get("access_summary"), dict) else {}
    context = response.get("context_summary") if isinstance(response.get("context_summary"), dict) else {}
    page = context.get("page_context") if isinstance(context.get("page_context"), dict) else {}
    items: list[dict[str, Any]] = []
    if page:
        title = str(page.get("title") or page.get("page_kind") or req.page_context.get("title") or "현재 페이지")
        items.append(
            _agent_evidence_item(
                kind="current_page",
                label=title,
                url=req.current_url,
                source="page_context",
                used_for=["answer", "followup"],
                access_summary=access,
            )
        )
    seen_urls = {item.get("url") for item in items if item.get("url")}
    for source_name, used_for in (("citations", ["answer", "citation", "followup"]), ("links", ["answer", "reference", "followup"])):
        for link in response.get(source_name) or []:
            if not isinstance(link, dict):
                continue
            url = normalize_agent_href(link.get("url") or link.get("href") or "")
            label = str(link.get("label") or link.get("title") or url or "").strip()
            if not label or (url and url in seen_urls):
                continue
            if url:
                seen_urls.add(url)
            items.append(
                _agent_evidence_item(
                    kind=str(link.get("kind") or source_name.rstrip("s") or "reference"),
                    label=label,
                    url=url,
                    source=source_name,
                    used_for=used_for,
                    access_summary=access,
                )
            )
    for artifact in normalize_agent_artifacts(response.get("artifacts"), str(response.get("answer_markdown") or "")):
        title = str(artifact.get("title") or artifact.get("type") or "artifact")
        items.append(
            _agent_evidence_item(
                kind=f"artifact:{artifact.get('type')}",
                label=title,
                source="agent_artifact",
                used_for=["answer", "followup"],
                access_summary=access,
            )
        )
    for card in normalize_agent_execution_cards(response.get("execution_cards"), employee_id):
        display = card.get("display") if isinstance(card.get("display"), dict) else {}
        items.append(
            _agent_evidence_item(
                kind=f"execution:{card.get('operation') or card.get('type')}",
                label=str(display.get("title") or card.get("title") or card.get("operation") or "확인 카드"),
                source="execution_card",
                confidence=0.9,
                used_for=["action_affordance", "followup"],
                access_summary=access,
            )
        )
    sanitized, _count = sanitize_agent_reference_value(items[:24], employee_id)
    return sanitized if isinstance(sanitized, list) else []


def build_agent_affordances(response: dict[str, Any], req: BoiAgentChatRequest, employee_id: str) -> list[dict[str, Any]]:
    artifacts = normalize_agent_artifacts(response.get("artifacts"), str(response.get("answer_markdown") or ""))
    artifact_types = {str(item.get("type") or "") for item in artifacts}
    cards = normalize_agent_execution_cards(response.get("execution_cards"), employee_id)
    links = [item for item in (response.get("links") or []) if isinstance(item, dict) and item.get("url")]
    intent = str(response.get("intent") or (response.get("context_summary") or {}).get("intent") or "")
    affordances: list[dict[str, Any]] = []

    def add(kind: str, label: str, question_hint: str, url: str = "", operation: str = "", skill_key: str = "") -> None:
        item = {
            "type": kind,
            "label": label,
            "question_hint": question_hint,
            "url": normalize_agent_href(url) if url else "",
            "operation": operation,
            "requires_confirmation": kind in {"create_draft", "request_execution", "complete_handoff", "approval"},
        }
        if skill_key:
            item["skill_key"] = skill_key
        affordances.append(item)

    add("ask_more", "근거 자세히 보기", "방금 답변의 근거를 더 자세히 설명해줘.")
    if links:
        first = links[0]
        add("open_reference", str(first.get("label") or "관련 문서 열기"), "가장 중요한 관련 문서를 기준으로 더 설명해줘.", str(first.get("url") or ""))
    if "mermaid" in artifact_types:
        add("check_gap", "Action Spec 누락 점검", "이 Mermaid 흐름에서 부족한 Action Spec을 점검해줘.")
        add("make_artifact", "관계 표로 보기", "이 흐름을 Event, Action, Manual Handoff 관계 표로 정리해줘.")
    if "workflow_summary" in artifact_types:
        add("make_artifact", "Mermaid로 보기", "이 관계 표를 Mermaid 프로세스 플로우로 다시 보여줘.")
        add("check_gap", "부족한 명세 점검", "이 관계 표에서 부족한 Action 명세를 찾아줘.")
    if "gap_table" in artifact_types or intent == "gap_check":
        add("create_draft", "부족 명세 초안", "누락된 Action 명세 초안을 먼저 만들어줘.", operation="event_type_draft")
    workflow_definition_context = response.get("workflow_definition_context") if isinstance(response.get("workflow_definition_context"), dict) else {}
    for skill_key in workflow_definition_context.get("action_skill_refs") or []:
        skill_key = str(skill_key or "")
        if skill_key == "event.publish":
            add("request_execution", "다음 Event 발행 전 확인", "이 Workflow 기준으로 다음 Event를 발행하기 전에 확인할 내용을 정리해줘.", operation="event_publish", skill_key=skill_key)
        elif skill_key == "manual.handoff_complete":
            add("complete_handoff", "조치 내용 입력", "이 Workflow 기준으로 수동 조치 완료 기록에 필요한 내용을 정리해줘.", operation="manual_handoff_complete", skill_key=skill_key)
        elif skill_key:
            add("ask_more", f"{skill_key} 활용", f"`{skill_key}`로 할 수 있는 업무를 설명해줘.", skill_key=skill_key)
    for card in cards:
        operation = str(card.get("operation") or "")
        display = card.get("display") if isinstance(card.get("display"), dict) else {}
        label = str(display.get("title") or card.get("title") or operation or "확인 필요")
        if "handoff" in operation:
            add("complete_handoff", label, "이 조치 내용을 입력해서 완료 기록을 남기고 싶어.", operation=operation)
        elif "approval" in operation or card.get("requires_confirmation"):
            add("approval", label, "이 요청을 실행하기 전에 확인할 내용을 정리해줘.", operation=operation)
        else:
            add("request_execution", label, "이 요청을 실행하기 전에 먼저 확인해줘.", operation=operation)
    sanitized, _count = sanitize_agent_reference_value(affordances[:12], employee_id)
    return sanitized if isinstance(sanitized, list) else []


AGENT_MUTATION_FOLLOWUP_TERMS = (
    "실행",
    "호출",
    "발행",
    "게시",
    "배포",
    "반영",
    "적용",
    "완료",
    "초안",
    "draft",
    "invoke",
    "publish",
)
AGENT_IMMEDIATE_MUTATION_FOLLOWUP_TERMS = (
    "바로 실행",
    "즉시 실행",
    "지금 바로 실행",
    "바로 발행",
    "즉시 발행",
    "지금 바로 발행",
    "바로 반영",
    "즉시 반영",
    "지금 바로 반영",
)
AGENT_MUTATION_AFFORDANCE_TYPES = {"create_draft", "request_execution", "complete_handoff", "approval"}
AGENT_SAFE_MUTATION_FOLLOWUP_QUALIFIERS = (
    "전에",
    "먼저",
    "초안",
    "승인",
    "기준",
    "입력",
    "필요",
    "영향",
    "근거",
    "확인",
    "점검",
    "검토",
)


def agent_response_has_mutation_affordance(response: dict[str, Any]) -> bool:
    for item in response.get("affordances") or []:
        if isinstance(item, dict) and str(item.get("type") or "") in AGENT_MUTATION_AFFORDANCE_TYPES:
            return True
    return bool(response.get("execution_cards"))


def filter_agent_followups_by_affordances(suggestions: list[str], response: dict[str, Any]) -> list[str]:
    has_mutation_affordance = agent_response_has_mutation_affordance(response)
    filtered: list[str] = []
    for suggestion in suggestions:
        lower = suggestion.lower()
        if any(term in lower for term in AGENT_IMMEDIATE_MUTATION_FOLLOWUP_TERMS):
            continue
        has_mutation_term = any(term in lower for term in AGENT_MUTATION_FOLLOWUP_TERMS)
        if not has_mutation_affordance and has_mutation_term:
            continue
        if has_mutation_affordance and has_mutation_term and not any(term in suggestion for term in AGENT_SAFE_MUTATION_FOLLOWUP_QUALIFIERS):
            continue
        filtered.append(suggestion)
    if not filtered:
        raise BoiAgentSuggestionsUnavailable("LLM suggestion writer returned only unsupported mutation follow-ups")
    return filtered


def followup_questions_from_affordances(response: dict[str, Any]) -> list[str]:
    questions: list[str] = []
    for item in response.get("affordances") or []:
        if not isinstance(item, dict):
            continue
        hint = normalize_suggestion_text(item.get("question_hint") or "")
        if hint and is_actionable_suggestion_text(hint):
            questions.append(hint)
    if not questions:
        return []
    try:
        return filter_agent_followups_by_affordances(dedupe_suggestions(questions, limit=5), response)
    except BoiAgentSuggestionsUnavailable:
        return []


def agent_memory_preferences(employee_id: str, q: str = "", limit: int = 6) -> list[dict[str, Any]]:
    preference_kinds = {
        "answer_style",
        "workflow_preference",
        "recurring_task",
        "domain_context",
        "avoidance",
        "preference",
    }
    items = [
        item
        for item in agent_memory_items(employee_id, q="", limit=max(limit * 4, 20))
        if str(item.get("memory_kind") or "") in preference_kinds
        and str(item.get("classification") or "internal") not in {"confidential", "restricted"}
    ]
    return sorted(items, key=lambda item: int(item.get("priority") or 0), reverse=True)[: max(1, min(limit, 12))]


def compact_answer_context_for_followups(req: BoiAgentChatRequest, response: dict[str, Any], employee_id: str) -> dict[str, Any]:
    answer_source = re.sub(r"```.*?```", " ", str(response.get("display_markdown") or response.get("answer_markdown") or ""), flags=re.DOTALL)
    answer_text = text_excerpt(re.sub(r"[#>*_`|\\-]+", " ", answer_source), 900)
    return {
        "question": req.question,
        "answer_summary": answer_text,
        "memory_preferences": agent_memory_preferences(employee_id, req.question, limit=6),
        "work_context_summary": response.get("work_context_summary") or {},
        "historical_patterns": response.get("historical_patterns") or [],
        "work_patterns_used": response.get("work_patterns_used") or [],
        "pattern_candidates": response.get("pattern_candidates") or [],
        "route": response.get("route") or (response.get("context_summary") or {}).get("route"),
        "intent": response.get("intent") or (response.get("context_summary") or {}).get("intent"),
        "artifacts": [
            {
                "type": item.get("type"),
                "title": item.get("title") or item.get("type"),
                **({"row_count": len(item.get("data") or [])} if isinstance(item.get("data"), list) else {}),
            }
            for item in normalize_agent_artifacts(response.get("artifacts"), str(response.get("answer_markdown") or ""))[:6]
            if isinstance(item, dict)
        ],
        "links": [
            {"label": item.get("label") or item.get("url"), "url": item.get("url"), "kind": item.get("kind")}
            for item in (response.get("links") or [])[:8]
            if isinstance(item, dict)
        ],
        "citations": [
            {"label": item.get("label") or item.get("ref") or item.get("url"), "url": item.get("url"), "kind": item.get("kind")}
            for item in (response.get("citations") or [])[:6]
            if isinstance(item, dict)
        ],
        "execution_cards": [
            {
                "operation": item.get("operation"),
                "title": item.get("title"),
                "display": item.get("display"),
                "requires_confirmation": item.get("requires_confirmation", True),
            }
            for item in (response.get("execution_cards") or [])[:5]
            if isinstance(item, dict)
        ],
        "tool_trace": [
            {"tool": item.get("tool"), "status": item.get("status"), "summary": item.get("summary")}
            for item in (response.get("tool_trace") or [])[-8:]
            if isinstance(item, dict)
        ],
        "evidence_ledger": response.get("evidence_ledger") or [],
        "affordances": response.get("affordances") or [],
        "followup_policy": {
            "mutation_affordances_available": agent_response_has_mutation_affordance(response),
            "forbidden_terms_without_mutation_affordance": [] if agent_response_has_mutation_affordance(response) else list(AGENT_MUTATION_FOLLOWUP_TERMS),
        },
        "access_summary": response.get("access_summary") or {},
        "guardrails_applied": response.get("guardrails_applied") or [],
    }


def add_agent_evidence_and_affordances(response: dict[str, Any], req: BoiAgentChatRequest, employee_id: str) -> dict[str, Any]:
    try:
        work_context = work_context_pack(employee_id, current_url=req.current_url)
        compact_context = compact_work_context_summary(work_context)
    except Exception:
        work_context = {}
        compact_context = {}
    if compact_context:
        response["work_context_summary"] = compact_context
        response["historical_patterns"] = compact_context.get("historical_patterns") or []
        response["recommended_next_steps"] = compact_context.get("recommended_next_steps") or []
    else:
        response.setdefault("work_context_summary", {})
        response.setdefault("historical_patterns", [])
        response.setdefault("recommended_next_steps", [])
    patterns = work_pattern_items(employee_id, limit=6)
    response["personalization_used"] = {
        "memory_count": len(agent_memory_preferences(employee_id, req.question, limit=6)),
        "work_pattern_count": len(patterns),
    }
    response["work_patterns_used"] = patterns[:6]
    response["pattern_candidates"] = derive_work_pattern_candidates(employee_id, limit=4)
    response["skill_candidates"] = [
        {
            "title": item.get("title"),
            "suggested_skill": item.get("suggested_skill"),
            "pattern_kind": item.get("pattern_kind"),
            "usage_count": item.get("usage_count"),
        }
        for item in response["pattern_candidates"]
        if item.get("suggested_skill")
    ]
    response["evidence_ledger"] = build_agent_evidence_ledger(response, req, employee_id)
    response["affordances"] = build_agent_affordances(response, req, employee_id)
    quality = response.get("answer_quality") if isinstance(response.get("answer_quality"), dict) else {}
    quality.update(
        {
            "has_answer": bool(str(response.get("answer_markdown") or response.get("display_markdown") or "").strip()),
            "evidence_count": len(response["evidence_ledger"]),
            "affordance_count": len(response["affordances"]),
            "followups_generated": bool(response.get("suggested_questions")),
        }
    )
    response["answer_quality"] = quality
    return response


def ensure_agent_answer_followups(req: BoiAgentChatRequest, response: dict[str, Any], employee_id: str) -> dict[str, Any]:
    existing = [str(item).strip() for item in response.get("suggested_questions") or [] if str(item).strip()]
    has_answer_material = bool(str(response.get("answer_markdown") or response.get("display_markdown") or "").strip() or response.get("artifacts"))
    if existing or not has_answer_material:
        if existing:
            existing = remove_repeated_original_suggestions(
                filter_agent_followups_by_affordances(existing, response),
                req.question,
            )
            response["suggested_questions"] = existing
        quality = response.get("answer_quality") if isinstance(response.get("answer_quality"), dict) else {}
        quality["followups_generated"] = bool(existing)
        response["answer_quality"] = quality
        return response
    base_answer_context = compact_answer_context_for_followups(req, response, employee_id)
    page_context = resolve_agent_page_context(req.current_url, employee_id)
    if not page_context.get("title") and req.page_context.get("title"):
        page_context["title"] = req.page_context.get("title")
    suggestions: list[str] = []
    last_exc: BoiAgentSuggestionsUnavailable | None = None
    try:
        for attempt in range(2):
            answer_context = dict(base_answer_context)
            if attempt > 0 and last_exc:
                answer_context["followup_repair"] = {
                    "previous_error": str(last_exc),
                    "instruction": "Rewrite follow-up questions so every item stays inside the provided affordances, links, and access policy.",
                }
            suggestion_req = BoiAgentSuggestionsRequest(
                current_url=req.current_url,
                page_context=req.page_context,
                answer_context=answer_context,
            )
            try:
                suggestions = remove_repeated_original_suggestions(
                    filter_agent_followups_by_affordances(call_boi_agent_suggestions_llm(suggestion_req, employee_id, page_context), response),
                    req.question,
                )
                if suggestions:
                    break
            except BoiAgentSuggestionsUnavailable as exc:
                last_exc = exc
                if attempt == 0:
                    continue
                raise
    except BoiAgentSuggestionsUnavailable as exc:
        affordance_questions = remove_repeated_original_suggestions(
            followup_questions_from_affordances(response),
            req.question,
        )
        errors = response.setdefault("component_errors", [])
        if isinstance(errors, list):
            errors.append(
                {
                    "component": "followup_suggestions",
                    "status": "boi_agent_suggestions_unavailable",
                    "message": str(exc),
                    "model": BOI_AGENT_SUGGESTIONS_MODEL,
                    "required": BOI_AGENT_SUGGESTIONS_REQUIRED,
                }
            )
        response["suggested_questions"] = affordance_questions
        response["suggested_questions_source"] = "affordance_contract_after_llm_error" if affordance_questions else "answer_scoped_llm_unavailable"
        quality = response.get("answer_quality") if isinstance(response.get("answer_quality"), dict) else {}
        quality["followups_generated"] = bool(affordance_questions)
        quality["followups_error"] = str(exc)
        response["answer_quality"] = quality
        return response
    if not suggestions:
        suggestions = remove_repeated_original_suggestions(
            followup_questions_from_affordances(response),
            req.question,
        )
        response["suggested_questions_source"] = "affordance_contract_after_repeated_followups" if suggestions else "answer_scoped_llm_unavailable"
    else:
        response["suggested_questions_source"] = "answer_scoped_llm"
    response["suggested_questions"] = suggestions
    quality = response.get("answer_quality") if isinstance(response.get("answer_quality"), dict) else {}
    quality["followups_generated"] = bool(suggestions)
    quality["followup_count"] = len(suggestions)
    response["answer_quality"] = quality
    return response


def finalize_agent_chat_response(req: BoiAgentChatRequest, employee_id: str, *, route: dict[str, Any] | None = None, progress_callback: Callable[[dict[str, Any]], None] | None = None) -> dict[str, Any]:
    if route is not None or progress_callback is not None:
        response = agent_chat_response(req, employee_id, route=route, progress_callback=progress_callback)
    else:
        response = agent_chat_response_with_optional_status_plan(req, employee_id)
    response = enrich_agent_answer_html(response, employee_id)
    response = add_agent_evidence_and_affordances(response, req, employee_id)
    response = ensure_agent_answer_followups(req, response, employee_id)
    response = add_agent_evidence_and_affordances(response, req, employee_id)
    return enrich_agent_answer_html(response, employee_id)


def finalize_agent_chat_response_without_followups(
    req: BoiAgentChatRequest,
    employee_id: str,
    *,
    route: dict[str, Any] | None = None,
    progress_callback: Callable[[dict[str, Any]], None] | None = None,
) -> dict[str, Any]:
    if route is not None or progress_callback is not None:
        response = agent_chat_response(req, employee_id, route=route, progress_callback=progress_callback)
    else:
        response = agent_chat_response_with_optional_status_plan(req, employee_id)
    response = enrich_agent_answer_html(response, employee_id)
    response = add_agent_evidence_and_affordances(response, req, employee_id)
    return enrich_agent_answer_html(response, employee_id)


def agent_sse_event(event: str, payload: dict[str, Any]) -> str:
    return f"event: {event}\ndata: {json.dumps(payload, ensure_ascii=False, default=str)}\n\n"


def iter_agent_answer_chunks(value: str, *, chunk_size: int = 180) -> list[str]:
    text = str(value or "")
    if not text:
        return []
    chunks: list[str] = []
    start = 0
    while start < len(text):
        end = min(len(text), start + chunk_size)
        if end < len(text):
            boundary = max(text.rfind("\n", start, end), text.rfind(" ", start, end))
            if boundary > start + 120:
                end = boundary + 1
        chunks.append(text[start:end])
        start = end
    return chunks


def agent_stream_chunk_delay_seconds() -> float:
    try:
        return max(0.0, min(0.25, float(os.getenv("BOI_AGENT_STREAM_CHUNK_DELAY_SECONDS", "0.025"))))
    except (TypeError, ValueError):
        return 0.025


def agent_stream_status_steps(req: BoiAgentChatRequest, employee_id: str) -> list[dict[str, str]]:
    return call_boi_agent_status_llm(req, employee_id)


def agent_stream_plan(req: BoiAgentChatRequest, employee_id: str) -> dict[str, Any]:
    return call_boi_agent_stream_plan_llm(req, employee_id)


def agent_tool_progress_status(payload: dict[str, Any], elapsed_ms: int) -> dict[str, Any]:
    message = str(payload.get("message") or "").strip()
    if not message:
        raise BoiAgentStatusUnavailable("Agent progress payload is missing generated status message")
    return {
        "stage": str(payload.get("stage") or "tool_progress"),
        "message": message,
        "tool": str(payload.get("tool") or ""),
        "status": str(payload.get("status") or ""),
        "summary": str(payload.get("summary") or ""),
        "elapsed_ms": int(payload.get("elapsed_ms") or elapsed_ms),
    }


def lightweight_doc_link_items(doc: dict[str, Any], employee_id: str, *, limit: int = 8) -> list[dict[str, Any]]:
    """Extract current-document OKF links without building the full ontology index."""
    items: list[dict[str, Any]] = []
    seen: set[str] = set()
    source_path = Path(str(doc.get("path") or ""))
    if not source_path.exists():
        return items
    for match in MARKDOWN_LINK_RE.finditer(str(doc.get("body") or "")):
        href = match.group(1)
        if re.match(r"^[a-zA-Z][a-zA-Z0-9+.-]*:", href) or href.startswith("#") or is_app_route_href(href):
            continue
        target, _resolved = resolve_okf_link(href, source_path=source_path, boi_root=DATA_ROOT)
        if target in seen:
            continue
        seen.add(target)
        path = find_doc_path_by_ref(target)
        if not path:
            continue
        try:
            linked_doc = read_doc(path)
        except Exception:
            continue
        if not is_accessible(linked_doc, employee_id):
            continue
        metadata = linked_doc.get("metadata") or {}
        ref = str(metadata.get("boi_id") or linked_doc.get("uri") or target)
        items.append(
            {
                "kind": "boi_document",
                "score": 100,
                "boi_id": metadata.get("boi_id") or "",
                "uri": linked_doc.get("uri") or "",
                "title": metadata.get("title") or ref,
                "description": metadata.get("description") or "",
                "url": doc_url_for_ref(ref, employee_id),
            }
        )
        if len(items) >= limit:
            break
    return items


def agent_fast_answer(req: BoiAgentChatRequest, employee_id: str, route: dict[str, Any], started_at: float) -> dict[str, Any]:
    context_pack = agent_context_pack(req, employee_id)
    page_context = context_pack["page_context"]
    intent = normalize_agent_intent(str(route.get("intent") or ""), fallback=deterministic_agent_intent(req.question, req.current_url))
    if page_context.get("resolved") and intent in {"page_qa", "summarize"}:
        search = {
            "best_matches": page_context.get("linked_items") or [],
            "query_expansion": [],
            "used_dictionary_terms": [],
            "knowledge_panel": {},
            "citations": [],
            "fast_path": "page_context",
        }
    else:
        search = context_pack.get("ontology_search_seed") or ontology_search_payload(req.question, employee_id, scope="all", limit=5, current_url=req.current_url)
    links: list[dict[str, Any]] = []
    links.extend(link_items_from_agent_context(page_context, employee_id))
    for item in search.get("best_matches") or []:
        link = agent_link_for_item(item)
        if link.get("url") and all(existing.get("url") != link["url"] for existing in links):
            links.append(link)
    page_label = str(page_context.get("title") or page_context.get("page_kind") or "현재 화면")
    if page_context.get("resolved"):
        answer_lines = [f"현재 화면은 `{page_context.get('page_kind')}`로 해석했습니다: **{page_label}**."]
    else:
        answer_lines = ["현재 화면을 정확히 해석하지 못해 BoI Wiki ontology search 기준으로 답변합니다."]
    if intent == "search":
        expanded = search.get("query_expansion") or []
        if expanded:
            answer_lines.append("검색어를 다음 업무 용어로 확장했습니다: " + ", ".join(f"`{term}`" for term in expanded[:6]))
        knowledge = search.get("knowledge_panel") or {}
        panel_bits = []
        for key, label in (("top_sop", "SOP"), ("top_event_type", "Event"), ("top_action", "Action")):
            value = knowledge.get(key) if isinstance(knowledge, dict) else []
            if isinstance(value, list) and value:
                item = value[0]
                panel_bits.append(f"{label}: {item.get('title') or item.get('event_type') or item.get('action_key')}")
        if panel_bits:
            answer_lines.append("가장 관련 높은 축은 " + " / ".join(panel_bits) + "입니다.")
    best = (search.get("best_matches") or [])[:3]
    if best:
        answer_lines.append("관련 항목:")
        for item in best:
            label = str(item.get("title") or item.get("term") or item.get("event_type") or item.get("action_key") or item.get("boi_id") or "결과")
            url = str(item.get("url") or "")
            description = text_excerpt(str(item.get("description") or ""), 120)
            rendered_label = f"[{label}]({url})" if url else f"**{label}**"
            reason = str(item.get("match_reason") or item.get("kind") or "").replace("_", " ")
            suffix = f": {description}" if description else ""
            if reason and reason not in description:
                suffix = f" ({reason})" + suffix
            answer_lines.append(f"- {rendered_label}{suffix}")
    elif page_context.get("body_excerpt"):
        answer_lines.append(f"본문 발췌: {page_context['body_excerpt']}")
    else:
        answer_lines.append("질문과 직접 연결되는 항목을 찾지 못했습니다.")
    if route.get("route") == "fast":
        answer_lines.append(
            "\n더 복합적인 판단이 필요하면 `도식으로 보여줘`, `누락된 Action을 찾아줘`, "
            "`실행 근거를 분석해줘`처럼 원하는 산출물을 구체적으로 요청하세요."
        )
    latency_ms = int((time.perf_counter() - started_at) * 1000)
    context_summary = {
        "page_context": page_context,
        "current_url": req.current_url,
        "route": route.get("route"),
        "intent": intent,
        "router_backend": route.get("router_backend"),
        "router_confidence": route.get("confidence"),
        "used_backend": "fast_api",
        "latency_ms": latency_ms,
    }
    return {
        "ok": True,
        "employee_id": employee_id,
        "answer_markdown": "\n".join(answer_lines),
        "links": links[:8],
        "citations": links[:5],
        "suggested_questions": [],
        "suggested_questions_source": "suggestions_endpoint_required",
        "artifacts": [],
        "context_summary": context_summary,
        "route": route.get("route"),
        "intent": intent,
        "router_backend": route.get("router_backend"),
        "router_confidence": route.get("confidence"),
        "used_backend": "fast_api",
        "latency_ms": latency_ms,
    }


def agent_inbox_answer(req: BoiAgentChatRequest, employee_id: str, route: dict[str, Any], started_at: float) -> dict[str, Any]:
    inbox = agent_inbox_payload(employee_id, status="open", limit=5, include_context="compact")
    items = inbox.get("items") or []
    intent = normalize_agent_intent(str(route.get("intent") or ""), fallback="inbox")
    lines = [f"현재 처리할 업무는 {len(items)}건입니다."]
    for item in items[:5]:
        display = item.get("display") if isinstance(item.get("display"), dict) else {}
        label = display.get("status_label") or item.get("status") or "확인 필요"
        title = display.get("title") or item.get("action_key") or "업무 확인"
        next_action = display.get("next_action") or "실행 현황이나 원본 기록을 확인하세요."
        first_link = (item.get("user_links") or [{}])[0] if isinstance(item.get("user_links"), list) else {}
        primary_url = str(first_link.get("url") or display.get("primary_url") or item.get("workflow_run_url") or item.get("raw_url") or "")
        rendered_title = f"[{title}]({primary_url})" if primary_url else f"**{title}**"
        lines.append(f"- {label}: {rendered_title} - {next_action}")
        narrative = item.get("work_context_narrative") if isinstance(item.get("work_context_narrative"), dict) else {}
        if narrative.get("summary_state") == "ready":
            stage_narrative = narrative.get("stage_history_narrative") if isinstance(narrative.get("stage_history_narrative"), list) else []
            for row in stage_narrative[:2]:
                if isinstance(row, dict) and row.get("text"):
                    lines.append(f"  - {row['text']}")
            similar = narrative.get("similar_case_narrative") if isinstance(narrative.get("similar_case_narrative"), dict) else {}
            if similar.get("text"):
                lines.append(f"  - {similar['text']}")
        elif item.get("context_preview"):
            lines.append("  - 업무 맥락 요약은 준비 중입니다. 원본 실행 현황과 기록을 확인해 판단하세요.")
    latency_ms = int((time.perf_counter() - started_at) * 1000)
    return {
        "ok": True,
        "employee_id": employee_id,
        "answer_markdown": "\n".join(lines),
        "links": [
            {**link, "kind": link.get("kind") or "inbox"}
            for item in items
            for link in (item.get("user_links") or [])
            if link.get("url")
        ],
        "citations": [],
        "suggested_questions": [],
        "suggested_questions_source": "suggestions_endpoint_required",
        "artifacts": [{"type": "task_cards", "data": [item.get("display") for item in items if item.get("display")]}],
        "context_summary": {"route": route.get("route"), "intent": intent, "router_backend": route.get("router_backend"), "used_backend": "inbox_api", "latency_ms": latency_ms},
        "route": route.get("route"),
        "intent": intent,
        "router_backend": route.get("router_backend"),
        "router_confidence": route.get("confidence"),
        "used_backend": "inbox_api",
        "latency_ms": latency_ms,
    }


def agent_safety_answer(req: BoiAgentChatRequest, employee_id: str, route: dict[str, Any], started_at: float) -> dict[str, Any]:
    latency_ms = int((time.perf_counter() - started_at) * 1000)
    route_name = str(route.get("route") or "approval_required")
    intent = normalize_agent_intent(str(route.get("intent") or ""), fallback="approval" if route_name == "approval_required" else "manual_complete")
    if route_name == "manual_handoff":
        answer = "조치 완료는 Inbox 카드에서 조치 내용과 결과를 입력한 뒤 명시적으로 완료 기록을 남겨야 합니다."
    else:
        answer = "승인, 실행, 게시, 편집 같은 상태 변경 요청은 Agent 답변만으로 수행하지 않습니다. 관련 SOP, 실행 현황, 원본 기록을 확인하고 명시 승인 절차로 진행해야 합니다."
    return {
        "ok": True,
        "employee_id": employee_id,
        "answer_markdown": answer,
        "links": [],
        "citations": [],
        "suggested_questions": [],
        "suggested_questions_source": "suggestions_endpoint_required",
        "artifacts": [],
        "context_summary": {"route": route_name, "intent": intent, "router_backend": route.get("router_backend"), "used_backend": "safety_guard", "latency_ms": latency_ms},
        "route": route_name,
        "intent": intent,
        "router_backend": route.get("router_backend"),
        "router_confidence": route.get("confidence"),
        "used_backend": "safety_guard",
        "latency_ms": latency_ms,
    }


def langflow_auth_headers() -> dict[str, str]:
    if LANGFLOW_AUTH_MODE == "api-key":
        return {"x-api-key": LANGFLOW_API_KEY}
    try:
        with httpx.Client(timeout=LANGFLOW_AGENT_TIMEOUT_SECONDS) as client:
            response = client.get(f"{LANGFLOW_URL}/api/v1/auto_login")
            response.raise_for_status()
            token = response.json().get("access_token")
    except Exception as exc:  # pragma: no cover - exercised through route-level unavailable handling
        raise LangflowBoiAgentUnavailable(f"Langflow auto_login failed: {exc}") from exc
    if not token:
        raise LangflowBoiAgentUnavailable("Langflow auto_login did not return access_token")
    return {"Authorization": f"Bearer {token}"}


def iter_langflow_text_candidates(value: Any, depth: int = 0) -> list[str]:
    if depth > 12:
        return []
    candidates: list[str] = []
    if isinstance(value, str):
        if value.strip():
            candidates.append(value)
        return candidates
    if isinstance(value, list):
        for item in value:
            candidates.extend(iter_langflow_text_candidates(item, depth + 1))
        return candidates
    if isinstance(value, dict):
        preferred_keys = (
            "choices",
            "answer_markdown",
            "text",
            "message",
            "content",
            "reasoning_content",
            "output",
            "result",
            "data",
            "results",
            "artifacts",
            "outputs",
            "messages",
        )
        seen_keys: set[str] = set()
        for key in preferred_keys:
            if key in value:
                seen_keys.add(key)
                candidates.extend(iter_langflow_text_candidates(value.get(key), depth + 1))
        for key, item in value.items():
            if key not in seen_keys:
                candidates.extend(iter_langflow_text_candidates(item, depth + 1))
    return candidates


def first_langflow_text(value: Any) -> str:
    for text in iter_langflow_text_candidates(value):
        if text.strip():
            return text
    return ""


def parse_langflow_json_text(text: str) -> dict[str, Any] | None:
    stripped = text.strip()
    if stripped.startswith("```json"):
        stripped = stripped.removeprefix("```json").strip()
        if stripped.endswith("```"):
            stripped = stripped[:-3].strip()
    elif stripped.startswith("```") and stripped.endswith("```"):
        stripped = stripped[3:-3].strip()
    if not stripped.startswith("{"):
        return None
    try:
        parsed = json.loads(stripped)
    except json.JSONDecodeError:
        return None
    return parsed if isinstance(parsed, dict) else None


def langflow_payload_has_answer(payload: dict[str, Any]) -> bool:
    answer = str(payload.get("answer_markdown") or payload.get("answer") or payload.get("message") or "").strip()
    return bool(answer and answer != "BoI Agent returned an empty answer.")


def parse_langflow_agent_payload(run_result: dict[str, Any]) -> dict[str, Any]:
    candidates = iter_langflow_text_candidates(run_result)
    if not candidates:
        raise LangflowBoiAgentUnavailable("BoI Agent Flow returned no message")
    parsed_candidates: list[dict[str, Any]] = []
    for text in candidates:
        parsed = parse_langflow_json_text(text)
        if parsed is None:
            continue
        if langflow_payload_has_answer(parsed):
            return parsed
        parsed_candidates.append(parsed)
    if parsed_candidates:
        return parsed_candidates[0]
    return {"answer_markdown": candidates[0]}


def normalize_langflow_agent_response(
    run_result: dict[str, Any],
    req: BoiAgentChatRequest,
    employee_id: str,
    route: dict[str, Any] | None = None,
    started_at: float | None = None,
) -> dict[str, Any]:
    parsed = parse_langflow_agent_payload(run_result)
    answer_markdown = str(parsed.get("answer_markdown") or parsed.get("answer") or parsed.get("message") or "").strip()
    if not answer_markdown:
        raise LangflowBoiAgentUnavailable("BoI Agent Flow response did not include answer_markdown")
    links = parsed.get("links")
    if not isinstance(links, list):
        links = []
    citations = parsed.get("citations")
    if not isinstance(citations, list):
        citations = links[:5]
    suggestions = parsed.get("suggested_questions")
    suggestions_source = "llm_composer" if isinstance(suggestions, list) and suggestions else "suggestions_endpoint_required"
    if not isinstance(suggestions, list) or not suggestions:
        suggestions = []
    artifacts = normalize_agent_artifacts(parsed.get("artifacts"), answer_markdown)
    intent = normalize_agent_intent(str(route.get("intent") if route else parsed.get("intent") or ""), fallback=deterministic_agent_intent(req.question, req.current_url))
    if intent == "diagram" and not any(item.get("type") == "mermaid" for item in artifacts):
        raise LangflowBoiAgentUnavailable("BoI Agent Flow did not return required Mermaid artifact for diagram intent")
    context_summary = parsed.get("context_summary")
    if not isinstance(context_summary, dict):
        context_summary = {}
    context_summary.update(
        {
            "current_url": req.current_url,
            "intent": intent,
            "langflow_flow": LANGFLOW_BOI_AGENT_ENDPOINT,
            "langflow_backend": "trusted",
        }
    )
    latency_ms = int((time.perf_counter() - started_at) * 1000) if started_at else None
    if route:
        context_summary.update(
            {
                "route": route.get("route"),
                "router_backend": route.get("router_backend"),
                "router_confidence": route.get("confidence"),
                "used_backend": "langflow",
            }
        )
        if latency_ms is not None:
            context_summary["latency_ms"] = latency_ms
    return {
        "ok": True,
        "employee_id": employee_id,
        "answer_markdown": answer_markdown,
        "links": links,
        "citations": citations,
        "suggested_questions": suggestions,
        "suggested_questions_source": suggestions_source,
        "artifacts": artifacts,
        "context_summary": context_summary,
        "route": route.get("route") if route else "deep",
        "intent": intent,
        "router_backend": route.get("router_backend") if route else "",
        "router_confidence": route.get("confidence") if route else None,
        "used_backend": "langflow",
        "latency_ms": latency_ms,
    }


def call_langflow_boi_agent(req: BoiAgentChatRequest, employee_id: str, route: dict[str, Any] | None = None, started_at: float | None = None) -> dict[str, Any]:
    if not LANGFLOW_URL or not LANGFLOW_BOI_AGENT_ENDPOINT:
        raise LangflowBoiAgentUnavailable("Langflow BoI Agent endpoint is not configured")
    context_pack = agent_context_pack(req, employee_id, search_limit=6)
    intent = normalize_agent_intent(str(route.get("intent") if route else req.intent), fallback=deterministic_agent_intent(req.question, req.current_url))
    payload = {
        "input_value": json.dumps(
            {
                "question": req.question,
                "employee_id": employee_id,
                "mode": req.mode,
                "intent": intent,
                "route": route or {},
                "current_url": req.current_url,
                "selected_text": req.selected_text,
                "page_context": req.page_context,
                "page_context_pack": context_pack.get("page_context") or {},
                "ontology_search_seed": context_pack.get("ontology_search_seed") or {},
                "conversation": req.conversation[-12:],
                "save_memory": req.save_memory,
            },
            ensure_ascii=False,
            default=str,
        ),
        "input_type": "chat",
        "output_type": "chat",
    }
    headers = {**langflow_auth_headers(), "Content-Type": "application/json"}
    url = f"{LANGFLOW_URL}/api/v1/run/{LANGFLOW_BOI_AGENT_ENDPOINT}"
    try:
        with httpx.Client(timeout=LANGFLOW_AGENT_TIMEOUT_SECONDS) as client:
            response = client.post(url, headers=headers, json=payload)
            if response.status_code == 404:
                raise LangflowBoiAgentUnavailable(f"BoI Agent Flow endpoint not found: {LANGFLOW_BOI_AGENT_ENDPOINT}")
            response.raise_for_status()
            run_result = response.json()
    except LangflowBoiAgentUnavailable:
        raise
    except Exception as exc:
        raise LangflowBoiAgentUnavailable(f"Langflow BoI Agent call failed: {exc}") from exc
    return normalize_langflow_agent_response(run_result, req, employee_id, route=route, started_at=started_at)


def agent_chat_response(
    req: BoiAgentChatRequest,
    employee_id: str,
    progress_callback: Callable[[dict[str, Any]], None] | None = None,
    route: dict[str, Any] | None = None,
) -> dict[str, Any]:
    started_at = time.perf_counter()
    route = dict(route) if route else route_boi_agent_request(req, employee_id)
    if BOI_AGENT_BACKEND in {"native", "hybrid"}:
        try:
            return call_native_boi_agent(req, employee_id, route, started_at, progress_callback=progress_callback)
        except NativeAgentRuntimeUnavailable:
            raise
        except Exception as exc:
            raise NativeAgentRuntimeUnavailable(f"Native Agent runtime failed: {exc}") from exc

    route_name = str(route.get("route") or "fast")
    if route_name in {"manual_handoff", "approval_required"}:
        return agent_safety_answer(req, employee_id, route, started_at)
    if BOI_AGENT_BACKEND == "langflow" and route_name == "deep":
        return call_langflow_boi_agent(req, employee_id, route=route, started_at=started_at)
    if BOI_AGENT_BACKEND not in {"native", "hybrid", "langflow"}:
        raise NativeAgentRuntimeUnavailable(f"Unknown BOI_AGENT_BACKEND: {BOI_AGENT_BACKEND}")
    if BOI_AGENT_BACKEND in {"native", "hybrid"} or route_name in {"fast", "deep", "inbox"}:
        return call_native_boi_agent(req, employee_id, route, started_at, progress_callback=progress_callback)
    if route_name == "inbox":
        return agent_inbox_answer(req, employee_id, route, started_at)
    return agent_fast_answer(req, employee_id, route, started_at)


def agent_chat_response_with_optional_status_plan(req: BoiAgentChatRequest, employee_id: str) -> dict[str, Any]:
    """Return the canonical Agent response for JSON/MCP clients.

    Web streaming already calls ``agent_stream_plan`` before running the Agent
    so users see LLM-authored progress lines. JSON API and MCP clients cannot
    consume SSE, therefore the same plan is embedded into ``status_updates``
    when the LLM status/router stack is configured. In local/test runtimes
    without that stack, explicit non-stream requests keep the existing Agent
    execution path.
    """
    planned_route: dict[str, Any] | None = None
    planned_status_updates: list[dict[str, Any]] = []
    if req.mode == "auto" and BOI_AGENT_STATUS_LLM_ENABLED and BOI_AGENT_ROUTER_LLM_ENABLED:
        try:
            stream_plan = agent_stream_plan(req, employee_id)
            planned_route = stream_plan["route"]
            planned_status_updates = list(stream_plan.get("status_steps") or [])
        except (BoiAgentRouterUnavailable, BoiAgentStatusUnavailable) as exc:
            planned_route = deterministic_agent_route_for_request(
                req,
                reason="stream plan unavailable; native goal router",
                component_error=agent_component_error(
                    "stream_plan",
                    "boi_agent_router_unavailable" if isinstance(exc, BoiAgentRouterUnavailable) else "status_generation_failed",
                    str(exc),
                    recoverable=True,
                    user_visible=False,
                ),
            )
    response = agent_chat_response(req, employee_id, route=planned_route) if planned_route else agent_chat_response(req, employee_id)
    if planned_status_updates:
        existing_updates = response.get("status_updates") if isinstance(response.get("status_updates"), list) else []
        response["status_updates"] = [*planned_status_updates, *existing_updates]
    return response


@app.post("/api/agents/boi-wiki/chat")
async def api_boi_agent_chat(req: BoiAgentChatRequest, employee_id: str = Depends(current_employee)) -> dict[str, Any]:
    append_activity(employee_id, {"activity_type": "agent_question", "target": req.current_url, "title": req.question[:120]})
    try:
        return await asyncio.wait_for(
            asyncio.to_thread(lambda: finalize_agent_chat_response(req, employee_id)),
            timeout=BOI_AGENT_CHAT_TIMEOUT_SECONDS,
        )
    except asyncio.TimeoutError as exc:
        raise HTTPException(
            status_code=503,
            detail={
                "ok": False,
                "status": "boi_agent_timeout",
                "message": f"BoI Agent did not finish within {BOI_AGENT_CHAT_TIMEOUT_SECONDS:.1f}s",
                "timeout_seconds": BOI_AGENT_CHAT_TIMEOUT_SECONDS,
                "used_backend": BOI_AGENT_BACKEND,
                "model": BOI_AGENT_COMPOSER_MODEL,
            },
        ) from exc
    except BoiAgentRouterUnavailable as exc:
        raise HTTPException(
            status_code=503,
            detail={
                "ok": False,
                "status": "boi_agent_router_unavailable",
                "message": str(exc),
                "model": BOI_AGENT_ROUTER_MODEL,
                "required": BOI_AGENT_ROUTER_REQUIRED,
            },
        ) from exc
    except BoiAgentStatusUnavailable as exc:
        raise HTTPException(
            status_code=503,
            detail={
                "ok": False,
                "status": "status_generation_failed",
                "message": str(exc),
                "model": BOI_AGENT_STATUS_MODEL,
                "required": BOI_AGENT_STATUS_REQUIRED,
            },
        ) from exc
    except NativeAgentRuntimeUnavailable as exc:
        raise HTTPException(
            status_code=503,
            detail={
                "ok": False,
                "status": "native_agent_runtime_unavailable",
                "message": str(exc),
                "langgraph_available": LANGGRAPH_AVAILABLE,
                "langgraph_required": BOI_AGENT_LANGGRAPH_REQUIRED,
            },
        ) from exc
    except LangflowBoiAgentUnavailable as exc:
        raise HTTPException(
            status_code=503,
            detail={
                "ok": False,
                "status": "langflow_boi_agent_unavailable",
                "message": str(exc),
                "langflow_url": LANGFLOW_URL,
                "endpoint": LANGFLOW_BOI_AGENT_ENDPOINT,
            },
        ) from exc
    except BoiAgentSuggestionsUnavailable as exc:
        raise HTTPException(
            status_code=503,
            detail={
                "ok": False,
                "status": "boi_agent_suggestions_unavailable",
                "message": str(exc),
                "model": BOI_AGENT_SUGGESTIONS_MODEL,
                "required": BOI_AGENT_SUGGESTIONS_REQUIRED,
            },
        ) from exc


@app.post("/api/agents/boi-wiki/chat/stream")
async def api_boi_agent_chat_stream(req: BoiAgentChatRequest, employee_id: str = Depends(current_employee)) -> StreamingResponse:
    append_activity(employee_id, {"activity_type": "agent_question", "target": req.current_url, "title": req.question[:120]})
    async def stream_events():
        yield agent_sse_event(
            "accepted",
            {
                "ok": True,
                "status": "accepted",
                "message": "요청을 받았습니다.",
                "source": "ui_state",
            },
        )
        stream_plan_diagnostic: dict[str, Any] | None = None
        try:
            stream_plan = await asyncio.to_thread(agent_stream_plan, req, employee_id)
            status_steps = list(stream_plan.get("status_steps") or [])
            planned_route = stream_plan["route"]
        except (BoiAgentStatusUnavailable, BoiAgentRouterUnavailable) as exc:
            error_status = "boi_agent_router_unavailable" if isinstance(exc, BoiAgentRouterUnavailable) else "status_generation_failed"
            stream_plan_diagnostic = agent_component_error(
                "stream_plan",
                error_status,
                str(exc),
                recoverable=True,
                user_visible=False,
            )
            planned_route = deterministic_agent_route_for_request(
                req,
                reason="stream plan unavailable; native goal router",
                component_error=stream_plan_diagnostic,
            )
            status_steps = []
            yield agent_sse_event(
                "diagnostic",
                {
                    **stream_plan_diagnostic,
                    "model": BOI_AGENT_STATUS_MODEL,
                    "required": BOI_AGENT_STATUS_REQUIRED,
                },
            )
        except NativeAgentRuntimeUnavailable as exc:
            yield agent_sse_event(
                "error",
                {
                    "status": "native_agent_runtime_unavailable",
                    "message": str(exc),
                    "langgraph_available": LANGGRAPH_AVAILABLE,
                    "langgraph_required": BOI_AGENT_LANGGRAPH_REQUIRED,
                },
            )
            return
        if not status_steps and stream_plan_diagnostic is None:
            yield agent_sse_event(
                "error",
                {
                    "status": "status_generation_failed",
                    "message": "status model returned no progress steps",
                    "model": BOI_AGENT_STATUS_MODEL,
                    "required": BOI_AGENT_STATUS_REQUIRED,
                },
            )
            return
        emitted_status_messages: set[str] = set()
        emitted_status_updates: list[dict[str, Any]] = []

        def status_event_if_new(step: dict[str, str], elapsed_ms: int) -> str | None:
            message = str(step.get("message") or "")
            if message in emitted_status_messages:
                return None
            emitted_status_messages.add(message)
            payload = {**step, "elapsed_ms": elapsed_ms}
            emitted_status_updates.append(payload)
            return agent_sse_event("status", payload)

        if status_steps:
            initial_status = status_event_if_new(status_steps[0], 0)
            if initial_status:
                yield initial_status
        started_at = time.perf_counter()
        progress_queue: queue.Queue[dict[str, Any]] = queue.Queue()
        result_queue: queue.Queue[tuple[str, Any]] = queue.Queue(maxsize=1)

        def emit_progress(payload: dict[str, Any]) -> None:
            progress_queue.put(payload)

        def drain_progress_events() -> list[dict[str, Any]]:
            drained: list[dict[str, Any]] = []
            while True:
                try:
                    drained.append(progress_queue.get_nowait())
                except queue.Empty:
                    return drained

        def run_agent() -> dict[str, Any]:
            return finalize_agent_chat_response_without_followups(req, employee_id, route=planned_route, progress_callback=emit_progress)

        def run_agent_worker() -> None:
            try:
                result_queue.put(("response", run_agent()))
            except Exception as exc:  # pragma: no cover - exercised through stream error path
                result_queue.put(("error", exc))

        worker = threading.Thread(target=run_agent_worker, name="boi-agent-stream-worker", daemon=True)
        worker.start()
        status_index = 1
        last_generic_status_at = started_at
        response: dict[str, Any] | None = None
        try:
            while True:
                elapsed_ms = int((time.perf_counter() - started_at) * 1000)
                drain_progress_events()

                try:
                    kind, payload = result_queue.get_nowait()
                except queue.Empty:
                    if (
                        status_index < len(status_steps)
                        and time.perf_counter() - last_generic_status_at >= max(0.5, BOI_AGENT_STREAM_HEARTBEAT_SECONDS)
                    ):
                        step = status_steps[min(status_index, len(status_steps) - 1)]
                        status_index += 1
                        last_generic_status_at = time.perf_counter()
                        status_event = status_event_if_new(step, elapsed_ms)
                        if status_event:
                            yield status_event
                    await asyncio.sleep(0.25)
                    continue
                if kind == "error":
                    raise payload
                response = payload
                break

            elapsed_ms = int((time.perf_counter() - started_at) * 1000)
            drain_progress_events()

            if response is None:
                raise RuntimeError("BoI Agent stream finished without a response")
            display_markdown = str(response.get("display_markdown") or response.get("answer_markdown") or "")
            chunks = iter_agent_answer_chunks(display_markdown)
            if chunks and status_steps:
                answer_status = next((item for item in status_steps if item.get("stage") == "answer_stream"), status_steps[-1])
                status_event = status_event_if_new(answer_status, elapsed_ms)
                if status_event:
                    yield status_event
            chunk_delay = agent_stream_chunk_delay_seconds()
            for chunk in chunks:
                yield agent_sse_event("answer_delta", {"delta": chunk})
                if chunk_delay:
                    await asyncio.sleep(chunk_delay)
            if emitted_status_updates:
                existing_updates = response.get("status_updates") if isinstance(response.get("status_updates"), list) else []
                response["status_updates"] = [*emitted_status_updates, *existing_updates]
                response["status_events"] = list(response["status_updates"])
            answer_ready = dict(response)
            answer_ready["suggested_questions"] = []
            quality = answer_ready.get("answer_quality") if isinstance(answer_ready.get("answer_quality"), dict) else {}
            quality["followups_generated"] = False
            answer_ready["answer_quality"] = quality
            yield agent_sse_event("answer_ready", answer_ready)
            await asyncio.sleep(0)
            try:
                response = await asyncio.to_thread(ensure_agent_answer_followups, req, response, employee_id)
                response = add_agent_evidence_and_affordances(response, req, employee_id)
                response = enrich_agent_answer_html(response, employee_id)
                yield agent_sse_event(
                    "followups",
                    {
                        "ok": True,
                        "suggested_questions": response.get("suggested_questions") or [],
                        "suggested_questions_source": response.get("suggested_questions_source") or "",
                        "answer_quality": response.get("answer_quality") or {},
                    },
                )
            except BoiAgentSuggestionsUnavailable as exc:
                quality = response.get("answer_quality") if isinstance(response.get("answer_quality"), dict) else {}
                quality.update(
                    {
                        "followups_generated": False,
                        "followups_error": str(exc),
                    }
                )
                response["answer_quality"] = quality
                response["suggested_questions"] = []
                yield agent_sse_event(
                    "followups",
                    {
                        "ok": False,
                        "status": "boi_agent_suggestions_unavailable",
                        "message": str(exc),
                        "model": BOI_AGENT_SUGGESTIONS_MODEL,
                        "required": BOI_AGENT_SUGGESTIONS_REQUIRED,
                        "suggested_questions": [],
                    },
                )
            yield agent_sse_event("final", response)
        except LangflowBoiAgentUnavailable as exc:
            yield agent_sse_event(
                "error",
                {
                    "status": "langflow_boi_agent_unavailable",
                    "message": str(exc),
                    "endpoint": LANGFLOW_BOI_AGENT_ENDPOINT,
                },
            )
        except BoiAgentRouterUnavailable as exc:
            yield agent_sse_event(
                "error",
                {
                    "status": "boi_agent_router_unavailable",
                    "message": str(exc),
                    "model": BOI_AGENT_ROUTER_MODEL,
                    "required": BOI_AGENT_ROUTER_REQUIRED,
                },
            )
        except NativeAgentRuntimeUnavailable as exc:
            yield agent_sse_event(
                "error",
                {
                    "status": "native_agent_runtime_unavailable",
                    "message": str(exc),
                    "langgraph_available": LANGGRAPH_AVAILABLE,
                    "langgraph_required": BOI_AGENT_LANGGRAPH_REQUIRED,
                },
            )
        except Exception as exc:
            yield agent_sse_event("error", {"status": "agent_stream_error", "message": str(exc)})
        finally:
            # The worker is daemonized because a client-side stop cannot safely
            # interrupt an in-flight LLM/tool request. Late results are dropped.
            worker.join(timeout=0)

    return StreamingResponse(stream_events(), media_type="text/event-stream")


@app.post("/api/agents/boi-wiki/suggestions")
async def api_boi_agent_suggestions(req: BoiAgentSuggestionsRequest, employee_id: str = Depends(current_employee)) -> dict[str, Any]:
    resolved_context = resolve_agent_page_context(req.current_url, employee_id)
    if not resolved_context.get("title") and req.page_context.get("title"):
        resolved_context["title"] = req.page_context.get("title")
    if not req.answer_context and not BOI_AGENT_SUGGESTIONS_REQUIRED:
        page_suggestions = page_context_suggestions(req.current_url, resolved_context)
        if page_suggestions:
            return {
                "ok": True,
                "employee_id": employee_id,
                "current_url": req.current_url,
                "page_context": resolved_context,
                "suggestions": page_suggestions,
                "suggestions_source": "page_context",
            }
    source = "answer_scoped_llm" if req.answer_context else "llm"
    try:
        suggestions = await asyncio.to_thread(call_boi_agent_suggestions_llm, req, employee_id, resolved_context)
    except BoiAgentSuggestionsUnavailable as exc:
        raise HTTPException(
            status_code=503,
            detail={
                "ok": False,
                "status": "boi_agent_suggestions_unavailable",
                "message": str(exc),
                "model": BOI_AGENT_SUGGESTIONS_MODEL,
                "required": BOI_AGENT_SUGGESTIONS_REQUIRED,
            },
        ) from exc
    return {
        "ok": True,
        "employee_id": employee_id,
        "current_url": req.current_url,
        "page_context": resolved_context,
        "suggestions": suggestions,
        "suggestions_source": source,
    }


