@app.post("/api/agents/boi-wiki/approve")
async def api_boi_agent_approve(req: BoiAgentApprovalRequest, employee_id: str = Depends(current_employee)) -> dict[str, Any]:
    if not req.user_confirmed:
        raise HTTPException(status_code=400, detail="user_confirmed=true is required")
    operation = req.operation.strip()
    payload = req.payload or {}
    supported_operations = {
        "event_publish",
        "publish_event",
        "workflow_start",
        "start_workflow",
        "action_invoke",
        "invoke_action",
        "manual_handoff_complete",
        "manual_complete",
        "event_type_draft",
        "create_event_type_draft",
        "event_type_draft_apply",
        "apply_event_type_draft",
        "promotion_submit",
        "submit_promotion",
        "source_apply",
        "doc_body_apply",
    }
    if operation not in supported_operations:
        raise HTTPException(status_code=400, detail=f"unsupported Agent approval operation: {req.operation}")
    permission = require_agent_operation_permission(employee_id, operation)
    if operation in {"event_publish", "publish_event"}:
        result = await publish_event(EventPublishRequest(**payload), employee_id)
        append_rbac_audit(
            employee_id,
            "agent_event_publish",
            {"operation": operation, "event_type": payload.get("event_type"), "note": req.note, "permission": permission},
        )
        return {"ok": True, "operation": operation, "status": "executed", "result": result}
    if operation in {"workflow_start", "start_workflow"}:
        workflow_key = str(payload.get("workflow_key") or payload.get("key") or "")
        if not workflow_key:
            raise HTTPException(status_code=400, detail="workflow_key is required")
        result = await start_workflow_from_data(workflow_key, payload.get("payload") or payload, employee_id)
        append_rbac_audit(employee_id, "agent_workflow_start", {"workflow_key": workflow_key, "note": req.note, "permission": permission})
        return {"ok": True, "operation": operation, "status": "executed", "result": result}
    if operation in {"action_invoke", "invoke_action"}:
        result = await invoke_action_gateway(ActionInvokeRequest(**payload), employee_id)
        append_rbac_audit(employee_id, "agent_action_invoke", {"action_key": payload.get("action_key"), "note": req.note, "permission": permission})
        return {"ok": True, "operation": operation, "status": "executed", "result": result}
    if operation in {"manual_handoff_complete", "manual_complete"}:
        result = await complete_manual_handoff(ManualHandoffCompleteRequest(**payload), employee_id)
        append_rbac_audit(
            employee_id,
            "agent_manual_handoff_complete",
            {"task_id": payload.get("task_id"), "note": req.note, "permission": permission},
        )
        return {"ok": True, "operation": operation, "status": "executed", "result": result}
    if operation in {"event_type_draft", "create_event_type_draft"}:
        draft_payload = {**payload, "user_confirmed": True}
        draft = create_event_type_draft(EventTypeDraftRequest(**draft_payload), employee_id)
        return {"ok": True, "operation": operation, "status": "draft_created", "draft": draft}
    if operation in {"event_type_draft_apply", "apply_event_type_draft"}:
        draft_id = str(payload.get("draft_id") or "")
        if not draft_id:
            raise HTTPException(status_code=400, detail="draft_id is required")
        apply_req = EventTypeDraftApplyRequest(user_confirmed=True, author=payload.get("author"), note=req.note or str(payload.get("note") or ""))
        result = apply_event_type_draft(draft_id, apply_req, employee_id)
        return {"ok": True, "operation": operation, "status": "applied", "result": result}
    if operation in {"promotion_submit", "submit_promotion"}:
        promotion_payload = {**payload, "user_confirmed": True}
        result = await submit_promotion(PromotionSubmitRequest(**promotion_payload), employee_id)
        append_rbac_audit(
            employee_id,
            "agent_promotion_submit",
            {
                "target_visibility": promotion_payload.get("target_visibility"),
                "team_id": promotion_payload.get("team_id"),
                "title": promotion_payload.get("title"),
                "note": req.note,
                "permission": permission,
            },
        )
        return {"ok": True, "operation": operation, "status": "executed", "result": result}
    if operation == "source_apply":
        result = await apply_source_edit_api(SourceApplyRequest(**payload), employee_id)
        append_rbac_audit(employee_id, "agent_source_apply", {"path": payload.get("path"), "note": req.note, "permission": permission})
        return {"ok": True, "operation": operation, "status": "applied", "result": result}
    if operation == "doc_body_apply":
        boi_id = str(payload.get("boi_id") or "")
        if not boi_id:
            raise HTTPException(status_code=400, detail="boi_id is required")
        body_payload = {key: value for key, value in payload.items() if key != "boi_id"}
        result = await apply_doc_body_edit(boi_id, BodyApplyRequest(**body_payload), employee_id)
        append_rbac_audit(employee_id, "agent_doc_body_apply", {"boi_id": boi_id, "note": req.note, "permission": permission})
        return {"ok": True, "operation": operation, "status": "applied", "result": result}
    raise HTTPException(status_code=400, detail=f"unsupported Agent approval operation: {req.operation}")


def activity_file_for_employee(employee_id: str) -> Path:
    now = datetime.now(KST)
    return ACTIVITY_ROOT / "private" / employee_id / f"activity-{now.strftime('%Y%m')}.jsonl"


def append_activity(employee_id: str, activity: dict[str, Any]) -> dict[str, Any]:
    ensure_dirs()
    path = activity_file_for_employee(employee_id)
    path.parent.mkdir(parents=True, exist_ok=True)
    row = {
        "activity_id": f"activity-{datetime.now(KST).strftime('%Y%m%d%H%M%S')}-{uuid.uuid4().hex[:6]}",
        "employee_id": employee_id,
        "logged_at": now_iso(),
        **activity,
    }
    with path.open("a", encoding="utf-8") as handle:
        handle.write(json.dumps(row, ensure_ascii=False, default=str) + "\n")
    return row


def recent_activity(employee_id: str, limit: int = 50) -> list[dict[str, Any]]:
    root = ACTIVITY_ROOT / "private" / employee_id
    if not root.exists():
        return []
    rows: list[dict[str, Any]] = []
    cutoff = datetime.now(KST) - timedelta(days=30)
    for path in sorted(root.glob("activity-*.jsonl"), reverse=True):
        for line in reversed(path.read_text(encoding="utf-8").splitlines()):
            try:
                row = json.loads(line)
            except Exception:
                continue
            try:
                logged_at = datetime.fromisoformat(str(row.get("logged_at") or ""))
            except Exception:
                logged_at = datetime.now(KST)
            if logged_at < cutoff:
                continue
            rows.append(row)
            if len(rows) >= limit:
                return rows
    return rows


@app.post("/api/agents/boi-wiki/activity")
async def api_agent_activity_write(req: ActivityRequest, employee_id: str = Depends(current_employee)) -> dict[str, Any]:
    return {"ok": True, "item": append_activity(employee_id, req.model_dump())}


@app.get("/api/agents/boi-wiki/activity")
async def api_agent_activity(employee_id: str = Depends(current_employee), limit: int = 50) -> dict[str, Any]:
    items = recent_activity(employee_id, limit=max(1, min(limit, 200)))
    return {"ok": True, "count": len(items), "items": items}


def work_pattern_items(employee_id: str, q: str = "", limit: int = 20, include_archived: bool = False) -> list[dict[str, Any]]:
    docs = [
        doc
        for doc in accessible_docs(employee_id)
        if str((doc.get("metadata") or {}).get("type") or "") == "boi/work-pattern"
        and "/agent-memory/" in str(doc.get("uri") or "")
    ]
    if not include_archived:
        docs = [doc for doc in docs if (doc.get("metadata") or {}).get("archive_status", "active") == "active"]
    if q:
        tokens = search_tokens_for_query(q, employee_id)
        docs = [
            doc
            for doc in docs
            if weighted_text_score(doc_search_blob(doc), tokens, title=str((doc.get("metadata") or {}).get("title") or "")) > 0
        ]
    items: list[dict[str, Any]] = []
    for doc in docs[: max(1, min(limit, 100))]:
        metadata = doc.get("metadata") or {}
        ref = stable_doc_ref(doc)
        items.append(
            {
                "pattern_id": metadata.get("boi_id") or ref,
                "title": metadata.get("title") or ref,
                "pattern_kind": metadata.get("pattern_kind") or "",
                "description": metadata.get("description") or "",
                "usage_count": metadata.get("usage_count", 1),
                "confidence": metadata.get("confidence", "medium"),
                "archive_status": metadata.get("archive_status", "active"),
                "visibility": metadata.get("visibility") or "private",
                "classification": metadata.get("classification") or "internal",
                "url": doc_url_for_ref(ref, employee_id),
            }
        )
    return items


def derive_work_pattern_candidates(employee_id: str, *, limit: int = 8) -> list[dict[str, Any]]:
    activities = recent_activity(employee_id, limit=200)
    counters: dict[tuple[str, str], dict[str, Any]] = {}
    for row in activities:
        metadata = row.get("metadata") if isinstance(row.get("metadata"), dict) else {}
        activity_type = str(row.get("activity_type") or "")
        artifact_type = str(metadata.get("artifact_type") or "")
        title = str(row.get("title") or "")
        target = str(row.get("target") or "")
        if artifact_type == "mermaid" or "Mermaid" in title or "머메이드" in title:
            key = ("answer_preference", "mermaid")
            description = "SOP나 업무 흐름을 Mermaid 다이어그램으로 확인하는 선호가 반복되었습니다."
        elif activity_type in {"followup_click", "suggestion_click"}:
            key = ("workflow_habit", "followup")
            description = "Agent 답변 이후 후속 질문을 이어가며 업무 맥락을 확장하는 패턴이 반복되었습니다."
        elif activity_type in {"inbox_open", "manual_handoff_submit"}:
            key = ("manual_to_ai_candidate", "inbox")
            description = "Inbox 조치 확인과 수동 조치 기록이 반복되어 Skill 또는 Action 후보로 정리할 수 있습니다."
        elif activity_type == "agent_question":
            key = ("recurring_task", normalize_search_token(title or target)[:40])
            description = "유사한 Agent 질문이 반복되어 업무 처리 패턴으로 정리할 수 있습니다."
        else:
            continue
        bucket = counters.setdefault(
            key,
            {
                "pattern_kind": key[0],
                "pattern_key": key[1],
                "title": "",
                "description": description,
                "usage_count": 0,
                "source_activity_refs": [],
                "target": target,
            },
        )
        bucket["usage_count"] += 1
        bucket["source_activity_refs"].append(row.get("activity_id"))
    candidates: list[dict[str, Any]] = []
    for item in counters.values():
        if int(item.get("usage_count") or 0) < 2:
            continue
        pattern_kind = str(item["pattern_kind"])
        if pattern_kind == "answer_preference":
            title = "Mermaid 기반 업무 흐름 확인 선호"
            suggested_skill = "boi-sop-flow-visualizer"
        elif pattern_kind == "manual_to_ai_candidate":
            title = "Inbox 수동 조치 자동화 후보"
            suggested_skill = "boi-event-workflow-planner"
        elif pattern_kind == "workflow_habit":
            title = "후속 질문 기반 업무 맥락 확장 패턴"
            suggested_skill = "boi-context-pack-builder"
        else:
            title = "반복 Agent 질문 패턴"
            suggested_skill = "boi-context-pack-builder"
        candidates.append(
            {
                "pattern_id": f"candidate:{hashlib.sha256(json.dumps(item, ensure_ascii=False, sort_keys=True, default=str).encode('utf-8')).hexdigest()[:12]}",
                "pattern_kind": pattern_kind,
                "title": title,
                "description": item["description"],
                "usage_count": item["usage_count"],
                "confidence": "high" if int(item["usage_count"]) >= 5 else "medium",
                "visibility": "private",
                "classification": "internal",
                "source_activity_refs": item["source_activity_refs"][:12],
                "suggested_skill": suggested_skill,
                "suggested_workflow_definition": "",
                "suggested_action": "",
                "suggested_event_type": "",
                "publish_status": "candidate_only",
            }
        )
    return sorted(candidates, key=lambda item: int(item.get("usage_count") or 0), reverse=True)[: max(1, min(limit, 20))]


