@app.get("/api/dictionary/terms")
async def api_dictionary_terms(
    employee_id: str = Depends(current_employee),
    scope: str = "all",
    q: str = "",
    limit: int = DICTIONARY_TERMS_DEFAULT_LIMIT,
    cursor: str = "0",
    domain: str = "",
    view: str = "compact",
) -> dict[str, Any]:
    items = dictionary_terms_for_employee(employee_id, scope=scope)
    if q:
        q_lower = normalize_search_token(q)
        items = [item for item in items if q_lower in normalize_search_token(json.dumps(item, ensure_ascii=False, default=str))]
    if domain:
        domain_lower = normalize_search_token(domain)
        items = [item for item in items if normalize_search_token(str(item.get("domain") or "")) == domain_lower]
    total = len(items)
    try:
        offset = max(0, int(cursor or 0))
    except (TypeError, ValueError):
        offset = 0
    effective_limit = dictionary_limit(limit, default=DICTIONARY_TERMS_DEFAULT_LIMIT, max_limit=DICTIONARY_TERMS_MAX_LIMIT)
    page = items[offset: offset + effective_limit]
    response_items = [compact_dictionary_term(item, view=view) for item in page]
    next_offset = offset + len(page)
    return {
        "ok": True,
        "count": len(response_items),
        "total": total,
        "cursor": str(offset),
        "next_cursor": str(next_offset) if next_offset < total else "",
        "items": response_items,
        "view": "full" if str(view or "").lower() == "full" else "compact",
    }


@app.post("/api/dictionary/terms")
async def api_dictionary_term_create(req: DictionaryTermRequest, employee_id: str = Depends(current_employee)) -> dict[str, Any]:
    if req.scope in {"team", "public"}:
        require_employee_role(employee_id, "boi.editor")
    employee_teams = teams_for(employee_id)
    visibility = "private" if req.scope == "private" else req.scope
    team_id = req.team_id or (employee_teams[0] if req.scope == "team" and employee_teams else None)
    if req.scope == "team":
        if not team_id:
            raise HTTPException(status_code=400, detail="team_id is required for team dictionary terms")
        if team_id not in employee_teams and "boi.admin" not in roles_for(employee_id):
            raise HTTPException(status_code=403, detail=f"employee is not member of team: {team_id}")
    owner = employee_id if req.scope == "private" else (team_id or "public")
    metadata = make_metadata(
        boi_type="boi/dictionary-term",
        title=req.term,
        description=req.definition,
        owner=owner,
        visibility=visibility,  # type: ignore[arg-type]
        classification="internal",
        team_id=team_id,
        source_refs=[{"type": "dictionary", "ref": "BoI Agent dictionary form"}],
        status="draft" if req.scope == "private" else "reviewed",
        tags=["Dictionary", req.domain] if req.domain else ["Dictionary"],
        reviewer="dictionary-curator" if req.scope != "private" else None,
    )
    metadata.update(
        {
            "term": req.term,
            "definition": req.definition,
            "aliases": req.aliases,
            "term_kind": req.term_kind or "",
            "curation_status": req.curation_status,
            "compound_reason": req.compound_reason,
            "examples": [req.example] if req.example else [],
            "links": req.links,
            "related_terms": req.related_terms,
            "broader": req.broader,
            "narrower": req.narrower,
            "same_as": req.same_as,
            "domain": req.domain,
            "maps_to_event_type": req.maps_to_event_type,
            "maps_to_action_key": req.maps_to_action_key,
            "maps_to_sop": req.maps_to_sop,
        }
    )
    if req.scope == "private":
        doc = write_boi_to_subfolder(metadata, dictionary_body(req), "dictionary")
    else:
        doc = write_boi(metadata, dictionary_body(req))
        append_rbac_audit(
            employee_id,
            "dictionary_term_create",
            {"scope": req.scope, "term": req.term, "team_id": team_id, "boi_id": (doc.get("metadata") or {}).get("boi_id")},
        )
    commit = git_commit_for_path(Path(str(doc["path"])), f"Create BoI dictionary term {(doc.get('metadata') or {}).get('boi_id')}")
    return {"ok": True, "item": doc_result_item(doc, employee_id), "commit": commit}


def dictionary_body(req: DictionaryTermRequest) -> str:
    related_links = req.related_terms or req.same_as or req.broader or req.narrower
    lines = [
        "# Summary",
        "",
        req.definition,
        "",
        "# BoI Usage",
        "",
        f"- Term: {req.term}",
    ]
    if req.aliases:
        lines.append(f"- Aliases: {', '.join(req.aliases)}")
    if req.term_kind:
        lines.append(f"- Term kind: {req.term_kind}")
    if req.example:
        lines.extend(["", "# Agent Notes", "", f"- Example: {req.example}"])
    else:
        lines.extend(["", "# Agent Notes", "", "- Add field usage examples before public/team promotion."])
    lines.extend(["", "# Related Dictionary Terms", ""])
    if related_links:
        lines.extend([f"- {term}" for term in related_links])
    else:
        lines.append("- Related term candidates are not set yet.")
    if req.links:
        lines.extend(["", "# Citations", "", *[f"- {link}" for link in req.links]])
    else:
        lines.extend(["", "# Citations", "", "- BoI Agent dictionary form"])
    return "\n".join(lines).strip() + "\n"


def completion_request_ids(rows: list[dict[str, Any]] | None = None) -> set[str]:
    completed: set[str] = set()
    for row in (rows if rows is not None else cached_action_log_rows()):
        if row.get("completion_for_request_id"):
            completed.add(str(row.get("completion_for_request_id")))
    return completed


