@app.post("/api/simulations/universal-agent", dependencies=[Depends(require_service_token)])
async def api_universal_simulation_agent(req: SimulationAgentRequest) -> dict[str, Any]:
    action = action_catalog_by_key().get(req.action_key)
    if not action:
        raise HTTPException(status_code=404, detail=f"Action not found: {req.action_key}")
    employee_id = req.employee_id or DEMO_EMPLOYEE_ID
    event_type = str(req.event.get("event_type") or "")
    trace_id = str(req.event.get("trace_id") or "")
    docs = simulation_context_docs(
        employee_id,
        action=action,
        event_type=event_type,
        trace_id=trace_id,
        sop_ref=req.sop_ref or "",
    )
    doc_lookup = build_doc_lookup(docs)
    event_def = get_event_type(event_type) or {}
    workflow: dict[str, Any] | None = None
    if req.workflow_key:
        try:
            workflow = workflow_context(req.workflow_key, employee_id, trace_id=str(req.event.get("trace_id") or ""), doc_lookup=doc_lookup)
        except HTTPException:
            workflow = None
    if workflow is None and event_type:
        workflow, stage, event_def = workflow_for_event_type(event_type, employee_id, doc_lookup=doc_lookup)
        if workflow and stage and not req.sop_stage_id:
            event_def = {**event_def, "sop_stage_id": stage.get("sop_stage_id") or stage.get("stage_id") or stage.get("stage")}
    prior_results = merge_prior_results(req.prior_results, trace_prior_action_results(trace_id, employee_id))
    return build_simulation_agent_result(
        action=action,
        event=req.event,
        payload=req.payload or req.event.get("payload") or {},
        prior_results=prior_results,
        employee_id=employee_id,
        docs=docs,
        event_def=event_def,
        workflow=workflow,
        sop_ref=req.sop_ref or "",
        sop_stage_id=req.sop_stage_id or "",
        max_rounds=max(1, min(int(req.max_rounds or 4), 5)),
        simulation_depth=req.simulation_depth or "stage_prerequisites",
    )


@app.get("/actions", response_class=HTMLResponse)
async def actions_page(
    request: Request,
    employee_id: str = Depends(current_employee),
    event_type: str = "",
    action_key: str = "",
    view: str = "",
    q: str = "",
    status: str = "",
    connector_kind: str = "",
    trace_id: str = "",
    request_id: str = "",
    from_time: str = "",
    to_time: str = "",
    time_preset: str = "",
    limit: int = Query(100, ge=1, le=200),
    offset: int = Query(0, ge=0),
) -> HTMLResponse:
    actions = load_action_catalog()
    if event_type:
        actions = [a for a in actions if event_type in (a.get("event_types") or [])]
    if action_key:
        actions = [a for a in actions if a.get("action_key") == action_key]
    doc_lookup = build_doc_lookup(accessible_docs(employee_id))
    action_history = filter_action_logs_payload(
        employee_id=employee_id,
        q=q,
        status=status,
        connector_kind=connector_kind,
        event_type=event_type,
        action_key=action_key,
        trace_id=trace_id,
        request_id=request_id,
        from_time=from_time,
        to_time=to_time,
        time_preset=time_preset,
        limit=limit,
        offset=offset,
    ) if view == "history" else {}
    query_base = {
        "view": "history",
        "q": q,
        "status": action_history.get("filters", {}).get("status") or status,
        "connector_kind": connector_kind,
        "event_type": event_type,
        "action_key": action_key,
        "trace_id": trace_id,
        "request_id": request_id,
        "from_time": from_time,
        "to_time": to_time,
        "time_preset": time_preset,
        "limit": str(limit),
    }
    active_history_filters = [
        {"label": "검색어", "value": q, "param": "q"},
        {"label": "상태", "value": ACTION_STATUS_LABELS.get(action_history.get("filters", {}).get("status") or status, action_history.get("filters", {}).get("status") or status), "param": "status"},
        {"label": "Connector", "value": connector_kind, "param": "connector_kind"},
        {"label": "Event", "value": event_type, "param": "event_type"},
        {"label": "Action", "value": action_key, "param": "action_key"},
        {"label": "Trace", "value": trace_id, "param": "trace_id"},
        {"label": "Request", "value": request_id, "param": "request_id"},
    ] if view == "history" else []
    active_history_filters = [item for item in active_history_filters if item.get("value")]
    return templates.TemplateResponse(
        "actions.html",
        {
            "request": request,
            "employee_id": employee_id,
            "shell": app_shell_context(
                request,
                employee_id,
                active_nav="actions",
                title="Action",
                description="API, MCP, Webhook, Manual Action을 BoI Wiki 업무 흐름에 연결해 재사용합니다.",
                page_actions=[
                    {"label": "Action 추가", "href": app_url("/sops/new", employee_id, focus="action"), "kind": "primary"},
                    {"label": "BoI Wiki", "href": app_url("/", employee_id), "kind": "secondary"},
                ],
            ),
            "event_type": event_type,
            "action_key": action_key,
            "q": q,
            "status": action_history.get("filters", {}).get("status") or status,
            "connector_kind": connector_kind,
            "trace_id": trace_id,
            "request_id": request_id,
            "from_time": from_time,
            "to_time": to_time,
            "time_preset": time_preset,
            "limit": limit,
            "offset": offset,
            "view": view,
            "event_types": load_event_types(),
            "actions": actions_for_template(actions, employee_id, doc_lookup=doc_lookup),
            "action_logs": action_history.get("items", []),
            "action_history": action_history,
            "action_status_options": [
                {"value": "invoked", "label": "실행됨"},
                {"value": "failed", "label": "실패"},
                {"value": "approval_required", "label": "승인 필요"},
                {"value": "manual_required", "label": "수동 조치"},
                {"value": "event_published", "label": "Event 발행"},
                {"value": "materialized", "label": "BoI 생성"},
            ],
            "connector_options": sorted(
                {
                    str(item.get("connector_kind") or "")
                    for item in load_action_catalog()
                    if str(item.get("connector_kind") or "")
                }
                | {
                    str(item.get("connector_kind") or "")
                    for item in action_history.get("items", [])
                    if str(item.get("connector_kind") or "")
                }
            ),
            "active_history_filters": active_history_filters,
            "clear_history_url": app_url("/actions", employee_id, view="history"),
            "next_history_url": app_url("/actions", employee_id, **{**query_base, "offset": str(action_history.get("next_offset") or "")}) if action_history.get("next_offset") is not None else "",
            "action_invoke_url": f"{boi_public_base_url(request)}/api/actions/invoke?employee_id={quote(employee_id)}",
        },
    )


